-- Quiz generado con Claude API

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('79d2b13e-8665-477b-95c0-c3df47cfd6a3', '¿Cuál es la característica principal del nivel de lectura literal?', 'What is the main characteristic of the literal reading level?', '["Evalúa la validez de los argumentos del texto","Extrae información explícita que está escrita directamente","Deduce significados implícitos del contexto","Emite juicios críticos sobre el contenido"]'::jsonb, '["Evaluates the validity of text arguments","Extracts explicit information that is written directly","Deduces implicit meanings from context","Makes critical judgments about content"]'::jsonb, 1, 'El nivel literal se enfoca en extraer la información explícita, es decir, lo que está escrito directamente en el texto como datos, fechas, nombres y hechos.', 'The literal level focuses on extracting explicit information, that is, what is written directly in the text such as data, dates, names and facts.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('79d2b13e-8665-477b-95c0-c3df47cfd6a3', 'Una pregunta como ''¿Por qué el personaje actuó de esa manera?'' corresponde al nivel:', 'A question like ''Why did the character act that way?'' corresponds to the level:', '["Literal","Inferencial","Crítico","Ninguno de los anteriores"]'::jsonb, '["Literal","Inferential","Critical","None of the above"]'::jsonb, 1, 'Esta pregunta requiere deducir motivaciones que no están explícitamente escritas, lo cual es característico del nivel inferencial donde se interpretan intenciones y se hacen deducciones.', 'This question requires deducing motivations that are not explicitly written, which is characteristic of the inferential level where intentions are interpreted and deductions are made.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('79d2b13e-8665-477b-95c0-c3df47cfd6a3', 'En el ejercicio del texto sobre ansiedad en jóvenes, la pregunta ''¿Es justo atribuirlo solo a redes sociales y pandemia?'' corresponde al nivel:', 'In the exercise about anxiety in young people, the question ''Is it fair to attribute it only to social media and pandemic?'' corresponds to the level:', '["Literal, porque busca datos específicos","Inferencial, porque deduce causas implícitas","Crítico, porque evalúa y cuestiona los argumentos","Es una combinación de los tres niveles"]'::jsonb, '["Literal, because it seeks specific data","Inferential, because it deduces implicit causes","Critical, because it evaluates and questions arguments","It''s a combination of all three levels"]'::jsonb, 2, 'Esta pregunta pertenece al nivel crítico porque evalúa la validez de los argumentos presentados y cuestiona si la explicación dada es completa o si faltan otros factores.', 'This question belongs to the critical level because it evaluates the validity of the arguments presented and questions whether the given explanation is complete or if other factors are missing.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('8abefc27-cec7-4781-bbe4-529ae88d7866', '¿Cuál es la principal diferencia entre RAM y disco duro?', 'What is the main difference between RAM and hard drive?', '["RAM es más barata que el disco duro","RAM guarda información temporalmente, el disco duro permanentemente","RAM es más lenta que el disco duro","RAM y disco duro son lo mismo"]'::jsonb, '["RAM is cheaper than hard drive","RAM stores information temporarily, hard drive permanently","RAM is slower than hard drive","RAM and hard drive are the same"]'::jsonb, 1, 'La RAM es memoria temporal donde se guarda lo que está usando en ese momento, mientras que el disco duro guarda archivos permanentemente.', 'RAM is temporary memory where what is currently being used is stored, while the hard drive stores files permanently.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('8abefc27-cec7-4781-bbe4-529ae88d7866', '¿Cuál de estos es un dispositivo de entrada?', 'Which of these is an input device?', '["Monitor","Bocinas","Micrófono","Impresora"]'::jsonb, '["Monitor","Speakers","Microphone","Printer"]'::jsonb, 2, 'El micrófono es un dispositivo de entrada porque permite introducir información (sonido) a la computadora.', 'The microphone is an input device because it allows information (sound) to be entered into the computer.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('8abefc27-cec7-4781-bbe4-529ae88d7866', '¿Qué sistema operativo es gratuito y de código abierto?', 'Which operating system is free and open source?', '["Windows 11","macOS","Linux","iOS"]'::jsonb, '["Windows 11","macOS","Linux","iOS"]'::jsonb, 2, 'Linux es el sistema operativo gratuito y de código abierto, muy usado por programadores.', 'Linux is the free and open source operating system, widely used by programmers.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fbf6dcaa-8fbe-46b3-a804-fcc5dc9eb901', '¿Cuál es el resultado de (x + 5)²?', 'What is the result of (x + 5)²?', '["x² + 10x + 25","x² + 5x + 25","x² + 25","x² + 10x + 5"]'::jsonb, '["x² + 10x + 25","x² + 5x + 25","x² + 25","x² + 10x + 5"]'::jsonb, 0, 'Usando la fórmula (a + b)² = a² + 2ab + b², donde a = x y b = 5: x² + 2(x)(5) + 5² = x² + 10x + 25', 'Using the formula (a + b)² = a² + 2ab + b², where a = x and b = 5: x² + 2(x)(5) + 5² = x² + 10x + 25', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fbf6dcaa-8fbe-46b3-a804-fcc5dc9eb901', '¿Cuál es el resultado de (2x + 3)(2x - 3)?', 'What is the result of (2x + 3)(2x - 3)?', '["4x² - 9","4x² + 9","2x² - 9","4x² - 6x - 9"]'::jsonb, '["4x² - 9","4x² + 9","2x² - 9","4x² - 6x - 9"]'::jsonb, 0, 'Este es un producto de binomios conjugados. Usando la fórmula (a + b)(a - b) = a² - b², donde a = 2x y b = 3: (2x)² - 3² = 4x² - 9', 'This is a product of conjugate binomials. Using the formula (a + b)(a - b) = a² - b², where a = 2x and b = 3: (2x)² - 3² = 4x² - 9', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fbf6dcaa-8fbe-46b3-a804-fcc5dc9eb901', 'Aplicando las leyes de los exponentes, ¿cuál es el resultado de x³ × x⁴ ÷ x²?', 'Applying the laws of exponents, what is the result of x³ × x⁴ ÷ x²?', '["x⁵","x⁹","x²⁴","x"]'::jsonb, '["x⁵","x⁹","x²⁴","x"]'::jsonb, 0, 'Primero multiplicamos: x³ × x⁴ = x⁷ (sumamos exponentes). Luego dividimos: x⁷ ÷ x² = x⁵ (restamos exponentes: 7 - 2 = 5)', 'First we multiply: x³ × x⁴ = x⁷ (add exponents). Then we divide: x⁷ ÷ x² = x⁵ (subtract exponents: 7 - 2 = 5)', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bc691cdb-e9b9-4add-9a25-aa96487d6399', 'Según la Organización Mundial de la Salud (OMS), ¿cómo se define la salud?', 'According to the World Health Organization (WHO), how is health defined?', '["Solo como la ausencia de enfermedades","Un estado de completo bienestar físico, mental y social","Únicamente el buen funcionamiento del cuerpo","La capacidad de hacer ejercicio regularmente"]'::jsonb, '["Only as the absence of diseases","A state of complete physical, mental and social well-being","Only the proper functioning of the body","The ability to exercise regularly"]'::jsonb, 1, 'La OMS define la salud como un estado de completo bienestar físico, mental y social, no solo como la ausencia de enfermedades.', 'WHO defines health as a state of complete physical, mental and social well-being, not just as the absence of diseases.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bc691cdb-e9b9-4add-9a25-aa96487d6399', '¿Qué porcentaje de tu salud depende de las decisiones de estilo de vida que tomas diariamente?', 'What percentage of your health depends on the lifestyle decisions you make daily?', '["10-15%","20%","50-55%","75%"]'::jsonb, '["10-15%","20%","50-55%","75%"]'::jsonb, 2, 'El estilo de vida representa el 50-55% de los factores que afectan tu salud, lo que significa que más de la mitad de tu bienestar depende de tus decisiones diarias.', 'Lifestyle represents 50-55% of the factors that affect your health, meaning more than half of your well-being depends on your daily decisions.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bc691cdb-e9b9-4add-9a25-aa96487d6399', '¿Cuál de las siguientes dimensiones de la salud se refiere a tener propósito, valores y sentido de vida?', 'Which of the following health dimensions refers to having purpose, values and meaning in life?', '["Dimensión física","Dimensión mental/emocional","Dimensión social","Dimensión espiritual"]'::jsonb, '["Physical dimension","Mental/emotional dimension","Social dimension","Spiritual dimension"]'::jsonb, 3, 'La dimensión espiritual se refiere a tener propósito, valores y sentido de vida, y no necesariamente está relacionada con la religión.', 'The spiritual dimension refers to having purpose, values and meaning in life, and is not necessarily related to religion.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('71c3e3c7-67ca-4b79-8c3c-b8bb83a7b06d', '¿Cuál civilización es considerada la ''cultura madre'' de Mesoamérica?', 'Which civilization is considered the ''mother culture'' of Mesoamerica?', '["Los Mayas","Los Olmecas","Los Teotihuacanos","Los Mexicas"]'::jsonb, '["The Mayans","The Olmecs","The Teotihuacans","The Mexicas"]'::jsonb, 1, 'Los Olmecas son considerados la ''cultura madre'' porque desarrollaron el primer sistema de escritura, el calendario y el juego de pelota, influyendo en las civilizaciones posteriores.', 'The Olmecs are considered the ''mother culture'' because they developed the first writing system, calendar, and ball game, influencing later civilizations.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('71c3e3c7-67ca-4b79-8c3c-b8bb83a7b06d', '¿Cómo se llamaba la escuela mexica destinada a los nobles y sacerdotes?', 'What was the name of the Mexica school for nobles and priests?', '["Telpochcalli","Calmécac","Cuicacalli","Tenochtitlán"]'::jsonb, '["Telpochcalli","Calmécac","Cuicacalli","Tenochtitlán"]'::jsonb, 1, 'El Calmécac era la escuela para nobles y sacerdotes donde se enseñaba religión, astronomía, escritura, historia y leyes.', 'The Calmécac was the school for nobles and priests where religion, astronomy, writing, history, and laws were taught.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('71c3e3c7-67ca-4b79-8c3c-b8bb83a7b06d', '¿Qué característica única tenía el sistema educativo mexica comparado con Europa de esa época?', 'What unique characteristic did the Mexica educational system have compared to Europe of that time?', '["Solo educaba a los nobles","Era exclusivo para sacerdotes","Era obligatorio y universal","Solo enseñaba oficios"]'::jsonb, '["It only educated nobles","It was exclusive to priests","It was mandatory and universal","It only taught trades"]'::jsonb, 2, 'El sistema educativo mexica era obligatorio y universal, todos los jóvenes asistían a alguna escuela, algo que Europa no logró sino hasta siglos después.', 'The Mexica educational system was mandatory and universal, all young people attended some school, something Europe didn''t achieve until centuries later.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4d69b117-365d-4985-8378-8da9c3c0d17a', '¿Cuál es la principal diferencia entre el bachillerato virtual y el presencial según el contenido?', 'What is the main difference between virtual and in-person high school according to the content?', '["El virtual tiene menos validez oficial","El virtual es más fácil de aprobar","El virtual es 100% en línea con flexibilidad de horarios","El virtual requiere menos disciplina"]'::jsonb, '["Virtual has less official validity","Virtual is easier to pass","Virtual is 100% online with flexible schedules","Virtual requires less discipline"]'::jsonb, 2, 'El bachillerato virtual tiene la misma validez oficial que el presencial, pero se cursa 100% en línea con flexibilidad de horarios las 24 horas del día, los 7 días de la semana.', 'Virtual high school has the same official validity as in-person, but is taken 100% online with flexible schedules 24 hours a day, 7 days a week.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4d69b117-365d-4985-8378-8da9c3c0d17a', 'Según el contenido, ¿cuántas horas diarias se recomiendan dedicar al estudio?', 'According to the content, how many daily hours are recommended for studying?', '["30 minutos a 1 hora","1 a 2 horas","3 a 4 horas","5 a 6 horas"]'::jsonb, '["30 minutes to 1 hour","1 to 2 hours","3 to 4 hours","5 to 6 hours"]'::jsonb, 1, 'El contenido establece claramente que se necesitan 1-2 horas diarias dedicadas al estudio para tener éxito en el bachillerato virtual.', 'The content clearly states that 1-2 hours daily dedicated to studying are needed to succeed in virtual high school.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4d69b117-365d-4985-8378-8da9c3c0d17a', '¿Cuál es el factor más importante para el éxito en el bachillerato virtual según el material?', 'What is the most important factor for success in virtual high school according to the material?', '["Tener una computadora de última generación","La inteligencia natural del estudiante","Disciplina y constancia","Vivir cerca de la escuela"]'::jsonb, '["Having a latest generation computer","The student''s natural intelligence","Discipline and consistency","Living close to school"]'::jsonb, 2, 'El contenido específicamente menciona que la disciplina y constancia son más importantes que la inteligencia, y enfatiza que la responsabilidad es 100% del estudiante.', 'The content specifically mentions that discipline and consistency are more important than intelligence, and emphasizes that responsibility is 100% the student''s.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('acc99942-8299-42ba-8ee8-ef1d0173d1fa', '¿Cuál es la forma correcta del presente continuo para ''She / watch TV''?', 'What is the correct present continuous form for ''She / watch TV''?', '["She watch TV","She is watching TV","She watches TV","She are watching TV"]'::jsonb, '["She watch TV","She is watching TV","She watches TV","She are watching TV"]'::jsonb, 1, 'El presente continuo usa la estructura: sujeto + am/is/are + verbo-ING. Para ''she'' usamos ''is'' + ''watching''.', 'Present continuous uses the structure: subject + am/is/are + verb-ING. For ''she'' we use ''is'' + ''watching''.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('acc99942-8299-42ba-8ee8-ef1d0173d1fa', '¿Cuál es la forma correcta de agregar -ING al verbo ''run''?', 'What is the correct way to add -ING to the verb ''run''?', '["runing","running","runeing","runn"]'::jsonb, '["runing","running","runeing","runn"]'::jsonb, 1, 'Para verbos que terminan en consonante-vocal-consonante corta, se dobla la última consonante: run → running.', 'For verbs ending in consonant-vowel-consonant (short), we double the last consonant: run → running.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('acc99942-8299-42ba-8ee8-ef1d0173d1fa', '¿Cuál oración describe una acción que está pasando AHORA MISMO?', 'Which sentence describes an action happening RIGHT NOW?', '["I drink coffee every morning","I am drinking coffee right now","I usually drink coffee","I always drink coffee at work"]'::jsonb, '["I drink coffee every morning","I am drinking coffee right now","I usually drink coffee","I always drink coffee at work"]'::jsonb, 1, 'El presente continuo ''I am drinking coffee right now'' indica una acción en progreso en este momento. Las otras opciones son hábitos (presente simple).', 'Present continuous ''I am drinking coffee right now'' indicates an action in progress at this moment. The other options are habits (simple present).', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('dc5f3cb2-c6cb-489f-92d6-7644cdbe4276', '¿Cuál de los siguientes números NO pertenece al conjunto de números naturales (ℕ)?', 'Which of the following numbers does NOT belong to the set of natural numbers (ℕ)?', '["5","0","12","1"]'::jsonb, '["5","0","12","1"]'::jsonb, 1, 'Los números naturales son los que usamos para contar (1, 2, 3, 4, 5...) y NO incluyen el cero ni los números negativos.', 'Natural numbers are those we use for counting (1, 2, 3, 4, 5...) and do NOT include zero or negative numbers.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('dc5f3cb2-c6cb-489f-92d6-7644cdbe4276', '¿Cuál de estos números es irracional?', 'Which of these numbers is irrational?', '["0.5","3/4","√2","0.333..."]'::jsonb, '["0.5","3/4","√2","0.333..."]'::jsonb, 2, '√2 es un número irracional porque no se puede escribir como fracción y su expansión decimal es infinita y no se repite.', '√2 is an irrational number because it cannot be written as a fraction and its decimal expansion is infinite and non-repeating.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('dc5f3cb2-c6cb-489f-92d6-7644cdbe4276', 'Según la organización de los conjuntos numéricos, ¿cuál afirmación es correcta?', 'According to the organization of numerical sets, which statement is correct?', '["Los números racionales están dentro de los naturales","Los números naturales están dentro de los enteros","Los números irracionales están dentro de los racionales","Los números reales están dentro de los enteros"]'::jsonb, '["Rational numbers are within natural numbers","Natural numbers are within integers","Irrational numbers are within rational numbers","Real numbers are within integers"]'::jsonb, 1, 'Los conjuntos están organizados como cajas dentro de cajas: los naturales están dentro de los enteros, los enteros dentro de los racionales, y todos forman los reales.', 'The sets are organized like boxes within boxes: naturals are within integers, integers are within rationals, and all form the reals.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('6d973d65-35a8-4039-821d-8a641e347452', '¿Cuál es la pronunciación correcta de la letra ''Y'' en inglés?', 'What is the correct pronunciation of the letter ''Y'' in English?', '["yi","uái","ái","i"]'::jsonb, '["yi","uái","ái","i"]'::jsonb, 1, 'La letra ''Y'' en inglés se pronuncia ''uái'', no como en español donde se pronuncia ''ye''.', 'The letter ''Y'' in English is pronounced ''uái'', not like in Spanish where it''s pronounced ''ye''.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('6d973d65-35a8-4039-821d-8a641e347452', '¿Cómo se escribe el número 15 en inglés?', 'How do you write the number 15 in English?', '["fiveteen","fifteen","fiften","fifty"]'::jsonb, '["fiveteen","fifteen","fiften","fifty"]'::jsonb, 1, 'El número 15 se escribe ''fifteen'' en inglés. Es importante recordar que cambia de ''five'' a ''fif''.', 'The number 15 is written ''fifteen'' in English. It''s important to remember that it changes from ''five'' to ''fif''.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('6d973d65-35a8-4039-821d-8a641e347452', '¿Cuál es la diferencia entre ''Good evening'' y ''Good night''?', 'What is the difference between ''Good evening'' and ''Good night''?', '["No hay diferencia","Good evening es para saludar al llegar, Good night para despedirse","Good night es para saludar al llegar, Good evening para despedirse","Ambos solo se usan para despedirse"]'::jsonb, '["There is no difference","Good evening is for greeting when arriving, Good night for saying goodbye","Good night is for greeting when arriving, Good evening for saying goodbye","Both are only used for saying goodbye"]'::jsonb, 1, '''Good evening'' se usa para saludar cuando llegas en la noche, mientras que ''Good night'' se usa para despedirse antes de dormir.', '''Good evening'' is used to greet when you arrive in the evening, while ''Good night'' is used to say goodbye before going to sleep.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d6979814-1791-4931-913b-9d9084c7af61', '¿Cuál es la principal diferencia entre sexo biológico y género?', 'What is the main difference between biological sex and gender?', '["El sexo es biológico y el género es una construcción social","Son exactamente lo mismo","El género es biológico y el sexo es social","Solo se diferencian en la orientación sexual"]'::jsonb, '["Sex is biological and gender is a social construction","They are exactly the same","Gender is biological and sex is social","They only differ in sexual orientation"]'::jsonb, 0, 'El sexo biológico se refiere a características físicas como cromosomas y órganos reproductores, mientras que el género es una construcción social que incluye roles y expectativas que varían entre culturas.', 'Biological sex refers to physical characteristics like chromosomes and reproductive organs, while gender is a social construction that includes roles and expectations that vary between cultures.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d6979814-1791-4931-913b-9d9084c7af61', '¿Qué porcentaje aproximado de la población nace con características intersexuales?', 'What approximate percentage of the population is born with intersex characteristics?', '["0.1%","1.7%","5%","10%"]'::jsonb, '["0.1%","1.7%","5%","10%"]'::jsonb, 1, 'Según el contenido, aproximadamente 1.7% de la población nace con variaciones naturales en las características sexuales, conocido como intersexualidad.', 'According to the content, approximately 1.7% of the population is born with natural variations in sexual characteristics, known as intersexuality.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d6979814-1791-4931-913b-9d9084c7af61', '¿Cuál de las siguientes afirmaciones sobre orientación sexual es correcta?', 'Which of the following statements about sexual orientation is correct?', '["Es una elección personal que se puede cambiar","No es una elección y nadie debería ser discriminado por ella","Solo existe la orientación heterosexual","Depende únicamente de la expresión de género"]'::jsonb, '["It''s a personal choice that can be changed","It''s not a choice and no one should be discriminated against for it","Only heterosexual orientation exists","It depends solely on gender expression"]'::jsonb, 1, 'El contenido establece claramente que la orientación sexual no es una elección y que nadie debería ser discriminado por su orientación, siendo esto un principio de derechos humanos protegido por la Constitución Mexicana.', 'The content clearly states that sexual orientation is not a choice and that no one should be discriminated against for their orientation, this being a human rights principle protected by the Mexican Constitution.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('1e09048e-517d-4192-91f5-a39911b5567b', '¿Cuál de los siguientes elementos del proceso de comunicación se refiere al medio por donde viaja el mensaje?', 'Which of the following elements of the communication process refers to the medium through which the message travels?', '["Código","Canal","Contexto","Retroalimentación"]'::jsonb, '["Code","Channel","Context","Feedback"]'::jsonb, 1, 'El canal es el medio físico por donde viaja el mensaje, como el aire para la voz, el papel para la escritura o internet para mensajes digitales.', 'The channel is the physical medium through which the message travels, such as air for voice, paper for writing, or internet for digital messages.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('1e09048e-517d-4192-91f5-a39911b5567b', 'Cuando alguien dice ''¡Compra ahora!'' está utilizando principalmente la función del lenguaje:', 'When someone says ''Buy now!'' they are mainly using the language function:', '["Referencial","Emotiva","Apelativa","Fática"]'::jsonb, '["Referential","Emotive","Appellative","Phatic"]'::jsonb, 2, 'La función apelativa busca provocar una reacción o respuesta específica en el receptor, como en este caso incitar a comprar.', 'The appellative function seeks to provoke a specific reaction or response from the receiver, such as in this case inciting to buy.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('1e09048e-517d-4192-91f5-a39911b5567b', 'Los gestos, expresiones faciales y postura corporal corresponden al lenguaje no verbal de tipo:', 'Gestures, facial expressions, and body posture correspond to non-verbal language of type:', '["Proxémico","Paralingüístico","Kinésico","Metalingüístico"]'::jsonb, '["Proxemic","Paralinguistic","Kinesic","Metalinguistic"]'::jsonb, 2, 'El lenguaje kinésico se refiere a la comunicación a través de movimientos corporales, gestos, expresiones faciales y posturas.', 'Kinesic language refers to communication through body movements, gestures, facial expressions, and postures.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d224dabc-391a-49d2-bf7f-6ce909344976', '¿Cuál de los siguientes es un ejemplo correcto de descomposición en pensamiento computacional?', 'Which of the following is a correct example of decomposition in computational thinking?', '["Ignorar los detalles menos importantes de un problema","Dividir ''estudiar para un examen'' en: revisar apuntes, hacer resúmenes, resolver ejercicios, repasar","Encontrar que siempre llueve los martes por la tarde","Crear pasos ordenados para resolver un problema"]'::jsonb, '["Ignoring the less important details of a problem","Dividing ''studying for an exam'' into: reviewing notes, making summaries, solving exercises, reviewing","Finding that it always rains on Tuesday afternoons","Creating ordered steps to solve a problem"]'::jsonb, 1, 'La descomposición consiste en dividir un problema grande en partes más pequeñas y manejables, como dividir ''estudiar para un examen'' en tareas específicas.', 'Decomposition consists of dividing a large problem into smaller, manageable parts, like dividing ''studying for an exam'' into specific tasks.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d224dabc-391a-49d2-bf7f-6ce909344976', 'En el ejemplo del problema ''No me alcanza el dinero a fin de mes'', ¿qué pilar del pensamiento computacional se aplica al ''enfocarse en los 3-4 gastos más grandes, ignorar los centavos''?', 'In the example of the problem ''I don''t have enough money at the end of the month'', which pillar of computational thinking applies to ''focusing on the 3-4 largest expenses, ignoring the cents''?', '["Descomposición","Reconocimiento de patrones","Abstracción","Diseño de algoritmos"]'::jsonb, '["Decomposition","Pattern recognition","Abstraction","Algorithm design"]'::jsonb, 2, 'La abstracción consiste en enfocarse en lo importante e ignorar los detalles irrelevantes, como centrarse en los gastos grandes e ignorar los centavos.', 'Abstraction consists of focusing on what''s important and ignoring irrelevant details, like focusing on large expenses and ignoring cents.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d224dabc-391a-49d2-bf7f-6ce909344976', '¿Cuál de las siguientes afirmaciones sobre el pensamiento computacional es FALSA?', 'Which of the following statements about computational thinking is FALSE?', '["Es solo útil para programadores y desarrolladores","Puede aplicarse para resolver problemas en cualquier área de la vida","Incluye cuatro pilares principales: descomposición, patrones, abstracción y algoritmos","Mejora la capacidad de pensar de forma lógica y organizada"]'::jsonb, '["It''s only useful for programmers and developers","It can be applied to solve problems in any area of life","It includes four main pillars: decomposition, patterns, abstraction and algorithms","It improves the ability to think logically and organized"]'::jsonb, 0, 'Es falso que el pensamiento computacional sea solo para programadores. El contenido claramente establece que ''no es solo para programadores'' y que ''puedes aplicar en cualquier área de tu vida''.', 'It''s false that computational thinking is only for programmers. The content clearly states that ''it''s not just for programmers'' and that ''you can apply it in any area of your life''.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('42188cf0-df4c-4dee-a39f-d570324abeda', '¿Cuál de las siguientes características NO es propia de un buen algoritmo?', 'Which of the following characteristics is NOT typical of a good algorithm?', '["Preciso","Infinito","Definido","Ordenado"]'::jsonb, '["Precise","Infinite","Defined","Ordered"]'::jsonb, 1, 'Un buen algoritmo debe ser finito, es decir, tener un inicio y un fin. No puede ser infinito.', 'A good algorithm must be finite, meaning it has a beginning and an end. It cannot be infinite.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('42188cf0-df4c-4dee-a39f-d570324abeda', 'En un diagrama de flujo, ¿qué símbolo se utiliza para representar una decisión?', 'In a flowchart, which symbol is used to represent a decision?', '["Óvalo","Rectángulo","Rombo","Paralelogramo"]'::jsonb, '["Oval","Rectangle","Diamond","Parallelogram"]'::jsonb, 2, 'El rombo se utiliza para representar decisiones (sí/no) en los diagramas de flujo.', 'The diamond is used to represent decisions (yes/no) in flowcharts.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('42188cf0-df4c-4dee-a39f-d570324abeda', '¿Cuál es la principal característica del pseudocódigo?', 'What is the main characteristic of pseudocode?', '["Es completamente en español","Es un lenguaje de programación real","Mezcla lenguaje humano y lenguaje de programación","Solo usa símbolos gráficos"]'::jsonb, '["It''s completely in Spanish","It''s a real programming language","It mixes human language and programming language","It only uses graphic symbols"]'::jsonb, 2, 'El pseudocódigo es una mezcla entre lenguaje humano y lenguaje de programación, lo que lo hace fácil de entender pero con estructura lógica.', 'Pseudocode is a mix between human language and programming language, making it easy to understand but with logical structure.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('169c2b59-5dbb-47a8-877b-6063e07dbb48', '¿En qué fase del ciclo menstrual ocurre la ovulación y cuál es el periodo de mayor fertilidad?', 'In which phase of the menstrual cycle does ovulation occur and what is the period of highest fertility?', '["Fase menstrual (días 1-5)","Ovulación (día 14 aprox) - periodo de mayor fertilidad","Fase lútea (días 15-28)","Fase folicular (días 1-13)"]'::jsonb, '["Menstrual phase (days 1-5)","Ovulation (day 14 approx) - period of highest fertility","Luteal phase (days 15-28)","Follicular phase (days 1-13)"]'::jsonb, 1, 'La ovulación ocurre aproximadamente el día 14 del ciclo menstrual, cuando el óvulo se libera del ovario, y este es el periodo de mayor fertilidad para la mujer.', 'Ovulation occurs approximately on day 14 of the menstrual cycle, when the egg is released from the ovary, and this is the period of highest fertility for women.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('169c2b59-5dbb-47a8-877b-6063e07dbb48', '¿Dónde ocurre la fecundación en el aparato reproductor femenino?', 'Where does fertilization occur in the female reproductive system?', '["En los ovarios","En las trompas de Falopio","En el útero","En la vagina"]'::jsonb, '["In the ovaries","In the fallopian tubes","In the uterus","In the vagina"]'::jsonb, 1, 'La fecundación ocurre cuando un espermatozoide se une con un óvulo en las trompas de Falopio, que conectan los ovarios con el útero.', 'Fertilization occurs when a sperm unites with an egg in the fallopian tubes, which connect the ovaries to the uterus.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('169c2b59-5dbb-47a8-877b-6063e07dbb48', '¿Cuál de las siguientes estructuras del aparato reproductor masculino es responsable de producir el líquido seminal?', 'Which of the following structures of the male reproductive system is responsible for producing seminal fluid?', '["Testículos y epidídimo","Vesículas seminales y próstata","Conductos deferentes y uretra","Pene y escroto"]'::jsonb, '["Testicles and epididymis","Seminal vesicles and prostate","Vas deferens and urethra","Penis and scrotum"]'::jsonb, 1, 'Las vesículas seminales y la próstata son las glándulas encargadas de producir el líquido seminal que nutre y transporta a los espermatozoides.', 'The seminal vesicles and prostate are the glands responsible for producing the seminal fluid that nourishes and transports sperm.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0847342e-925d-4dcf-a2f1-43e55e78d66c', '¿Cuál es la principal intención comunicativa de un texto expositivo?', 'What is the main communicative intention of an expository text?', '["Contar una historia","Convencer al lector","Informar objetivamente","Describir detalladamente"]'::jsonb, '["Tell a story","Convince the reader","Inform objectively","Describe in detail"]'::jsonb, 2, 'Los textos expositivos tienen como fin informar sobre un tema de forma objetiva, sin dar opiniones personales.', 'Expository texts aim to inform about a topic objectively, without giving personal opinions.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0847342e-925d-4dcf-a2f1-43e55e78d66c', 'Si un texto usa palabras como ''en mi opinión'', ''por lo tanto'' y ''sin embargo'', ¿qué tipo de texto es probablemente?', 'If a text uses words like ''in my opinion'', ''therefore'' and ''however'', what type of text is it probably?', '["Narrativo","Descriptivo","Expositivo","Argumentativo"]'::jsonb, '["Narrative","Descriptive","Expository","Argumentative"]'::jsonb, 3, 'Estas palabras clave son características de textos argumentativos, que buscan defender una postura y convencer al lector.', 'These key words are characteristic of argumentative texts, which seek to defend a position and convince the reader.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0847342e-925d-4dcf-a2f1-43e55e78d66c', '¿Cuál de estos ejemplos corresponde a un texto narrativo?', 'Which of these examples corresponds to a narrative text?', '["Un manual de instrucciones","Una biografía","Un artículo de opinión","Una ficha técnica"]'::jsonb, '["An instruction manual","A biography","An opinion article","A technical sheet"]'::jsonb, 1, 'Una biografía es un texto narrativo porque cuenta la historia de la vida de una persona, con secuencia de hechos y trama.', 'A biography is a narrative text because it tells the story of a person''s life, with a sequence of events and plot.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4e0bdc06-b10f-49f5-a0f6-7089076e9f2b', '¿Cuál es la forma correcta del verbo TO BE para ''She''?', 'What is the correct form of the verb TO BE for ''She''?', '["She am","She is","She are","She be"]'::jsonb, '["She am","She is","She are","She be"]'::jsonb, 1, 'Con el pronombre ''She'' (ella) siempre se usa ''is''. Por ejemplo: She is tall.', 'With the pronoun ''She'' we always use ''is''. For example: She is tall.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4e0bdc06-b10f-49f5-a0f6-7089076e9f2b', '¿Cómo se forma la pregunta con ''You are a teacher''?', 'How do you form a question with ''You are a teacher''?', '["You are a teacher?","Are you a teacher?","Are a teacher you?","You a teacher are?"]'::jsonb, '["You are a teacher?","Are you a teacher?","Are a teacher you?","You a teacher are?"]'::jsonb, 1, 'Para formar preguntas con TO BE, se invierte el orden: el verbo va primero. ''You are'' se convierte en ''Are you''.', 'To form questions with TO BE, we invert the order: the verb goes first. ''You are'' becomes ''Are you''.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4e0bdc06-b10f-49f5-a0f6-7089076e9f2b', '¿Cuál es la forma negativa correcta de ''We are students''?', 'What is the correct negative form of ''We are students''?', '["We not are students","We are not students","We don''t are students","We no are students"]'::jsonb, '["We not are students","We are not students","We don''t are students","We no are students"]'::jsonb, 1, 'Para formar el negativo con TO BE, se agrega ''not'' después del verbo: ''We are not students'' o ''We aren''t students''.', 'To form the negative with TO BE, we add ''not'' after the verb: ''We are not students'' or ''We aren''t students''.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('58159d95-28fc-4752-af37-d9e03a1c42a5', '¿Cuál fue el objetivo principal de la educación durante la época colonial en la Nueva España?', 'What was the main objective of education during the colonial period in New Spain?', '["Formar administradores para el gobierno","La evangelización de los indígenas","Enseñar oficios y comercio","Preservar las culturas prehispánicas"]'::jsonb, '["Train administrators for government","The evangelization of indigenous people","Teach trades and commerce","Preserve pre-Hispanic cultures"]'::jsonb, 1, 'El objetivo principal de la educación colonial era la evangelización, es decir, convertir a los indígenas al cristianismo. Los frailes franciscanos, dominicos y agustinos fueron los primeros educadores con este propósito.', 'The main objective of colonial education was evangelization, that is, converting indigenous people to Christianity. Franciscan, Dominican, and Augustinian friars were the first educators with this purpose.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('58159d95-28fc-4752-af37-d9e03a1c42a5', '¿Qué factores fueron decisivos para que Hernán Cortés lograra conquistar el imperio mexica?', 'What factors were decisive for Hernán Cortés to successfully conquer the Mexica empire?', '["Solo la superioridad numérica de los españoles","Las alianzas con tlaxcaltecas, enfermedades europeas, la interpretación de Malintzin y superioridad tecnológica","Únicamente las armas de fuego y los caballos","El apoyo directo del rey de España"]'::jsonb, '["Only the numerical superiority of the Spanish","Alliances with Tlaxcaltecas, European diseases, Malintzin''s interpretation and technological superiority","Only firearms and horses","Direct support from the King of Spain"]'::jsonb, 1, 'La conquista fue posible por una combinación de factores: las alianzas con pueblos enemigos de los mexicas como los tlaxcaltecas, las enfermedades europeas como la viruela, la interpretación de Malintzin y la superioridad tecnológica española.', 'The conquest was made possible by a combination of factors: alliances with peoples who were enemies of the Mexicas like the Tlaxcaltecas, European diseases like smallpox, Malintzin''s interpretation, and Spanish technological superiority.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('58159d95-28fc-4752-af37-d9e03a1c42a5', '¿Cómo afectaba el sistema de castas al acceso a la educación en la Nueva España?', 'How did the caste system affect access to education in New Spain?', '["Todos tenían igual acceso a la educación","El acceso a la educación dependía de la posición social en el sistema de castas","Solo los indígenas podían estudiar","La educación era exclusiva para mujeres"]'::jsonb, '["Everyone had equal access to education","Access to education depended on social position in the caste system","Only indigenous people could study","Education was exclusive for women"]'::jsonb, 1, 'El sistema de castas establecía una jerarquía social donde el acceso a la educación dependía de la posición social. Los peninsulares tenían mayor acceso, seguidos por criollos, mestizos, indígenas y afrodescendientes. Esta desigualdad contribuyó al descontento independentista.', 'The caste system established a social hierarchy where access to education depended on social position. Peninsulars had greater access, followed by criollos, mestizos, indigenous people, and Afro-descendants. This inequality contributed to independentist discontent.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('075a4ebf-4563-41ee-aa80-4b5d1f63b140', '¿Qué porcentaje de tu alimentación diaria deben representar los carbohidratos?', 'What percentage of your daily diet should carbohydrates represent?', '["20-35%","45-65%","10-35%","5-15%"]'::jsonb, '["20-35%","45-65%","10-35%","5-15%"]'::jsonb, 1, 'Los carbohidratos son tu principal fuente de energía y deben constituir entre 45-65% de tu alimentación diaria según el contenido.', 'Carbohydrates are your main source of energy and should constitute 45-65% of your daily diet according to the content.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('075a4ebf-4563-41ee-aa80-4b5d1f63b140', 'Según el Plato del Bien Comer, ¿cuál grupo de alimentos debe ocupar la mayor parte de tu plato?', 'According to the Mexican Food Plate, which food group should occupy the largest part of your plate?', '["Cereales y tubérculos (amarillo)","Frutas y verduras (verde)","Leguminosas y alimentos de origen animal (rojo)","Todos en partes iguales"]'::jsonb, '["Cereals and tubers (yellow)","Fruits and vegetables (green)","Legumes and animal products (red)","All in equal parts"]'::jsonb, 1, 'El grupo verde (frutas y verduras) debe ser abundante y ocupar la mayor parte del plato según la guía mexicana del Plato del Bien Comer.', 'The green group (fruits and vegetables) should be abundant and occupy the largest part of the plate according to the Mexican Food Plate guide.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('075a4ebf-4563-41ee-aa80-4b5d1f63b140', '¿Cuántos vasos de agua se recomienda beber diariamente?', 'How many glasses of water are recommended to drink daily?', '["3-4 vasos","6-8 vasos","10-12 vasos","Solo cuando tengas sed"]'::jsonb, '["3-4 glasses","6-8 glasses","10-12 glasses","Only when thirsty"]'::jsonb, 1, 'Se recomienda beber 6-8 vasos diarios de agua (equivalente a 1.5-2 litros), y más si haces ejercicio o hace calor.', 'It''s recommended to drink 6-8 glasses of water daily (equivalent to 1.5-2 liters), and more if you exercise or it''s hot.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('722df124-98de-4a7a-b4ad-4309e85d810f', '¿Cuál es la forma correcta de buscar información sobre las causas específicas de la Revolución Mexicana en Wikipedia usando Google?', 'What is the correct way to search for information about the specific causes of the Mexican Revolution on Wikipedia using Google?', '["revolución mexicana","site:wikipedia.org revolución mexicana causas","\"revolución mexicana\" -causas","revolución mexicana filetype:pdf"]'::jsonb, '["mexican revolution","site:wikipedia.org mexican revolution causes","\"mexican revolution\" -causes","mexican revolution filetype:pdf"]'::jsonb, 1, 'La opción correcta usa ''site:wikipedia.org'' para buscar específicamente en Wikipedia, seguido de términos específicos como ''causas'' para obtener información más precisa.', 'The correct option uses ''site:wikipedia.org'' to search specifically on Wikipedia, followed by specific terms like ''causes'' to get more precise information.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('722df124-98de-4a7a-b4ad-4309e85d810f', '¿Cuál de las siguientes características NO es un indicador de una fuente confiable?', 'Which of the following characteristics is NOT an indicator of a reliable source?', '["Autor identificable","Muchos anuncios publicitarios","Referencias y fuentes citadas","Dominio .edu o .gob"]'::jsonb, '["Identifiable author","Many advertisements","References and cited sources",".edu or .gov domain"]'::jsonb, 1, 'Los sitios con muchos anuncios publicitarios generalmente NO son confiables, ya que pueden priorizar el beneficio económico sobre la calidad de la información.', 'Sites with many advertisements are generally NOT reliable, as they may prioritize economic benefit over information quality.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('722df124-98de-4a7a-b4ad-4309e85d810f', '¿Qué atajo de teclado te permite buscar una palabra específica dentro de la página web que estás visitando?', 'What keyboard shortcut allows you to search for a specific word within the web page you are visiting?', '["Ctrl+T","Ctrl+L","Ctrl+F","Ctrl+D"]'::jsonb, '["Ctrl+T","Ctrl+L","Ctrl+F","Ctrl+D"]'::jsonb, 2, 'Ctrl+F abre la función de búsqueda dentro de la página, permitiéndote encontrar palabras o frases específicas en el contenido que estás viendo.', 'Ctrl+F opens the search function within the page, allowing you to find specific words or phrases in the content you are viewing.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9c640e06-5523-45d2-a923-aaab300be291', '¿Cuál es la estrategia de estudio más recomendada para una persona con estilo de aprendizaje auditivo?', 'What is the most recommended study strategy for a person with auditory learning style?', '["Crear mapas conceptuales con colores","Grabar explicaciones y escucharlas","Hacer resúmenes escritos","Resolver ejercicios prácticos"]'::jsonb, '["Create concept maps with colors","Record explanations and listen to them","Make written summaries","Solve practical exercises"]'::jsonb, 1, 'Las personas con estilo auditivo aprenden mejor escuchando, por lo que grabar explicaciones y escucharlas es la estrategia más adecuada para este tipo de aprendizaje.', 'People with auditory style learn better by listening, so recording explanations and listening to them is the most suitable strategy for this type of learning.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9c640e06-5523-45d2-a923-aaab300be291', 'Según el modelo VARK, ¿qué característica es típica de una persona con estilo kinestésico?', 'According to the VARK model, what characteristic is typical of a person with kinesthetic style?', '["Recuerda mejor lo que ve que lo que escucha","Se distrae fácilmente con ruidos","Prefiere leer instrucciones detalladas","Le cuesta trabajo estar quieto mientras estudia"]'::jsonb, '["Remembers better what they see than what they hear","Gets easily distracted by noise","Prefers to read detailed instructions","Has trouble staying still while studying"]'::jsonb, 3, 'Una señal característica del estilo kinestésico es que a estas personas les cuesta estar quietas, ya que aprenden mejor a través del movimiento y la práctica.', 'A characteristic sign of kinesthetic style is that these people have trouble staying still, as they learn better through movement and practice.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9c640e06-5523-45d2-a923-aaab300be291', '¿Cuántos tipos de inteligencia propuso Howard Gardner en su teoría de las inteligencias múltiples?', 'How many types of intelligence did Howard Gardner propose in his theory of multiple intelligences?', '["5 tipos","6 tipos","8 tipos","10 tipos"]'::jsonb, '["5 types","6 types","8 types","10 types"]'::jsonb, 2, 'Howard Gardner propuso que existen al menos 8 tipos de inteligencia: lingüística, lógico-matemática, espacial, musical, corporal-kinestésica, interpersonal, intrapersonal y naturalista.', 'Howard Gardner proposed that there are at least 8 types of intelligence: linguistic, logical-mathematical, spatial, musical, bodily-kinesthetic, interpersonal, intrapersonal, and naturalistic.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('98bc88c3-5587-487a-a992-b7f957a538d6', '¿Cuál es el resultado correcto de 4 + 6 × 2?', 'What is the correct result of 4 + 6 × 2?', '["20","16","14","12"]'::jsonb, '["20","16","14","12"]'::jsonb, 1, 'Según PEMDAS, la multiplicación se resuelve antes que la suma: 6 × 2 = 12, luego 4 + 12 = 16.', 'According to PEMDAS, multiplication is solved before addition: 6 × 2 = 12, then 4 + 12 = 16.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('98bc88c3-5587-487a-a992-b7f957a538d6', 'En la expresión 18 ÷ 3 × 2, ¿cuál es el orden correcto de resolución?', 'In the expression 18 ÷ 3 × 2, what is the correct order of solution?', '["Primero división, luego multiplicación","Primero multiplicación, luego división","Se resuelven de izquierda a derecha","No importa el orden"]'::jsonb, '["Division first, then multiplication","Multiplication first, then division","They are solved from left to right","Order doesn''t matter"]'::jsonb, 2, 'La multiplicación y división tienen la misma prioridad, por lo que se resuelven de izquierda a derecha: 18 ÷ 3 = 6, luego 6 × 2 = 12.', 'Multiplication and division have the same priority, so they are solved from left to right: 18 ÷ 3 = 6, then 6 × 2 = 12.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('98bc88c3-5587-487a-a992-b7f957a538d6', '¿Cuál es el resultado de 5 + (3 × 2)² - 4?', 'What is the result of 5 + (3 × 2)² - 4?', '["37","33","41","29"]'::jsonb, '["37","33","41","29"]'::jsonb, 0, 'Siguiendo PEMDAS: Paréntesis (3 × 2 = 6), Exponente (6² = 36), luego suma y resta de izquierda a derecha: 5 + 36 - 4 = 37.', 'Following PEMDAS: Parentheses (3 × 2 = 6), Exponent (6² = 36), then addition and subtraction from left to right: 5 + 36 - 4 = 37.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fb1d4456-c594-4bf8-bb26-8141dbc0bace', '¿Cuál es la forma correcta del verbo ''study'' en pasado simple?', 'What is the correct past simple form of the verb ''study''?', '["studyed","studied","studyied","studed"]'::jsonb, '["studyed","studied","studyied","studed"]'::jsonb, 1, 'Cuando un verbo termina en consonante + y, se cambia la ''y'' por ''ied''. Por eso ''study'' se convierte en ''studied''.', 'When a verb ends in consonant + y, we change ''y'' to ''ied''. That''s why ''study'' becomes ''studied''.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fb1d4456-c594-4bf8-bb26-8141dbc0bace', '¿Cuál es la forma negativa correcta de ''They worked yesterday''?', 'What is the correct negative form of ''They worked yesterday''?', '["They didn''t worked yesterday","They not worked yesterday","They didn''t work yesterday","They don''t worked yesterday"]'::jsonb, '["They didn''t worked yesterday","They not worked yesterday","They didn''t work yesterday","They don''t worked yesterday"]'::jsonb, 2, 'En la forma negativa del pasado simple usamos ''didn''t'' + verbo en forma base (sin -ed). Por eso es ''They didn''t work yesterday''.', 'In the negative form of simple past we use ''didn''t'' + base verb (without -ed). That''s why it''s ''They didn''t work yesterday''.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fb1d4456-c594-4bf8-bb26-8141dbc0bace', '¿Cuál es la pregunta correcta para ''She danced last night''?', 'What is the correct question for ''She danced last night''?', '["Danced she last night?","Did she danced last night?","Did she dance last night?","Does she danced last night?"]'::jsonb, '["Danced she last night?","Did she danced last night?","Did she dance last night?","Does she danced last night?"]'::jsonb, 2, 'Para formar preguntas en pasado simple usamos ''Did'' + sujeto + verbo en forma base. Por eso es ''Did she dance last night?''', 'To form questions in simple past we use ''Did'' + subject + base verb. That''s why it''s ''Did she dance last night?''', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('efdb546e-1924-4771-898e-ec8c964498e8', '¿Cuál es el porcentaje máximo recomendado para subrayar en un texto?', 'What is the maximum recommended percentage for highlighting in a text?', '["10% del texto","20% del texto","30% del texto","50% del texto"]'::jsonb, '["10% of the text","20% of the text","30% of the text","50% of the text"]'::jsonb, 1, 'El contenido establece claramente que se debe subrayar máximo el 20% del texto, enfocándose solo en las ideas principales para evitar saturar la lectura.', 'The content clearly states that you should highlight a maximum of 20% of the text, focusing only on main ideas to avoid overwhelming the reading.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('efdb546e-1924-4771-898e-ec8c964498e8', '¿Qué tipo de lectura usarías si necesitas encontrar rápidamente una fecha específica en un artículo largo?', 'What type of reading would you use if you need to quickly find a specific date in a long article?', '["Skimming","Scanning","Lectura intensiva","Lectura extensiva"]'::jsonb, '["Skimming","Scanning","Intensive reading","Extensive reading"]'::jsonb, 1, 'El scanning es la técnica de lectura rápida para buscar datos específicos, como fechas, nombres o números, sin leer todo el texto completo.', 'Scanning is the speed reading technique for finding specific data, such as dates, names, or numbers, without reading the entire text.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('efdb546e-1924-4771-898e-ec8c964498e8', '¿Cuál de estas actividades NO corresponde a las estrategias que se aplican ANTES de leer?', 'Which of these activities does NOT correspond to strategies applied BEFORE reading?', '["Establecer el propósito de lectura","Hacer anotaciones al margen","Activar conocimientos previos","Revisar la estructura del texto"]'::jsonb, '["Establish reading purpose","Make margin notes","Activate prior knowledge","Review text structure"]'::jsonb, 1, 'Hacer anotaciones al margen es una estrategia que se realiza DURANTE la lectura, no antes. Las estrategias previas incluyen establecer propósito, activar conocimientos y revisar estructura.', 'Making margin notes is a strategy performed DURING reading, not before. Pre-reading strategies include establishing purpose, activating knowledge, and reviewing structure.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('02deb5bf-d237-48dc-9533-97d161f2329f', '¿Cuál es la factorización correcta de la expresión 12x³ + 18x²?', 'What is the correct factorization of the expression 12x³ + 18x²?', '["6x²(2x + 3)","6x(2x² + 3x)","12x²(x + 6)","3x²(4x + 6)"]'::jsonb, '["6x²(2x + 3)","6x(2x² + 3x)","12x²(x + 6)","3x²(4x + 6)"]'::jsonb, 0, 'Primero identificamos el factor común: el MCD de 12 y 18 es 6, y la variable con menor exponente es x². Por tanto: 12x³ + 18x² = 6x²(2x + 3).', 'First we identify the common factor: the GCD of 12 and 18 is 6, and the variable with the smallest exponent is x². Therefore: 12x³ + 18x² = 6x²(2x + 3).', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('02deb5bf-d237-48dc-9533-97d161f2329f', 'La expresión x² - 49 es un ejemplo de:', 'The expression x² - 49 is an example of:', '["Factor común","Diferencia de cuadrados","Trinomio cuadrado perfecto","Trinomio de la forma x² + bx + c"]'::jsonb, '["Common factor","Difference of squares","Perfect square trinomial","Trinomial of the form x² + bx + c"]'::jsonb, 1, 'Es una diferencia de cuadrados porque tenemos dos términos que son cuadrados perfectos (x² y 49 = 7²) separados por un signo menos. Se factoriza como (x + 7)(x - 7).', 'It''s a difference of squares because we have two terms that are perfect squares (x² and 49 = 7²) separated by a minus sign. It factors as (x + 7)(x - 7).', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('02deb5bf-d237-48dc-9533-97d161f2329f', 'Para factorizar x² + 8x + 15, necesitamos encontrar dos números que:', 'To factor x² + 8x + 15, we need to find two numbers that:', '["Multiplicados den 8 y sumados den 15","Multiplicados den 15 y sumados den 8","Multiplicados den 23 y sumados den 7","Multiplicados den 1 y sumados den 23"]'::jsonb, '["Multiply to give 8 and add to give 15","Multiply to give 15 and add to give 8","Multiply to give 23 and add to give 7","Multiply to give 1 and add to give 23"]'::jsonb, 1, 'En un trinomio de la forma x² + bx + c, buscamos dos números que multiplicados den ''c'' (15) y sumados den ''b'' (8). Los números son 3 y 5, por lo que x² + 8x + 15 = (x + 3)(x + 5).', 'In a trinomial of the form x² + bx + c, we look for two numbers that multiply to give ''c'' (15) and add to give ''b'' (8). The numbers are 3 and 5, so x² + 8x + 15 = (x + 3)(x + 5).', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('055cfb28-2853-4fc3-b55e-1ad5ad8a72c9', '¿Cuál es la principal diferencia entre una noticia y un artículo de opinión?', 'What is the main difference between a news article and an opinion piece?', '["La noticia informa hechos objetivamente, mientras que el artículo de opinión expresa una postura personal","La noticia es más larga que el artículo de opinión","La noticia siempre incluye imágenes, el artículo de opinión no","La noticia se publica en primera plana, el artículo de opinión no"]'::jsonb, '["News reports facts objectively, while opinion pieces express a personal stance","News is longer than opinion pieces","News always includes images, opinion pieces don''t","News is published on the front page, opinion pieces are not"]'::jsonb, 0, 'La noticia debe informar hechos de forma objetiva sin incluir juicios de valor, mientras que el artículo de opinión permite al autor expresar su postura personal sobre un tema.', 'News should report facts objectively without including value judgments, while opinion pieces allow the author to express their personal stance on a topic.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('055cfb28-2853-4fc3-b55e-1ad5ad8a72c9', '¿Qué preguntas debe responder el lead o entrada de una noticia?', 'What questions should the lead or opening of a news story answer?', '["Las 5W: Qué, Quién, Cuándo, Dónde, Por qué","Solo el Qué y el Quién","Únicamente el Cuándo y el Dónde","Solo el Por qué y el Cómo"]'::jsonb, '["The 5Ws: What, Who, When, Where, Why","Only What and Who","Only When and Where","Only Why and How"]'::jsonb, 0, 'El lead o primer párrafo de una noticia debe responder las 5W del periodismo: Qué ocurrió, Quién está involucrado, Cuándo pasó, Dónde ocurrió y Por qué sucedió.', 'The lead or first paragraph of a news story should answer the 5Ws of journalism: What happened, Who is involved, When it happened, Where it occurred, and Why it happened.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('055cfb28-2853-4fc3-b55e-1ad5ad8a72c9', '¿Cuál de las siguientes NO es una estrategia recomendada para detectar noticias falsas?', 'Which of the following is NOT a recommended strategy for detecting fake news?', '["Compartir inmediatamente si el titular parece impactante","Verificar la fuente del medio que publica","Buscar la noticia en otros medios reconocidos","Revisar la fecha de publicación"]'::jsonb, '["Share immediately if the headline seems shocking","Verify the source of the publishing medium","Search for the news in other recognized media","Check the publication date"]'::jsonb, 0, 'Compartir inmediatamente por un titular impactante es justamente lo que NO se debe hacer. Es importante verificar la información antes de compartirla, ya que muchos titulares distorsionan el contenido real.', 'Sharing immediately because of a shocking headline is precisely what should NOT be done. It''s important to verify information before sharing it, as many headlines distort the actual content.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('89c22fca-746b-43f4-9ebb-798d86568257', '¿Cuál es el resultado de 2/5 + 1/3?', 'What is the result of 2/5 + 1/3?', '["3/8","11/15","6/15","5/15"]'::jsonb, '["3/8","11/15","6/15","5/15"]'::jsonb, 1, 'Para sumar fracciones con diferente denominador, necesitamos el mínimo común denominador. El MCD de 5 y 3 es 15. Convertimos: 2/5 = 6/15 y 1/3 = 5/15. Entonces: 6/15 + 5/15 = 11/15.', 'To add fractions with different denominators, we need the least common denominator. The LCD of 5 and 3 is 15. We convert: 2/5 = 6/15 and 1/3 = 5/15. Therefore: 6/15 + 5/15 = 11/15.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('89c22fca-746b-43f4-9ebb-798d86568257', '¿Cuál es la fracción equivalente del decimal 0.6?', 'What is the equivalent fraction of the decimal 0.6?', '["6/10","3/5","Ambas son correctas","6/100"]'::jsonb, '["6/10","3/5","Both are correct","6/100"]'::jsonb, 2, '0.6 tiene un decimal, por lo que se escribe como 6/10. Al simplificar dividiendo numerador y denominador entre 2, obtenemos 3/5. Ambas fracciones representan el mismo valor.', '0.6 has one decimal place, so it''s written as 6/10. When simplified by dividing both numerator and denominator by 2, we get 3/5. Both fractions represent the same value.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('89c22fca-746b-43f4-9ebb-798d86568257', '¿Cuál es el resultado de 3/4 ÷ 2/3?', 'What is the result of 3/4 ÷ 2/3?', '["6/12","9/8","5/7","1/2"]'::jsonb, '["6/12","9/8","5/7","1/2"]'::jsonb, 1, 'Para dividir fracciones, multiplicamos por el recíproco de la segunda fracción. 3/4 ÷ 2/3 = 3/4 × 3/2 = 9/8.', 'To divide fractions, we multiply by the reciprocal of the second fraction. 3/4 ÷ 2/3 = 3/4 × 3/2 = 9/8.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d9d1d0b8-1e15-44c1-bb61-04e32af35cb0', '¿Cuál es la forma correcta del pasado del verbo ''go''?', 'What is the correct past form of the verb ''go''?', '["goed","went","goes","going"]'::jsonb, '["goed","went","goes","going"]'::jsonb, 1, 'El verbo ''go'' es irregular y su forma en pasado es ''went'', no sigue la regla de agregar -ed.', 'The verb ''go'' is irregular and its past form is ''went'', it doesn''t follow the -ed rule.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d9d1d0b8-1e15-44c1-bb61-04e32af35cb0', 'Completa la oración: ''Yesterday, they _____ at home all day.''', 'Complete the sentence: ''Yesterday, they _____ at home all day.''', '["was","were","are","is"]'::jsonb, '["was","were","are","is"]'::jsonb, 1, 'Se usa ''were'' con el pronombre ''they'' en pasado simple. ''Was'' se usa solo con I, he, she, it.', 'We use ''were'' with the pronoun ''they'' in simple past. ''Was'' is only used with I, he, she, it.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d9d1d0b8-1e15-44c1-bb61-04e32af35cb0', '¿Cuál oración está correctamente escrita en pasado simple?', 'Which sentence is correctly written in simple past?', '["She maked a cake yesterday","She made a cake yesterday","She makes a cake yesterday","She making a cake yesterday"]'::jsonb, '["She maked a cake yesterday","She made a cake yesterday","She makes a cake yesterday","She making a cake yesterday"]'::jsonb, 1, 'El verbo ''make'' es irregular y su forma en pasado es ''made'', no ''maked''.', 'The verb ''make'' is irregular and its past form is ''made'', not ''maked''.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('f499bb47-47ca-43d1-8aec-9407af6a789b', '¿Cuál es la traducción correcta de ''Mi hermana favorita''?', 'What is the correct translation of ''Mi hermana favorita''?', '["My favorite brother","My favorite sister","My favorite cousin","My favorite daughter"]'::jsonb, '["My favorite brother","My favorite sister","My favorite cousin","My favorite daughter"]'::jsonb, 1, 'Sister significa hermana en inglés, mientras que brother es hermano.', 'Sister means hermana in English, while brother means hermano.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('f499bb47-47ca-43d1-8aec-9407af6a789b', '¿Qué día de la semana está escrito INCORRECTAMENTE?', 'Which day of the week is written INCORRECTLY?', '["Monday","wednesday","Friday","Sunday"]'::jsonb, '["Monday","wednesday","Friday","Sunday"]'::jsonb, 1, 'Los días de la semana en inglés siempre van con mayúscula inicial, por lo que debe ser ''Wednesday''.', 'Days of the week in English always start with a capital letter, so it should be ''Wednesday''.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('f499bb47-47ca-43d1-8aec-9407af6a789b', 'Si alguien dice ''My birthday is in July'', ¿en qué estación del año celebra su cumpleaños en el hemisferio norte?', 'If someone says ''My birthday is in July'', in which season do they celebrate their birthday in the northern hemisphere?', '["Spring","Summer","Fall","Winter"]'::jsonb, '["Spring","Summer","Fall","Winter"]'::jsonb, 1, 'July (julio) es un mes de verano (Summer) en el hemisferio norte.', 'July is a summer month in the northern hemisphere.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bfa10dba-13b7-4af5-a43e-539ac600f6e6', '¿Qué es la idea principal de un texto?', 'What is the main idea of a text?', '["Son todas las ideas que apoyan al tema","Es el mensaje central que responde a ''de qué trata''","Son los ejemplos que se dan en el párrafo","Es la última oración del texto"]'::jsonb, '["All the ideas that support the topic","It''s the central message that answers ''what is it about''","The examples given in the paragraph","It''s the last sentence of the text"]'::jsonb, 1, 'La idea principal es el mensaje central del texto que responde a la pregunta ''¿de qué trata?'' y si tuvieras que resumir todo el párrafo en una oración, esa sería la idea principal.', 'The main idea is the central message of the text that answers the question ''what is it about?'' and if you had to summarize the entire paragraph in one sentence, that would be the main idea.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bfa10dba-13b7-4af5-a43e-539ac600f6e6', 'En el ejemplo sobre México y su biodiversidad, ¿cuáles son las ideas secundarias?', 'In the example about Mexico and its biodiversity, what are the secondary ideas?', '["México es un país con enorme biodiversidad","Las 200,000 especies, animales de selvas, mares y desiertos","Solo los animales que viven en el mar","Únicamente los cactus del desierto"]'::jsonb, '["Mexico is a country with enormous biodiversity","The 200,000 species, animals from jungles, seas and deserts","Only the animals that live in the sea","Only the desert cacti"]'::jsonb, 1, 'Las ideas secundarias son las que apoyan y ejemplifican la idea principal. En este caso, las 200,000 especies y los ejemplos de animales de diferentes ecosistemas apoyan la idea de que México tiene gran biodiversidad.', 'Secondary ideas are those that support and exemplify the main idea. In this case, the 200,000 species and examples of animals from different ecosystems support the idea that Mexico has great biodiversity.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bfa10dba-13b7-4af5-a43e-539ac600f6e6', '¿Cuál es el nivel de comprensión lectora que busca responder ''¿Qué se puede deducir del texto?''?', 'What is the reading comprehension level that seeks to answer ''What can be deduced from the text?''?', '["Nivel literal","Nivel inferencial","Nivel crítico","Nivel básico"]'::jsonb, '["Literal level","Inferential level","Critical level","Basic level"]'::jsonb, 1, 'El nivel inferencial es el que busca deducir información que no está explícita en el texto, es decir, lo que no dice directamente pero se puede entender o deducir.', 'The inferential level seeks to deduce information that is not explicit in the text, that is, what it doesn''t say directly but can be understood or deduced.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('706f3daa-dc18-4bf6-9a4c-c56d32487d2b', 'Según el contenido, ¿cuál es la REALIDAD sobre los carbohidratos?', 'According to the content, what is the REALITY about carbohydrates?', '["Los carbohidratos siempre engordan y deben eliminarse","Los carbohidratos son la principal fuente de energía y se deben elegir los complejos","Solo se pueden comer carbohidratos en la mañana","Los carbohidratos light son los únicos saludables"]'::jsonb, '["Carbohydrates always cause weight gain and should be eliminated","Carbohydrates are the main source of energy and complex ones should be chosen","Carbohydrates can only be eaten in the morning","Light carbohydrates are the only healthy ones"]'::jsonb, 1, 'Los carbohidratos son la principal fuente de energía del cuerpo. El problema no son los carbohidratos en sí, sino el exceso de cualquier alimento. Se recomienda elegir carbohidratos complejos como los integrales.', 'Carbohydrates are the body''s main source of energy. The problem is not carbohydrates themselves, but excess of any food. It''s recommended to choose complex carbohydrates like whole grains.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('706f3daa-dc18-4bf6-9a4c-c56d32487d2b', 'Al leer etiquetas nutricionales, ¿qué cantidad de azúcar por porción se considera BAJA?', 'When reading nutrition labels, what amount of sugar per serving is considered LOW?', '["Menos de 10g por porción","Menos de 15g por porción","Menos de 5g por porción","Menos de 20g por porción"]'::jsonb, '["Less than 10g per serving","Less than 15g per serving","Less than 5g per serving","Less than 20g per serving"]'::jsonb, 2, 'Según el contenido, una cantidad baja de azúcar en los alimentos es menos de 5 gramos por porción. Esto ayuda a identificar productos más saludables.', 'According to the content, a low amount of sugar in foods is less than 5 grams per serving. This helps identify healthier products.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('706f3daa-dc18-4bf6-9a4c-c56d32487d2b', '¿Cuál de estas es una señal de ALERTA de trastornos alimentarios?', 'Which of these is a WARNING sign of eating disorders?', '["Comer frutas y verduras diariamente","Hacer ejercicio 3 veces por semana","Obsesión excesiva con el peso o la imagen corporal","Leer las etiquetas de los alimentos"]'::jsonb, '["Eating fruits and vegetables daily","Exercising 3 times a week","Excessive obsession with weight or body image","Reading food labels"]'::jsonb, 2, 'La obsesión excesiva con el peso o la imagen corporal es una de las señales de alerta mencionadas para detectar posibles trastornos alimentarios que requieren ayuda profesional.', 'Excessive obsession with weight or body image is one of the warning signs mentioned to detect possible eating disorders that require professional help.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b8a4c6d1-54a5-4906-98a6-f1433d47419d', '¿Cuál de los siguientes nombres de variable NO sigue las reglas correctas de nomenclatura?', 'Which of the following variable names does NOT follow correct naming rules?', '["nombre_alumno","2promedio","edadEstudiante","aprobado"]'::jsonb, '["nombre_alumno","2promedio","edadEstudiante","aprobado"]'::jsonb, 1, 'Los nombres de variables no pueden empezar con números. ''2promedio'' viola esta regla, mientras que los demás nombres son válidos.', 'Variable names cannot start with numbers. ''2promedio'' violates this rule, while the other names are valid.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b8a4c6d1-54a5-4906-98a6-f1433d47419d', '¿Qué tipo de dato devuelve la operación de comparación ''edad >= 18''?', 'What data type does the comparison operation ''edad >= 18'' return?', '["Entero (int)","Decimal (float)","Texto (string)","Booleano (bool)"]'::jsonb, '["Integer (int)","Decimal (float)","Text (string)","Boolean (bool)"]'::jsonb, 3, 'Todas las operaciones de comparación devuelven un valor booleano: verdadero o falso (true/false).', 'All comparison operations return a boolean value: true or false.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b8a4c6d1-54a5-4906-98a6-f1433d47419d', 'Si tenemos las variables a = 10 y b = 3, ¿cuál es el resultado de a % b?', 'If we have variables a = 10 and b = 3, what is the result of a % b?', '["3","1","13","3.33"]'::jsonb, '["3","1","13","3.33"]'::jsonb, 1, 'El operador módulo (%) devuelve el residuo de la división. 10 dividido entre 3 es 3 con residuo 1, por lo tanto 10 % 3 = 1.', 'The modulo operator (%) returns the remainder of division. 10 divided by 3 is 3 with remainder 1, therefore 10 % 3 = 1.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0368b63a-aee7-412a-8f2a-4bbbfd0efd43', '¿Cuál de las siguientes opciones representa un nombre de usuario PROFESIONAL para correo electrónico?', 'Which of the following options represents a PROFESSIONAL email username?', '["princesita_pink@gmail.com","maria.gonzalez.h@gmail.com","elchido99@gmail.com","corazoncito2024@gmail.com"]'::jsonb, '["princesita_pink@gmail.com","maria.gonzalez.h@gmail.com","elchido99@gmail.com","corazoncito2024@gmail.com"]'::jsonb, 1, 'Un nombre de usuario profesional debe incluir tu nombre real o iniciales, evitando apodos, diminutivos o palabras informales que no proyecten seriedad.', 'A professional username should include your real name or initials, avoiding nicknames, diminutives or informal words that don''t project seriousness.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0368b63a-aee7-412a-8f2a-4bbbfd0efd43', 'En la estructura de un correo formal, ¿qué debe contener la introducción?', 'In the structure of a formal email, what should the introduction contain?', '["Solo un saludo cordial","Quién eres y por qué escribes en una oración","Todo el mensaje principal detallado","Únicamente tu nombre completo"]'::jsonb, '["Only a cordial greeting","Who you are and why you''re writing in one sentence","All the detailed main message","Only your full name"]'::jsonb, 1, 'La introducción debe ser breve y clara, presentándote e indicando el motivo del correo en una sola oración para que el destinatario entienda inmediatamente el propósito.', 'The introduction should be brief and clear, introducing yourself and stating the reason for the email in one sentence so the recipient immediately understands the purpose.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0368b63a-aee7-412a-8f2a-4bbbfd0efd43', 'Según las reglas de etiqueta digital, ¿cuál de estas prácticas es INCORRECTA?', 'According to digital etiquette rules, which of these practices is INCORRECT?', '["Responder en máximo 24-48 horas","ESCRIBIR TODO EL MENSAJE EN MAYÚSCULAS","Revisar ortografía antes de enviar","Usar un asunto descriptivo"]'::jsonb, '["Respond within maximum 24-48 hours","WRITE THE ENTIRE MESSAGE IN CAPITAL LETTERS","Check spelling before sending","Use a descriptive subject"]'::jsonb, 1, 'Escribir en mayúsculas equivale a gritar en el mundo digital y es considerado de mala educación. Debe evitarse para mantener un tono profesional y respetuoso.', 'Writing in capital letters is equivalent to shouting in the digital world and is considered rude. It should be avoided to maintain a professional and respectful tone.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('21b99e99-d12d-4306-a3dc-23659996d021', '¿En qué fecha dio Miguel Hidalgo el Grito de Dolores que marcó el inicio de la Independencia de México?', 'On what date did Miguel Hidalgo give the Cry of Dolores that marked the beginning of Mexico''s Independence?', '["15 de septiembre de 1810","16 de septiembre de 1810","27 de septiembre de 1810","16 de septiembre de 1811"]'::jsonb, '["September 15, 1810","September 16, 1810","September 27, 1810","September 16, 1811"]'::jsonb, 1, 'Miguel Hidalgo dio el Grito de Dolores el 16 de septiembre de 1810, fecha que marca el inicio oficial del movimiento de independencia mexicano.', 'Miguel Hidalgo gave the Cry of Dolores on September 16, 1810, the date that marks the official beginning of the Mexican independence movement.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('21b99e99-d12d-4306-a3dc-23659996d021', '¿Cuál fue el documento escrito por José María Morelos que expresaba los ideales del movimiento independentista?', 'What was the document written by José María Morelos that expressed the ideals of the independence movement?', '["Plan de Iguala","Sentimientos de la Nación","Constitución de Apatzingán","Grito de Dolores"]'::jsonb, '["Plan of Iguala","Feelings of the Nation","Constitution of Apatzingán","Cry of Dolores"]'::jsonb, 1, 'José María Morelos escribió ''Sentimientos de la Nación'', documento que establecía los principios fundamentales para la nueva nación mexicana.', 'José María Morelos wrote ''Feelings of the Nation'', a document that established the fundamental principles for the new Mexican nation.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('21b99e99-d12d-4306-a3dc-23659996d021', '¿Qué sistema educativo se implementó en el México independiente donde un alumno avanzado enseñaba a otros?', 'What educational system was implemented in independent Mexico where an advanced student taught others?', '["Sistema Jesuita","Compañía Lancasteriana","Escuelas Normales","Sistema Franciscano"]'::jsonb, '["Jesuit System","Lancasterian Company","Normal Schools","Franciscan System"]'::jsonb, 1, 'La Compañía Lancasteriana fue el sistema educativo donde un alumno avanzado enseñaba a otros estudiantes, permitiendo educar a más personas con menos maestros.', 'The Lancasterian Company was the educational system where an advanced student taught other students, allowing more people to be educated with fewer teachers.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('98f431a1-b299-49c5-a947-8141786cc878', '¿Cuál es la diferencia principal entre pubertad y adolescencia?', 'What is the main difference between puberty and adolescence?', '["La pubertad solo afecta a las mujeres, la adolescencia a los hombres","La pubertad se refiere a cambios físicos, la adolescencia incluye también aspectos psicosociales","La pubertad dura más tiempo que la adolescencia","No hay diferencia, son sinónimos"]'::jsonb, '["Puberty only affects women, adolescence affects men","Puberty refers to physical changes, adolescence also includes psychosocial aspects","Puberty lasts longer than adolescence","There is no difference, they are synonyms"]'::jsonb, 1, 'La pubertad es el periodo de cambios físicos para desarrollar capacidad reproductiva, mientras que la adolescencia es el periodo psicosocial más amplio que incluye estos cambios físicos y también los aspectos emocionales y sociales.', 'Puberty is the period of physical changes to develop reproductive capacity, while adolescence is the broader psychosocial period that includes these physical changes and also emotional and social aspects.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('98f431a1-b299-49c5-a947-8141786cc878', '¿En qué rango de edad generalmente comienza la pubertad?', 'In what age range does puberty generally begin?', '["Entre los 6 y 10 años para ambos sexos","Entre los 8-13 años para mujeres y 9-14 años para hombres","Entre los 12-16 años para ambos sexos","Entre los 10-12 años para mujeres y 14-16 años para hombres"]'::jsonb, '["Between 6 and 10 years for both sexes","Between 8-13 years for women and 9-14 years for men","Between 12-16 years for both sexes","Between 10-12 years for women and 14-16 years for men"]'::jsonb, 1, 'Según el contenido, la pubertad en mujeres ocurre generalmente entre los 8 y 13 años, mientras que en hombres ocurre entre los 9 y 14 años, siendo un proceso gradual que dura varios años.', 'According to the content, puberty in women generally occurs between 8 and 13 years old, while in men it occurs between 9 and 14 years old, being a gradual process that lasts several years.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('98f431a1-b299-49c5-a947-8141786cc878', '¿Cuál de las siguientes situaciones requiere atención médica?', 'Which of the following situations requires medical attention?', '["Cambios de humor frecuentes durante la adolescencia","Sentir confusión sobre los cambios corporales","No tener ningún signo de pubertad después de los 14 años","Mayor necesidad de privacidad"]'::jsonb, '["Frequent mood swings during adolescence","Feeling confused about body changes","Having no signs of puberty after age 14","Greater need for privacy"]'::jsonb, 2, 'No tener ningún signo de pubertad después de los 14 años no es normal y requiere atención médica, mientras que los cambios de humor, confusión y necesidad de privacidad son parte normal del proceso de adolescencia.', 'Having no signs of puberty after age 14 is not normal and requires medical attention, while mood swings, confusion, and need for privacy are normal parts of the adolescence process.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e869bd2c-84c2-49ad-83ca-4dccc6f89cf6', '¿Cuál es el primer paso para resolver la ecuación 2(3x - 5) + 7 = 4x + 1?', 'What is the first step to solve the equation 2(3x - 5) + 7 = 4x + 1?', '["Sumar 7 a ambos lados","Distribuir el 2 en el paréntesis","Restar 4x de ambos lados","Dividir toda la ecuación entre 2"]'::jsonb, '["Add 7 to both sides","Distribute the 2 in the parentheses","Subtract 4x from both sides","Divide the entire equation by 2"]'::jsonb, 1, 'Cuando hay paréntesis en una ecuación, el primer paso es distribuir para eliminarlos. En este caso, distribuir el 2: 2(3x - 5) = 6x - 10.', 'When there are parentheses in an equation, the first step is to distribute to eliminate them. In this case, distribute the 2: 2(3x - 5) = 6x - 10.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e869bd2c-84c2-49ad-83ca-4dccc6f89cf6', 'Para resolver x/2 + x/6 = 8, ¿por qué número debes multiplicar toda la ecuación?', 'To solve x/2 + x/6 = 8, by what number should you multiply the entire equation?', '["2","6","8","6"]'::jsonb, '["2","6","8","6"]'::jsonb, 3, 'Debes multiplicar por el MCM de los denominadores. El MCM de 2 y 6 es 6, ya que 6 es divisible entre 2 y entre 6.', 'You must multiply by the LCM of the denominators. The LCM of 2 and 6 is 6, since 6 is divisible by both 2 and 6.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e869bd2c-84c2-49ad-83ca-4dccc6f89cf6', '¿Cuál es el error en esta solución: -(2x + 3) = -2x + 3?', 'What is the error in this solution: -(2x + 3) = -2x + 3?', '["No hay error","El signo negativo no se distribuyó correctamente al 3","Falta multiplicar por 2","Se debió sumar en lugar de restar"]'::jsonb, '["There is no error","The negative sign was not distributed correctly to the 3","Need to multiply by 2","Should have added instead of subtracted"]'::jsonb, 1, 'El signo negativo debe distribuirse a todos los términos dentro del paréntesis. La forma correcta es: -(2x + 3) = -2x - 3.', 'The negative sign must be distributed to all terms inside the parentheses. The correct form is: -(2x + 3) = -2x - 3.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e0722730-85dc-4383-a269-e8f7cf78ed9d', '¿En qué consiste la técnica de recuerdo activo (Active Recall)?', 'What does the Active Recall technique consist of?', '["Releer el material varias veces hasta memorizarlo","Cerrar el material e intentar recordar lo que se leyó","Subrayar las partes más importantes del texto","Copiar los apuntes textualmente"]'::jsonb, '["Reread the material several times until memorized","Close the material and try to remember what was read","Highlight the most important parts of the text","Copy notes verbatim"]'::jsonb, 1, 'El recuerdo activo consiste en cerrar el material e intentar recordar lo que se leyó, hacerse preguntas y explicar el tema sin ver el contenido. Es la técnica más efectiva según la ciencia.', 'Active recall consists of closing the material and trying to remember what was read, asking yourself questions and explaining the topic without looking at the content. It is the most effective technique according to science.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e0722730-85dc-4383-a269-e8f7cf78ed9d', '¿Cuál es la estructura correcta de la Técnica Pomodoro?', 'What is the correct structure of the Pomodoro Technique?', '["Estudiar 30 minutos y descansar 10 minutos","Estudiar 25 minutos y descansar 5 minutos, repitiendo 4 veces","Estudiar 45 minutos y descansar 15 minutos","Estudiar 20 minutos y descansar 10 minutos"]'::jsonb, '["Study 30 minutes and rest 10 minutes","Study 25 minutes and rest 5 minutes, repeating 4 times","Study 45 minutes and rest 15 minutes","Study 20 minutes and rest 10 minutes"]'::jsonb, 1, 'La Técnica Pomodoro consiste en estudiar 25 minutos con concentración total, descansar 5 minutos, repetir 4 veces y después del 4° pomodoro descansar 15-30 minutos.', 'The Pomodoro Technique consists of studying 25 minutes with total concentration, resting 5 minutes, repeating 4 times and after the 4th pomodoro resting 15-30 minutes.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e0722730-85dc-4383-a269-e8f7cf78ed9d', 'Según el contenido, ¿cuál de estas prácticas NO es efectiva para estudiar?', 'According to the content, which of these practices is NOT effective for studying?', '["Usar la repetición espaciada para repasar","Aplicar la Técnica Feynman explicando como a un niño","Releer el material una y otra vez","Crear mapas mentales con colores y conexiones"]'::jsonb, '["Using spaced repetition for review","Applying the Feynman Technique explaining as to a child","Rereading the material over and over","Creating mind maps with colors and connections"]'::jsonb, 2, 'Releer una y otra vez está listado específicamente como una técnica que NO funciona porque crea una ilusión de aprendizaje, aunque es una práctica popular.', 'Rereading over and over is specifically listed as a technique that does NOT work because it creates an illusion of learning, although it is a popular practice.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('56dad3dc-78bd-48f4-9929-9d8c5efe92d3', '¿Cuál es la combinación de teclas correcta para aplicar formato de negrita en Google Docs?', 'What is the correct key combination to apply bold formatting in Google Docs?', '["Ctrl+B","Ctrl+N","Ctrl+G","Ctrl+F"]'::jsonb, '["Ctrl+B","Ctrl+N","Ctrl+G","Ctrl+F"]'::jsonb, 0, 'Ctrl+B es el atajo de teclado estándar para aplicar formato de negrita en procesadores de texto, incluyendo Google Docs.', 'Ctrl+B is the standard keyboard shortcut to apply bold formatting in word processors, including Google Docs.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('56dad3dc-78bd-48f4-9929-9d8c5efe92d3', 'Para el formato académico básico en tareas, ¿cuál debe ser el interlineado recomendado?', 'For basic academic formatting in assignments, what should be the recommended line spacing?', '["Sencillo","1.5 o doble","Triple","1.25"]'::jsonb, '["Single","1.5 or double","Triple","1.25"]'::jsonb, 1, 'El formato académico básico requiere interlineado de 1.5 o doble para facilitar la lectura y permitir comentarios del profesor.', 'Basic academic formatting requires 1.5 or double line spacing to facilitate reading and allow teacher comments.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('56dad3dc-78bd-48f4-9929-9d8c5efe92d3', '¿Cuál es la ventaja principal de Google Docs sobre Microsoft Word?', 'What is the main advantage of Google Docs over Microsoft Word?', '["Tiene más funciones","Es gratuito y guarda automáticamente en la nube","Solo funciona sin internet","Es más rápido"]'::jsonb, '["It has more features","It''s free and automatically saves to the cloud","It only works without internet","It''s faster"]'::jsonb, 1, 'Google Docs es gratuito, funciona en el navegador y guarda automáticamente en la nube, lo que evita perder el trabajo.', 'Google Docs is free, works in the browser, and automatically saves to the cloud, which prevents losing work.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('519b2f0d-8866-42a5-a868-7b72b16b3de1', '¿Cuál es el ÚNICO método anticonceptivo que también protege contra las infecciones de transmisión sexual?', 'Which is the ONLY contraceptive method that also protects against sexually transmitted infections?', '["Las pastillas anticonceptivas","El condón","El DIU","El implante subdérmico"]'::jsonb, '["Birth control pills","The condom","The IUD","The subdermal implant"]'::jsonb, 1, 'El condón (masculino o femenino) es el único método anticonceptivo que además de prevenir embarazos, protege contra las infecciones de transmisión sexual al crear una barrera física.', 'The condom (male or female) is the only contraceptive method that, in addition to preventing pregnancy, protects against sexually transmitted infections by creating a physical barrier.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('519b2f0d-8866-42a5-a868-7b72b16b3de1', '¿Cuál de las siguientes infecciones de transmisión sexual es la más común?', 'Which of the following sexually transmitted infections is the most common?', '["VIH/SIDA","VPH (Virus del Papiloma Humano)","Sífilis","Herpes genital"]'::jsonb, '["HIV/AIDS","HPV (Human Papillomavirus)","Syphilis","Genital herpes"]'::jsonb, 1, 'Según el contenido, el VPH (Virus del Papiloma Humano) es la ITS más común. Puede causar verrugas genitales y cáncer cervicouterino, pero existe vacuna para prevenirlo.', 'According to the content, HPV (Human Papillomavirus) is the most common STI. It can cause genital warts and cervical cancer, but there is a vaccine to prevent it.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('519b2f0d-8866-42a5-a868-7b72b16b3de1', '¿Cuáles de los siguientes NO son métodos anticonceptivos confiables?', 'Which of the following are NOT reliable contraceptive methods?', '["Condón y pastillas anticonceptivas","DIU e implante subdérmico","Ritmo calendario y coito interrumpido","Inyección hormonal y parche"]'::jsonb, '["Condom and birth control pills","IUD and subdermal implant","Calendar rhythm and withdrawal method","Hormonal injection and patch"]'::jsonb, 2, 'El ritmo calendario y el coito interrumpido (''salirse antes'') NO son métodos confiables según el contenido. Es importante usar métodos comprobadamente efectivos para prevenir embarazos no deseados.', 'The calendar rhythm method and withdrawal method (''pulling out'') are NOT reliable methods according to the content. It''s important to use proven effective methods to prevent unwanted pregnancies.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('7ec0b567-eb65-4d0c-98fb-6727a1fb9384', 'Según la Matriz de Eisenhower, ¿cómo debes clasificar un examen que tienes mañana?', 'According to the Eisenhower Matrix, how should you classify an exam you have tomorrow?', '["Importante + No urgente: Planificar","No importante + Urgente: Delegar/rápido","Importante + Urgente: Hacer YA","No importante + No urgente: Eliminar"]'::jsonb, '["Important + Not urgent: Plan","Not important + Urgent: Delegate/quick","Important + Urgent: Do NOW","Not important + Not urgent: Eliminate"]'::jsonb, 2, 'Un examen para mañana es tanto importante (afecta tus calificaciones) como urgente (el tiempo límite es muy cercano), por lo que va en el cuadrante ''Hacer YA''.', 'An exam for tomorrow is both important (affects your grades) and urgent (deadline is very close), so it goes in the ''Do NOW'' quadrant.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('7ec0b567-eb65-4d0c-98fb-6727a1fb9384', '¿Cuánto tiempo sugiere el contenido dedicar cada domingo a la planificación semanal?', 'How much time does the content suggest dedicating each Sunday to weekly planning?', '["30 minutos","15 minutos","1 hora","5 minutos"]'::jsonb, '["30 minutes","15 minutes","1 hour","5 minutes"]'::jsonb, 1, 'El contenido específicamente menciona dedicar 15 minutos cada domingo para planificar la semana siguiente, lo cual es suficiente y realista.', 'The content specifically mentions dedicating 15 minutes each Sunday to plan the following week, which is sufficient and realistic.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('7ec0b567-eb65-4d0c-98fb-6727a1fb9384', '¿Qué establece la ''regla de los 5 minutos'' para vencer la procrastinación?', 'What does the ''5-minute rule'' establish for overcoming procrastination?', '["Si algo toma menos de 5 minutos, hazlo ahora","Toma un descanso de 5 minutos cada hora","Comprométete a estudiar solo 5 minutos para empezar","Divide las tareas en bloques de 5 minutos"]'::jsonb, '["If something takes less than 5 minutes, do it now","Take a 5-minute break every hour","Commit to studying just 5 minutes to get started","Divide tasks into 5-minute blocks"]'::jsonb, 2, 'La regla de los 5 minutos consiste en comprometerse a estudiar solo 5 minutos. Una vez que empiezas, generalmente continúas estudiando por más tiempo.', 'The 5-minute rule consists of committing to study for just 5 minutes. Once you start, you generally continue studying for longer.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bf689d51-e5cd-40b5-8ce0-648d6d537fe7', '¿Qué representa la solución de un sistema de ecuaciones lineales con 2 incógnitas de manera visual?', 'What does the solution of a system of linear equations with 2 unknowns represent visually?', '["El punto donde dos líneas rectas se cruzan","La pendiente de las líneas","El intercepto con el eje y","La distancia entre las líneas"]'::jsonb, '["The point where two straight lines intersect","The slope of the lines","The y-intercept","The distance between the lines"]'::jsonb, 0, 'La solución de un sistema de ecuaciones lineales con 2 incógnitas representa gráficamente el punto donde las dos líneas rectas se cruzan, ya que ese punto satisface ambas ecuaciones simultáneamente.', 'The solution of a system of linear equations with 2 unknowns graphically represents the point where two straight lines intersect, since that point satisfies both equations simultaneously.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bf689d51-e5cd-40b5-8ce0-648d6d537fe7', 'Resuelve por sustitución: x + y = 8 y 2x - y = 4. ¿Cuál es el valor de x?', 'Solve by substitution: x + y = 8 and 2x - y = 4. What is the value of x?', '["x = 3","x = 4","x = 5","x = 6"]'::jsonb, '["x = 3","x = 4","x = 5","x = 6"]'::jsonb, 1, 'De la primera ecuación: y = 8 - x. Sustituyendo en la segunda: 2x - (8-x) = 4, entonces 2x - 8 + x = 4, por lo que 3x = 12 y x = 4.', 'From the first equation: y = 8 - x. Substituting into the second: 2x - (8-x) = 4, so 2x - 8 + x = 4, therefore 3x = 12 and x = 4.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('bf689d51-e5cd-40b5-8ce0-648d6d537fe7', '¿Qué tipo de sistema tiene infinitas soluciones?', 'What type of system has infinite solutions?', '["Sistema inconsistente","Sistema dependiente","Sistema consistente","Sistema independiente"]'::jsonb, '["Inconsistent system","Dependent system","Consistent system","Independent system"]'::jsonb, 1, 'Un sistema dependiente tiene infinitas soluciones porque las ecuaciones representan la misma línea recta, por lo que todos los puntos de esa línea satisfacen ambas ecuaciones.', 'A dependent system has infinite solutions because the equations represent the same straight line, so all points on that line satisfy both equations.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ab966df6-1c1e-4994-8604-36e0ea3c7cf4', '¿Cuál de las siguientes palabras esdrújulas está correctamente acentuada?', 'Which of the following esdrújula words is correctly accented?', '["medico","músico","pajaro","matematica"]'::jsonb, '["medico","músico","pajaro","matematica"]'::jsonb, 1, 'Las palabras esdrújulas SIEMPRE llevan tilde sin excepción. ''Músico'' es la única opción que tiene la tilde correcta en la antepenúltima sílaba.', 'Esdrújula words ALWAYS carry a written accent without exception. ''Músico'' is the only option that has the correct accent on the antepenultimate syllable.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ab966df6-1c1e-4994-8604-36e0ea3c7cf4', '¿Cuál es la regla correcta para acentuar las palabras agudas?', 'What is the correct rule for accenting aguda words?', '["Llevan tilde cuando terminan en consonante","Llevan tilde cuando terminan en N, S o vocal","Nunca llevan tilde","Siempre llevan tilde"]'::jsonb, '["They carry an accent when they end in a consonant","They carry an accent when they end in N, S or vowel","They never carry an accent","They always carry an accent"]'::jsonb, 1, 'Las palabras agudas llevan tilde únicamente cuando terminan en N, S o vocal. Por ejemplo: café, camión, compás.', 'Aguda words carry an accent only when they end in N, S or vowel. For example: café, camión, compás.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ab966df6-1c1e-4994-8604-36e0ea3c7cf4', '¿Cuál par de palabras ejemplifica correctamente el uso de la tilde diacrítica?', 'Which pair of words correctly exemplifies the use of the diacritical accent?', '["casa - casá","él (pronombre) - el (artículo)","libro - libró","mesa - mesá"]'::jsonb, '["casa - casá","él (pronoun) - el (article)","libro - libró","mesa - mesá"]'::jsonb, 1, 'La tilde diacrítica distingue palabras que se escriben igual pero tienen diferente significado. ''Él'' (pronombre personal) lleva tilde para diferenciarse de ''el'' (artículo).', 'The diacritical accent distinguishes words that are spelled the same but have different meanings. ''Él'' (personal pronoun) carries an accent to differentiate from ''el'' (article).', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a3e91941-922e-430e-a571-e3566f8c43e1', '¿Cuál de las siguientes opciones describe mejor qué es una tesis en un texto argumentativo?', 'Which of the following options best describes what a thesis is in an argumentative text?', '["Los datos concretos que respaldan las ideas del autor","La postura central del autor, lo que quiere que el lector crea","Las razones que da el autor para apoyar sus ideas","La mención de posiciones contrarias para refutarlas"]'::jsonb, '["The concrete data that supports the author''s ideas","The author''s central position, what they want the reader to believe","The reasons the author gives to support their ideas","The mention of opposing positions to refute them"]'::jsonb, 1, 'La tesis es la postura central del autor, la idea principal que quiere convencer al lector de que acepte. Es el núcleo del texto argumentativo.', 'The thesis is the author''s central position, the main idea they want to convince the reader to accept. It is the core of the argumentative text.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a3e91941-922e-430e-a571-e3566f8c43e1', '¿Qué tipo de falacia se comete en el siguiente ejemplo: ''No deberíamos escuchar la propuesta de Juan sobre cambio climático porque es muy joven''?', 'What type of fallacy is committed in the following example: ''We shouldn''t listen to Juan''s proposal about climate change because he''s very young''?', '["Falsa causa","Ad hominem","Generalización apresurada","Falso dilema"]'::jsonb, '["False cause","Ad hominem","Hasty generalization","False dilemma"]'::jsonb, 1, 'Es una falacia ad hominem porque ataca a la persona (su edad) en lugar de evaluar el mérito de su argumento sobre cambio climático.', 'It''s an ad hominem fallacy because it attacks the person (their age) instead of evaluating the merit of their argument about climate change.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a3e91941-922e-430e-a571-e3566f8c43e1', '¿Cuál es la función principal de los contraargumentos en un texto argumentativo?', 'What is the main function of counterarguments in an argumentative text?', '["Confundir al lector con ideas contradictorias","Demostrar que el autor no tiene una posición clara","Mencionar posiciones contrarias para refutarlas y fortalecer la tesis","Presentar evidencia estadística"]'::jsonb, '["To confuse the reader with contradictory ideas","To show that the author doesn''t have a clear position","To mention opposing positions in order to refute them and strengthen the thesis","To present statistical evidence"]'::jsonb, 2, 'Los contraargumentos permiten al autor reconocer posiciones contrarias y refutarlas, lo cual fortalece su tesis al mostrar que ha considerado otras perspectivas.', 'Counterarguments allow the author to acknowledge opposing positions and refute them, which strengthens their thesis by showing they have considered other perspectives.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ff53dd98-22f6-43ed-9f97-75cfde1a615f', 'Según las recomendaciones de la OMS, ¿cuánto tiempo de actividad física deben realizar diariamente los adolescentes de 13-17 años?', 'According to WHO recommendations, how much physical activity should adolescents aged 13-17 perform daily?', '["30 minutos","45 minutos","60 minutos","90 minutos"]'::jsonb, '["30 minutes","45 minutes","60 minutes","90 minutes"]'::jsonb, 2, 'La OMS recomienda un mínimo de 60 minutos diarios de actividad física moderada a vigorosa para adolescentes.', 'WHO recommends a minimum of 60 minutes daily of moderate to vigorous physical activity for adolescents.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ff53dd98-22f6-43ed-9f97-75cfde1a615f', '¿Cuál de los siguientes NO es un beneficio mental de la actividad física mencionado en el contenido?', 'Which of the following is NOT a mental benefit of physical activity mentioned in the content?', '["Reduce el estrés y ansiedad","Mejora la memoria","Aumenta la masa muscular","Mejora el estado de ánimo"]'::jsonb, '["Reduces stress and anxiety","Improves memory","Increases muscle mass","Improves mood"]'::jsonb, 2, 'El aumento de masa muscular es un beneficio físico, no mental. Los beneficios mentales incluyen reducir estrés, mejorar memoria y estado de ánimo.', 'Increased muscle mass is a physical benefit, not mental. Mental benefits include reducing stress, improving memory and mood.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ff53dd98-22f6-43ed-9f97-75cfde1a615f', 'Si alguien no ha hecho ejercicio antes, ¿cuál es la recomendación para empezar?', 'If someone hasn''t exercised before, what is the recommendation to start?', '["Hacer 60 minutos desde el primer día","Empezar con 15-20 minutos y aumentar gradualmente","Solo hacer ejercicios de alta intensidad","Ir directamente al gimnasio"]'::jsonb, '["Do 60 minutes from day one","Start with 15-20 minutes and gradually increase","Only do high-intensity exercises","Go directly to the gym"]'::jsonb, 1, 'Para principiantes se recomienda empezar con 15-20 minutos e ir aumentando gradualmente, priorizando la consistencia sobre la intensidad.', 'For beginners, it''s recommended to start with 15-20 minutes and gradually increase, prioritizing consistency over intensity.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('03491332-6c25-43f6-a372-5eecf0fd5f7a', '¿Cuál es la forma correcta de expresar una decisión espontánea en el momento?', 'What is the correct way to express a spontaneous decision in the moment?', '["I''m going to help you","I will help you","I help you","I''m helping you"]'::jsonb, '["I''m going to help you","I will help you","I help you","I''m helping you"]'::jsonb, 1, 'Para decisiones espontáneas del momento usamos WILL. La estructura es sujeto + will + verbo base.', 'For spontaneous decisions in the moment we use WILL. The structure is subject + will + base verb.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('03491332-6c25-43f6-a372-5eecf0fd5f7a', 'Si ya compraste boletos de avión para el próximo mes, ¿cómo expresas este plan?', 'If you already bought plane tickets for next month, how do you express this plan?', '["I will travel next month","I''m going to travel next month","I travel next month","I''ll be traveling next month"]'::jsonb, '["I will travel next month","I''m going to travel next month","I travel next month","I''ll be traveling next month"]'::jsonb, 1, 'Para planes e intenciones ya decididas usamos GOING TO. Ya tienes los boletos, es un plan confirmado.', 'For plans and intentions already decided we use GOING TO. You already have the tickets, it''s a confirmed plan.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('03491332-6c25-43f6-a372-5eecf0fd5f7a', '¿Cuál es la forma interrogativa correcta con WILL?', 'What is the correct interrogative form with WILL?', '["Do you will come?","Will you come?","Are you will come?","You will come?"]'::jsonb, '["Do you will come?","Will you come?","Are you will come?","You will come?"]'::jsonb, 1, 'Para formar preguntas con WILL, la estructura es: Will + sujeto + verbo base + ?', 'To form questions with WILL, the structure is: Will + subject + base verb + ?', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('67645733-03da-434d-b4cb-9f197ea3d5b8', '¿Cuál es la diferencia entre = y == en programación?', 'What is the difference between = and == in programming?', '["= es para comparar y == es para asignar","= es para asignar y == es para comparar","Ambos sirven para lo mismo","= solo funciona con números y == con texto"]'::jsonb, '["= is for comparing and == is for assigning","= is for assigning and == is for comparing","Both serve the same purpose","= only works with numbers and == with text"]'::jsonb, 1, 'El símbolo = se usa para asignar valores a variables, mientras que == se usa para comparar si dos valores son iguales en las condiciones.', 'The = symbol is used to assign values to variables, while == is used to compare if two values are equal in conditions.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('67645733-03da-434d-b4cb-9f197ea3d5b8', 'En el ejemplo de la ropa según el clima, si temperatura = 20 y esta_lloviendo = falso, ¿qué mensaje se mostraría?', 'In the clothing example based on weather, if temperatura = 20 and esta_lloviendo = false, what message would be displayed?', '["Lleva paraguas y chamarra impermeable","Lleva chamarra abrigadora","Lleva suéter ligero","Ropa fresca"]'::jsonb, '["Bring umbrella and raincoat","Bring warm jacket","Bring light sweater","Fresh clothes"]'::jsonb, 2, 'Como no está lloviendo (falso) y la temperatura es 20 (mayor que 15 pero menor que 25), se ejecuta la condición ''temperatura < 25'' que indica ''Lleva suéter ligero''.', 'Since it''s not raining (false) and the temperature is 20 (greater than 15 but less than 25), the condition ''temperatura < 25'' is executed, indicating ''Bring light sweater''.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('67645733-03da-434d-b4cb-9f197ea3d5b8', '¿Cuál es el propósito del operador AND en las condiciones compuestas?', 'What is the purpose of the AND operator in compound conditions?', '["Que solo una de las condiciones sea verdadera","Que ambas condiciones sean verdaderas al mismo tiempo","Que ninguna condición sea verdadera","Que las condiciones se ejecuten por separado"]'::jsonb, '["Only one of the conditions must be true","Both conditions must be true at the same time","Neither condition must be true","The conditions are executed separately"]'::jsonb, 1, 'El operador AND requiere que todas las condiciones conectadas sean verdaderas para que el bloque de código se ejecute. En el ejemplo, tanto ''edad >= 18'' como ''tiene_licencia == verdadero'' deben cumplirse.', 'The AND operator requires that all connected conditions be true for the code block to execute. In the example, both ''edad >= 18'' and ''tiene_licencia == verdadero'' must be met.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('74cdcbee-f875-471a-8392-38002bef140f', '¿Cuál fue el principal objetivo de las Leyes de Reforma impulsadas por Benito Juárez?', 'What was the main objective of the Reform Laws promoted by Benito Juárez?', '["Fortalecer el poder de la Iglesia Católica","Separar la Iglesia del Estado y modernizar México","Recuperar el territorio perdido ante Estados Unidos","Establecer una monarquía constitucional"]'::jsonb, '["Strengthen the power of the Catholic Church","Separate Church from State and modernize Mexico","Recover territory lost to the United States","Establish a constitutional monarchy"]'::jsonb, 1, 'Las Leyes de Reforma buscaron separar completamente la Iglesia del Estado y sentar las bases del México moderno, eliminando privilegios eclesiásticos y estableciendo un Estado laico.', 'The Reform Laws sought to completely separate Church from State and lay the foundations of modern Mexico, eliminating ecclesiastical privileges and establishing a secular State.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('74cdcbee-f875-471a-8392-38002bef140f', '¿Qué estableció la Constitución de 1857 en materia educativa?', 'What did the Constitution of 1857 establish regarding education?', '["Educación exclusivamente religiosa","Educación laica, gratuita y obligatoria","Educación solo para las clases altas","Educación mixta religiosa y civil"]'::jsonb, '["Exclusively religious education","Secular, free and mandatory education","Education only for upper classes","Mixed religious and civil education"]'::jsonb, 1, 'La Constitución de 1857 estableció los principios de educación laica (sin influencia religiosa), gratuita y obligatoria, principios que siguen vigentes en México.', 'The Constitution of 1857 established the principles of secular education (without religious influence), free and mandatory, principles that remain in force in Mexico.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('74cdcbee-f875-471a-8392-38002bef140f', '¿Qué sucedió durante la Intervención Francesa en México (1862-1867)?', 'What happened during the French Intervention in Mexico (1862-1867)?', '["Francia ayudó a Juárez a consolidar la República","Francia impuso a Maximiliano como emperador, pero Juárez resistió y triunfó","México recuperó los territorios perdidos ante Estados Unidos","Se estableció definitivamente la monarquía en México"]'::jsonb, '["France helped Juárez consolidate the Republic","France imposed Maximilian as emperor, but Juárez resisted and triumphed","Mexico recovered territories lost to the United States","Monarchy was definitively established in Mexico"]'::jsonb, 1, 'Durante la Intervención Francesa, Francia logró imponer a Maximiliano de Habsburgo como emperador, pero Benito Juárez mantuvo la resistencia republicana y finalmente triunfó, ejecutando a Maximiliano en 1867.', 'During the French Intervention, France managed to impose Maximilian of Habsburg as emperor, but Benito Juárez maintained republican resistance and finally triumphed, executing Maximilian in 1867.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('97168b14-4628-4650-8e54-2f924637e551', '¿Cuál es la forma correcta de completar la frase: ''I need ___ umbrella for ___ rain''?', 'What is the correct way to complete the sentence: ''I need ___ umbrella for ___ rain''?', '["a umbrella / a rain","an umbrella / the rain","a umbrella / the rain","an umbrella / a rain"]'::jsonb, '["a umbrella / a rain","an umbrella / the rain","a umbrella / the rain","an umbrella / a rain"]'::jsonb, 1, 'Se usa ''an'' antes de umbrella porque empieza con vocal, y ''the'' con rain porque es específica (la lluvia de la que estamos hablando).', 'We use ''an'' before umbrella because it starts with a vowel, and ''the'' with rain because it''s specific (the rain we''re talking about).', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('97168b14-4628-4650-8e54-2f924637e551', '¿Cuál es el plural correcto de las siguientes palabras: knife, baby, box?', 'What is the correct plural of the following words: knife, baby, box?', '["knifes, babys, boxs","knives, babies, boxes","knifes, babies, boxs","knives, babys, boxes"]'::jsonb, '["knifes, babys, boxs","knives, babies, boxes","knifes, babies, boxs","knives, babys, boxes"]'::jsonb, 1, 'Knife termina en -f, cambia a -ves. Baby termina en consonante+y, cambia a -ies. Box termina en -x, se agrega -es.', 'Knife ends in -f, changes to -ves. Baby ends in consonant+y, changes to -ies. Box ends in -x, add -es.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('97168b14-4628-4650-8e54-2f924637e551', '¿Cuáles de estos sustantivos son INCONTABLES y NO pueden usar ''a/an'' ni plural?', 'Which of these nouns are UNCOUNTABLE and CANNOT use ''a/an'' or plural?', '["book, car, dog","water, music, information","man, woman, child","city, baby, story"]'::jsonb, '["book, car, dog","water, music, information","man, woman, child","city, baby, story"]'::jsonb, 1, 'Water, music e information son sustantivos incontables, no se pueden contar con números y no llevan artículos indefinidos ni plural.', 'Water, music and information are uncountable nouns, they can''t be counted with numbers and don''t take indefinite articles or plurals.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d498879e-4394-4470-8154-6b9a550a7657', '¿Cómo se expresa algebraicamente ''el triple de un número más cuatro''?', 'How is ''three times a number plus four'' expressed algebraically?', '["3 + x + 4","3x + 4","3(x + 4)","x³ + 4"]'::jsonb, '["3 + x + 4","3x + 4","3(x + 4)","x³ + 4"]'::jsonb, 1, 'El triple de un número se expresa como 3x (tres veces la variable x), y al agregarle cuatro se obtiene 3x + 4.', 'Three times a number is expressed as 3x (three times the variable x), and adding four gives us 3x + 4.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d498879e-4394-4470-8154-6b9a550a7657', '¿Cuáles de los siguientes términos son semejantes?', 'Which of the following terms are like terms?', '["2x y 5x²","3xy y 7xy","4x y 6y","x² y 2x"]'::jsonb, '["2x and 5x²","3xy and 7xy","4x and 6y","x² and 2x"]'::jsonb, 1, 'Los términos 3xy y 7xy son semejantes porque tienen exactamente las mismas variables (x e y) con los mismos exponentes (1 para ambas).', 'The terms 3xy and 7xy are like terms because they have exactly the same variables (x and y) with the same exponents (1 for both).', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d498879e-4394-4470-8154-6b9a550a7657', 'Al simplificar la expresión 6x - 2x + 4x, ¿cuál es el resultado?', 'When simplifying the expression 6x - 2x + 4x, what is the result?', '["8x","12x","10x","2x"]'::jsonb, '["8x","12x","10x","2x"]'::jsonb, 0, 'Al agrupar términos semejantes: 6x - 2x + 4x = (6 - 2 + 4)x = 8x.', 'When combining like terms: 6x - 2x + 4x = (6 - 2 + 4)x = 8x.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('69ab9f20-8142-4cc6-ad0e-4135569b6ae0', '¿Cuál fue el lema principal de Francisco I. Madero durante la Revolución Mexicana?', 'What was Francisco I. Madero''s main slogan during the Mexican Revolution?', '["La tierra es de quien la trabaja","Sufragio efectivo, no reelección","Justicia para los pobres del norte","Orden constitucional"]'::jsonb, '["The land belongs to those who work it","Effective suffrage, no re-election","Justice for the poor of the north","Constitutional order"]'::jsonb, 1, 'Francisco I. Madero luchaba por la democracia y su lema era ''Sufragio efectivo, no reelección'', oponiéndose a la dictadura de Porfirio Díaz.', 'Francisco I. Madero fought for democracy and his slogan was ''Effective suffrage, no re-election'', opposing Porfirio Díaz''s dictatorship.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('69ab9f20-8142-4cc6-ad0e-4135569b6ae0', '¿Qué establece el Artículo 3° de la Constitución de 1917?', 'What does Article 3 of the 1917 Constitution establish?', '["Derechos laborales como jornada de 8 horas","Que la tierra y recursos pertenecen a la nación","Educación laica, gratuita y obligatoria","El derecho al voto para las mujeres"]'::jsonb, '["Labor rights such as 8-hour workday","That land and resources belong to the nation","Secular, free and mandatory education","The right to vote for women"]'::jsonb, 2, 'El Artículo 3° establece que la educación debe ser laica, gratuita y obligatoria, siendo uno de los grandes logros sociales de la Revolución Mexicana.', 'Article 3 establishes that education must be secular, free and mandatory, being one of the great social achievements of the Mexican Revolution.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('69ab9f20-8142-4cc6-ad0e-4135569b6ae0', '¿En qué año se hizo obligatorio el bachillerato en México?', 'In what year did high school become mandatory in Mexico?', '["1917","1920","2000","2012"]'::jsonb, '["1917","1920","2000","2012"]'::jsonb, 3, 'En 2012 se hizo obligatorio el bachillerato, extendiendo el derecho constitucional a la educación hasta el nivel medio superior.', 'In 2012, high school became mandatory, extending the constitutional right to education to the upper secondary level.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fff9308e-29fc-4d4e-a93d-450a47fe8085', '¿Cuál es el primer paso para resolver la ecuación 4x + 12 = 28?', 'What is the first step to solve the equation 4x + 12 = 28?', '["Dividir ambos lados entre 4","Restar 12 de ambos lados","Sumar 12 a ambos lados","Multiplicar ambos lados por 4"]'::jsonb, '["Divide both sides by 4","Subtract 12 from both sides","Add 12 to both sides","Multiply both sides by 4"]'::jsonb, 1, 'Para aislar la variable x, primero debemos eliminar el término constante +12 restando 12 de ambos lados, siguiendo el principio de la balanza.', 'To isolate the variable x, we must first eliminate the constant term +12 by subtracting 12 from both sides, following the balance principle.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fff9308e-29fc-4d4e-a93d-450a47fe8085', 'Al resolver 3x - 5 = x + 7, ¿cuál es el valor de x?', 'When solving 3x - 5 = x + 7, what is the value of x?', '["x = 2","x = 6","x = 4","x = 8"]'::jsonb, '["x = 2","x = 6","x = 4","x = 8"]'::jsonb, 1, 'Restando x de ambos lados: 2x - 5 = 7. Sumando 5 a ambos lados: 2x = 12. Dividiendo entre 2: x = 6.', 'Subtracting x from both sides: 2x - 5 = 7. Adding 5 to both sides: 2x = 12. Dividing by 2: x = 6.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fff9308e-29fc-4d4e-a93d-450a47fe8085', '¿Por qué es importante comprobar la solución de una ecuación?', 'Why is it important to check the solution of an equation?', '["Para hacer la ecuación más difícil","Para verificar que el valor encontrado hace que ambos lados sean iguales","Para cambiar el resultado","Para encontrar más soluciones"]'::jsonb, '["To make the equation more difficult","To verify that the found value makes both sides equal","To change the result","To find more solutions"]'::jsonb, 1, 'La comprobación es la regla de oro porque nos asegura que el valor encontrado para x realmente satisface la ecuación original, confirmando que nuestra solución es correcta.', 'Checking is the golden rule because it ensures that the value found for x actually satisfies the original equation, confirming that our solution is correct.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ad6eaf5c-86f8-4de0-a780-835364e39267', '¿Cuál es la forma correcta de usar CAN en tercera persona?', 'What is the correct way to use CAN in third person?', '["She cans swim very well","She can swim very well","She can swims very well","She do can swim very well"]'::jsonb, '["She cans swim very well","She can swim very well","She can swims very well","She do can swim very well"]'::jsonb, 1, 'Los verbos modales nunca llevan -S en tercera persona y siempre van seguidos del verbo en forma base.', 'Modal verbs never take -S in third person and are always followed by the base form of the verb.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ad6eaf5c-86f8-4de0-a780-835364e39267', '¿Cuál es la diferencia principal entre MUST y HAVE TO?', 'What is the main difference between MUST and HAVE TO?', '["No hay diferencia","Must es más personal/interno, Have to es más externo/por reglas","Must es para el pasado, Have to para el presente","Must es informal, Have to es formal"]'::jsonb, '["There''s no difference","Must is more personal/internal, Have to is more external/by rules","Must is for past, Have to for present","Must is informal, Have to is formal"]'::jsonb, 1, 'Must expresa una obligación más personal o interna, mientras que Have to se usa para obligaciones externas o impuestas por reglas.', 'Must expresses a more personal or internal obligation, while Have to is used for external obligations or those imposed by rules.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ad6eaf5c-86f8-4de0-a780-835364e39267', '¿Cuál es la forma correcta de hacer una pregunta con SHOULD?', 'What is the correct way to make a question with SHOULD?', '["Do you should see a doctor?","Should you see a doctor?","You should see a doctor?","Does you should see a doctor?"]'::jsonb, '["Do you should see a doctor?","Should you see a doctor?","You should see a doctor?","Does you should see a doctor?"]'::jsonb, 1, 'Los verbos modales no necesitan DO/DOES para formar preguntas. Se invierte el orden: modal + sujeto + verbo base.', 'Modal verbs don''t need DO/DOES to form questions. The order is inverted: modal + subject + base verb.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('5d71530d-4e10-483a-827c-c4ca46137492', '¿Cuál es la técnica de respiración profunda mencionada para manejar el estrés?', 'What is the deep breathing technique mentioned for managing stress?', '["Inhalar 3 segundos, retener 3, exhalar 3","Inhalar 4 segundos, retener 4, exhalar 4","Inhalar 5 segundos, retener 5, exhalar 5","Inhalar 6 segundos, retener 6, exhalar 6"]'::jsonb, '["Inhale 3 seconds, hold 3, exhale 3","Inhale 4 seconds, hold 4, exhale 4","Inhale 5 seconds, hold 5, exhale 5","Inhale 6 seconds, hold 6, exhale 6"]'::jsonb, 1, 'La técnica correcta es inhalar 4 segundos, retener 4 segundos y exhalar 4 segundos, repitiendo 5 veces para activar el sistema parasimpático y generar calma.', 'The correct technique is to inhale for 4 seconds, hold for 4 seconds, and exhale for 4 seconds, repeating 5 times to activate the parasympathetic system and create calm.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('5d71530d-4e10-483a-827c-c4ca46137492', '¿Cuándo se debe buscar ayuda profesional para problemas de salud mental?', 'When should professional help be sought for mental health problems?', '["Solo cuando hay pensamientos de hacerse daño","Cuando los síntomas duran más de 2 semanas e interfieren con la vida diaria","Únicamente si se usan sustancias","Solo cuando la familia lo sugiere"]'::jsonb, '["Only when there are thoughts of self-harm","When symptoms last more than 2 weeks and interfere with daily life","Only if substances are used","Only when family suggests it"]'::jsonb, 1, 'Se debe buscar ayuda profesional cuando los síntomas duran más de 2 semanas, interfieren con la vida diaria, hay pensamientos de hacerse daño, o se usan sustancias para lidiar con las emociones.', 'Professional help should be sought when symptoms last more than 2 weeks, interfere with daily life, there are thoughts of self-harm, or substances are used to cope with emotions.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('5d71530d-4e10-483a-827c-c4ca46137492', '¿Cuál NO es un síntoma típico de ansiedad según el contenido?', 'Which is NOT a typical symptom of anxiety according to the content?', '["Preocupación constante","Respiración acelerada","Pérdida de apetito prolongada","Taquicardia"]'::jsonb, '["Constant worry","Rapid breathing","Prolonged loss of appetite","Tachycardia"]'::jsonb, 2, 'La pérdida de apetito prolongada es mencionada como síntoma de depresión, no de ansiedad. Los síntomas de ansiedad incluyen preocupación constante, respiración acelerada, sudoración y taquicardia.', 'Prolonged loss of appetite is mentioned as a symptom of depression, not anxiety. Anxiety symptoms include constant worry, rapid breathing, sweating, and tachycardia.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0f9c4eaa-a0fd-4cde-a727-14c9b5e06c81', 'Según la regla 6×6 para presentaciones digitales, ¿cuál es el límite recomendado?', 'According to the 6×6 rule for digital presentations, what is the recommended limit?', '["Máximo 6 diapositivas con 6 imágenes cada una","Máximo 6 líneas por diapositiva y 6 palabras por línea","Máximo 6 fuentes diferentes y 6 colores por presentación","Máximo 6 minutos por diapositiva y 6 animaciones"]'::jsonb, '["Maximum 6 slides with 6 images each","Maximum 6 lines per slide and 6 words per line","Maximum 6 different fonts and 6 colors per presentation","Maximum 6 minutes per slide and 6 animations"]'::jsonb, 1, 'La regla 6×6 establece que debe haber máximo 6 líneas por diapositiva y máximo 6 palabras por línea para mantener las diapositivas claras y concisas.', 'The 6×6 rule establishes that there should be maximum 6 lines per slide and maximum 6 words per line to keep slides clear and concise.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0f9c4eaa-a0fd-4cde-a727-14c9b5e06c81', '¿Cuál es la función principal de las diapositivas en una presentación?', 'What is the main function of slides in a presentation?', '["Servir como documento completo para leer","Actuar como apoyo visual, no como guión","Contener todo el texto de la exposición","Reemplazar completamente la exposición oral"]'::jsonb, '["Serve as a complete document to read","Act as visual support, not as a script","Contain all the text of the presentation","Completely replace the oral presentation"]'::jsonb, 1, 'Las diapositivas son un apoyo visual para el presentador, no un documento para leer. El principio fundamental es ''menos es más'' y no se debe leer directamente de las diapositivas.', 'Slides are visual support for the presenter, not a document to read from. The fundamental principle is ''less is more'' and you should not read directly from the slides.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('0f9c4eaa-a0fd-4cde-a727-14c9b5e06c81', '¿Cuál es el tamaño mínimo recomendado para el texto del cuerpo en las diapositivas?', 'What is the minimum recommended size for body text in slides?', '["18 puntos","24 puntos","30 puntos","36 puntos"]'::jsonb, '["18 points","24 points","30 points","36 points"]'::jsonb, 1, 'El contenido establece que el texto debe ser grande, con mínimo 24 puntos para el cuerpo del texto y 36+ puntos para los títulos, para asegurar buena legibilidad.', 'The content establishes that text should be large, with minimum 24 points for body text and 36+ points for titles, to ensure good readability.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('337f93c7-c7bc-4173-98c4-ce5f6bbf3c3d', '¿Cuál de los siguientes es un derecho sexual reconocido internacionalmente?', 'Which of the following is an internationally recognized sexual right?', '["Derecho a tener relaciones solo después del matrimonio","Derecho a la información sexual basada en ciencia","Derecho a que los padres decidan sobre tu vida sexual","Derecho a ocultar tu orientación sexual"]'::jsonb, '["Right to have relationships only after marriage","Right to science-based sexual information","Right for parents to decide about your sexual life","Right to hide your sexual orientation"]'::jsonb, 1, 'El derecho a la información sexual basada en ciencia es uno de los 8 derechos sexuales fundamentales reconocidos internacionalmente, permitiendo que las personas tomen decisiones informadas sobre su sexualidad.', 'The right to science-based sexual information is one of the 8 fundamental sexual rights recognized internationally, allowing people to make informed decisions about their sexuality.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('337f93c7-c7bc-4173-98c4-ce5f6bbf3c3d', 'Según el contenido, ¿qué establece el artículo 4° de la Constitución mexicana?', 'According to the content, what does Article 4 of the Mexican Constitution establish?', '["El derecho a la educación sexual","El derecho a decidir de manera libre y responsable el número y espaciamiento de los hijos","El derecho a métodos anticonceptivos gratuitos","El derecho a la atención médica gratuita"]'::jsonb, '["The right to sexual education","The right to freely and responsibly decide the number and spacing of children","The right to free contraceptive methods","The right to free medical care"]'::jsonb, 1, 'El artículo 4° constitucional establece específicamente el derecho a decidir de manera libre y responsable el número y espaciamiento de los hijos, siendo un derecho reproductivo fundamental en México.', 'Constitutional Article 4 specifically establishes the right to freely and responsibly decide the number and spacing of children, being a fundamental reproductive right in Mexico.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('337f93c7-c7bc-4173-98c4-ce5f6bbf3c3d', '¿Cuál de las siguientes situaciones representa una violación a tus derechos sexuales y reproductivos?', 'Which of the following situations represents a violation of your sexual and reproductive rights?', '["Recibir educación sexual integral en la escuela","Que te nieguen información sobre anticonceptivos","Acudir a un centro de salud para consulta","Decidir no tener relaciones sexuales"]'::jsonb, '["Receiving comprehensive sexual education at school","Being denied information about contraceptives","Going to a health center for consultation","Deciding not to have sexual relations"]'::jsonb, 1, 'Negar información sobre anticonceptivos es una violación al derecho a la información sexual basada en ciencia y al derecho a acceder a métodos anticonceptivos, ambos derechos fundamentales.', 'Denying information about contraceptives is a violation of the right to science-based sexual information and the right to access contraceptive methods, both fundamental rights.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('dfd86690-196b-435a-b15c-dc24add54f49', '¿En cuál de las siguientes oraciones se usa INCORRECTAMENTE la coma?', 'In which of the following sentences is the comma used INCORRECTLY?', '["María, ven aquí inmediatamente.","Los estudiantes, llegaron tarde a clase.","Sin embargo, no pudo terminar la tarea.","Juan, el más inteligente del grupo, ganó el concurso."]'::jsonb, '["María, come here immediately.","The students, arrived late to class.","However, he couldn''t finish the homework.","Juan, the smartest in the group, won the contest."]'::jsonb, 1, 'Nunca se debe colocar coma entre sujeto y verbo. ''Los estudiantes llegaron tarde'' es la forma correcta, sin coma.', 'A comma should never be placed between subject and verb. ''The students arrived late'' is the correct form, without a comma.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('dfd86690-196b-435a-b15c-dc24add54f49', '¿Cuál es la diferencia entre ''No, espera.'' y ''No espera.''?', 'What is the difference between ''No, wait.'' and ''No wait.''?', '["No hay diferencia, significan lo mismo","La primera pide que alguien no se vaya, la segunda dice que alguien no tiene paciencia","La primera es incorrecta gramaticalmente","La segunda necesita signos de exclamación"]'::jsonb, '["There''s no difference, they mean the same","The first asks someone not to leave, the second says someone has no patience","The first is grammatically incorrect","The second needs exclamation marks"]'::jsonb, 1, 'La coma cambia completamente el significado: ''No, espera'' es una petición para que no se vaya, mientras que ''No espera'' describe que alguien no tiene paciencia.', 'The comma completely changes the meaning: ''No, wait'' is a request for someone not to leave, while ''No wait'' describes that someone has no patience.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('dfd86690-196b-435a-b15c-dc24add54f49', '¿Cuándo se usan los dos puntos (:)?', 'When are colons (:) used?', '["Solo para separar horas","Antes de enumerar, antes de citas textuales y después del saludo en cartas","Únicamente en listas de compras","Para reemplazar el punto y seguido"]'::jsonb, '["Only to separate hours","Before enumerating, before direct quotes and after greetings in letters","Only in shopping lists","To replace periods within paragraphs"]'::jsonb, 1, 'Los dos puntos tienen tres usos principales: antes de enumeraciones, antes de citas textuales y después del saludo en correspondencia formal.', 'Colons have three main uses: before enumerations, before direct quotes, and after greetings in formal correspondence.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('3cfafb80-615f-4ec6-bedf-22ddb6b917b8', 'Al resolver la desigualdad -2x + 8 ≥ 14, ¿cuál es la solución correcta?', 'When solving the inequality -2x + 8 ≥ 14, what is the correct solution?', '["x ≥ -3","x ≤ -3","x ≥ 3","x ≤ 3"]'::jsonb, '["x ≥ -3","x ≤ -3","x ≥ 3","x ≤ 3"]'::jsonb, 1, 'Restamos 8: -2x ≥ 6. Al dividir entre -2 (número negativo), se invierte el signo: x ≤ -3.', 'Subtract 8: -2x ≥ 6. When dividing by -2 (negative number), the inequality sign flips: x ≤ -3.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('3cfafb80-615f-4ec6-bedf-22ddb6b917b8', '¿Cómo se escribe en notación de intervalos la solución x > -4?', 'How do you write the solution x > -4 in interval notation?', '["[-4, ∞)","(-4, ∞)","(-∞, -4)","(-∞, -4]"]'::jsonb, '["[-4, ∞)","(-4, ∞)","(-∞, -4)","(-∞, -4]"]'::jsonb, 1, 'Como x > -4 (mayor que, no incluye -4), usamos paréntesis: (-4, ∞). El infinito siempre lleva paréntesis.', 'Since x > -4 (greater than, doesn''t include -4), we use parentheses: (-4, ∞). Infinity always uses parentheses.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('3cfafb80-615f-4ec6-bedf-22ddb6b917b8', 'Al resolver la desigualdad compuesta -1 ≤ 3x - 4 < 8, ¿cuál es la solución en notación de intervalos?', 'When solving the compound inequality -1 ≤ 3x - 4 < 8, what is the solution in interval notation?', '["[1, 4)","(-1, 8)","[1, 4]","(-1, 8]"]'::jsonb, '["[1, 4)","(-1, 8)","[1, 4]","(-1, 8]"]'::jsonb, 0, 'Sumamos 4: 3 ≤ 3x < 12. Dividimos entre 3: 1 ≤ x < 4. En intervalos: [1, 4) porque incluye 1 pero no 4.', 'Add 4: 3 ≤ 3x < 12. Divide by 3: 1 ≤ x < 4. In intervals: [1, 4) because it includes 1 but not 4.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9e6e7df2-f44f-4f35-9ce8-575342bd61a8', '¿Cuál es la forma correcta del verbo ''study'' para ''She'' en presente simple?', 'What is the correct form of the verb ''study'' for ''She'' in simple present?', '["She study English","She studys English","She studies English","She studyes English"]'::jsonb, '["She study English","She studys English","She studies English","She studyes English"]'::jsonb, 2, 'Con he/she/it se agrega -s al verbo. Como ''study'' termina en consonante + y, se cambia la ''y'' por ''ies'', quedando ''studies''.', 'With he/she/it we add -s to the verb. Since ''study'' ends in consonant + y, we change the ''y'' to ''ies'', making it ''studies''.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9e6e7df2-f44f-4f35-9ce8-575342bd61a8', '¿Dónde se coloca el adverbio de frecuencia ''always'' en la oración ''I _____ wake up at 7 AM''?', 'Where is the frequency adverb ''always'' placed in the sentence ''I _____ wake up at 7 AM''?', '["I wake up always at 7 AM","I always wake up at 7 AM","Always I wake up at 7 AM","I wake always up at 7 AM"]'::jsonb, '["I wake up always at 7 AM","I always wake up at 7 AM","Always I wake up at 7 AM","I wake always up at 7 AM"]'::jsonb, 1, 'Los adverbios de frecuencia van ANTES del verbo principal, por lo que ''always'' se coloca antes de ''wake up''.', 'Frequency adverbs go BEFORE the main verb, so ''always'' is placed before ''wake up''.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9e6e7df2-f44f-4f35-9ce8-575342bd61a8', '¿Cuál es la forma correcta del verbo ''go'' para ''He'' en presente simple?', 'What is the correct form of the verb ''go'' for ''He'' in simple present?', '["He go to school","He gos to school","He goes to school","He going to school"]'::jsonb, '["He go to school","He gos to school","He goes to school","He going to school"]'::jsonb, 2, 'Con he/she/it se agrega -s al verbo. Como ''go'' termina en ''o'', se agrega -es, quedando ''goes''.', 'With he/she/it we add -s to the verb. Since ''go'' ends in ''o'', we add -es, making it ''goes''.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('861615e1-2b0d-4592-a1b0-c60b9fdfbe20', '¿Cuál de las siguientes frases es un ejemplo de metáfora?', 'Which of the following phrases is an example of metaphor?', '["Corrió como el viento","Sus ojos eran dos luceros","Te lo he dicho mil veces","El sol se escondió detrás de las nubes"]'::jsonb, '["He ran like the wind","His eyes were two bright stars","I''ve told you a thousand times","The sun hid behind the clouds"]'::jsonb, 1, 'La metáfora dice que algo ES otra cosa sin usar ''como''. ''Sus ojos eran dos luceros'' afirma directamente que los ojos son estrellas, no los compara.', 'Metaphor says that something IS something else without using ''like''. ''His eyes were two bright stars'' directly states that eyes are stars, it doesn''t compare them.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('861615e1-2b0d-4592-a1b0-c60b9fdfbe20', '¿Qué figura literaria se utiliza en la frase ''La luna nos observaba''?', 'What literary figure is used in the phrase ''The moon was watching us''?', '["Hipérbole","Símil","Personificación","Antítesis"]'::jsonb, '["Hyperbole","Simile","Personification","Antithesis"]'::jsonb, 2, 'La personificación da cualidades humanas a objetos o animales. La luna no puede realmente observar, es una acción humana que se le atribuye.', 'Personification gives human qualities to objects or animals. The moon cannot really watch, it''s a human action attributed to it.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('861615e1-2b0d-4592-a1b0-c60b9fdfbe20', 'En la frase publicitaria ''El café que despierta tus sueños'', ¿qué recursos retóricos se combinan?', 'In the advertising phrase ''The coffee that awakens your dreams'', what rhetorical resources are combined?', '["Hipérbole y símil","Personificación y metáfora","Ironía y anáfora","Antítesis y comparación"]'::jsonb, '["Hyperbole and simile","Personification and metaphor","Irony and anaphora","Antithesis and comparison"]'::jsonb, 1, 'El café ''despierta'' (personificación - acción humana) y los ''sueños'' representan esperanzas o aspiraciones (metáfora), no sueños literales del dormir.', 'The coffee ''awakens'' (personification - human action) and ''dreams'' represent hopes or aspirations (metaphor), not literal sleeping dreams.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('96ec18c4-ecb2-4468-9168-3b9097cb5c70', '¿Cuál de las siguientes NO es una característica de una relación saludable?', 'Which of the following is NOT a characteristic of a healthy relationship?', '["Respeto mutuo por el espacio personal","Comunicación abierta y honesta","Celos excesivos para demostrar amor","Apoyo para el crecimiento personal"]'::jsonb, '["Mutual respect for personal space","Open and honest communication","Excessive jealousy to show love","Support for personal growth"]'::jsonb, 2, 'Los celos excesivos son una señal de relación tóxica, no saludable. En una relación sana debe existir confianza sin celos obsesivos.', 'Excessive jealousy is a sign of a toxic relationship, not a healthy one. In a healthy relationship there should be trust without obsessive jealousy.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('96ec18c4-ecb2-4468-9168-3b9097cb5c70', 'Para que exista consentimiento sexual válido, este debe ser:', 'For valid sexual consent to exist, it must be:', '["Solo libre de amenazas","Libre, informado, específico, reversible y entusiasta","Únicamente verbal","Permanente una vez dado"]'::jsonb, '["Only free from threats","Free, informed, specific, reversible and enthusiastic","Only verbal","Permanent once given"]'::jsonb, 1, 'El consentimiento sexual válido debe cumplir con todas estas características: libre, informado, específico, reversible y entusiasta para ser considerado verdadero consentimiento.', 'Valid sexual consent must meet all these characteristics: free, informed, specific, reversible and enthusiastic to be considered true consent.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('96ec18c4-ecb2-4468-9168-3b9097cb5c70', '¿Cuál de los siguientes comportamientos es un ejemplo de violencia digital?', 'Which of the following behaviors is an example of digital violence?', '["Controlar el dinero de la pareja","Difundir imágenes íntimas sin consentimiento","Dar empujones durante una discusión","Hacer comentarios humillantes en privado"]'::jsonb, '["Controlling partner''s money","Sharing intimate images without consent","Pushing during an argument","Making humiliating comments in private"]'::jsonb, 1, 'La difusión de imágenes íntimas sin consentimiento es un ejemplo claro de violencia digital, que incluye el acoso y abuso a través de medios digitales.', 'Sharing intimate images without consent is a clear example of digital violence, which includes harassment and abuse through digital media.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('331b617c-59a0-4de9-ae7f-da72fdb234ab', 'Según el método CRAAP para evaluar fuentes, ¿qué significa la ''A'' de Authority?', 'According to the CRAAP method for evaluating sources, what does the ''A'' in Authority mean?', '["Verificar si los datos son exactos y tienen fuentes","Identificar quién es el autor y si tiene credenciales","Determinar si la información es actual y vigente","Evaluar si el propósito es informar o persuadir"]'::jsonb, '["Check if the data is accurate and has sources","Identify who the author is and if they have credentials","Determine if the information is current and valid","Evaluate if the purpose is to inform or persuade"]'::jsonb, 1, 'Authority se refiere a evaluar quién es el autor y verificar si tiene las credenciales o experiencia necesaria para hablar sobre el tema.', 'Authority refers to evaluating who the author is and verifying if they have the necessary credentials or experience to speak about the topic.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('331b617c-59a0-4de9-ae7f-da72fdb234ab', '¿Cuál de los siguientes es un ejemplo del sesgo de confirmación?', 'Which of the following is an example of confirmation bias?', '["Creer que algo es verdad porque todos lo dicen","Solo buscar artículos que apoyen tu opinión sobre un tema","Pensar que alguien tiene razón en todo porque te cae bien","Darle demasiada importancia a la primera información que recibiste"]'::jsonb, '["Believing something is true because everyone says so","Only looking for articles that support your opinion on a topic","Thinking someone is right about everything because you like them","Giving too much importance to the first information you received"]'::jsonb, 1, 'El sesgo de confirmación ocurre cuando solo buscas información que confirma lo que ya crees, ignorando evidencia que contradiga tu opinión.', 'Confirmation bias occurs when you only look for information that confirms what you already believe, ignoring evidence that contradicts your opinion.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('331b617c-59a0-4de9-ae7f-da72fdb234ab', 'En la jerarquía de fuentes presentada, ¿cuál es considerada la MÁS confiable?', 'In the source hierarchy presented, which is considered the MOST reliable?', '["Sitios oficiales (.gob, .edu, .org reconocidas)","Artículos científicos revisados por pares","Libros académicos y enciclopedias","Periódicos y revistas reconocidos"]'::jsonb, '["Official websites (.gov, .edu, recognized .org)","Peer-reviewed scientific articles","Academic books and encyclopedias","Recognized newspapers and magazines"]'::jsonb, 1, 'Los artículos científicos revisados por pares ocupan el primer lugar en la jerarquía porque pasan por un riguroso proceso de evaluación por expertos antes de ser publicados.', 'Peer-reviewed scientific articles rank first in the hierarchy because they go through a rigorous evaluation process by experts before being published.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ded54196-ea5b-422f-a790-472b8e9d9890', '¿Cuál es la diferencia principal entre dato e información?', 'What is the main difference between data and information?', '["Un dato es procesado y tiene contexto, mientras que información es un hecho aislado","Un dato es un hecho aislado sin contexto, mientras que información son datos procesados con significado","No hay diferencia, son sinónimos","Un dato es más importante que la información"]'::jsonb, '["Data is processed and has context, while information is an isolated fact","Data is an isolated fact without context, while information is processed data with meaning","There is no difference, they are synonyms","Data is more important than information"]'::jsonb, 1, 'Un dato es un hecho aislado sin contexto (como ''25''), mientras que la información son datos procesados que tienen significado y contexto (como ''La temperatura es 25°C'').', 'Data is an isolated fact without context (like ''25''), while information is processed data that has meaning and context (like ''The temperature is 25°C'').', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ded54196-ea5b-422f-a790-472b8e9d9890', '¿Qué fórmula de Excel usarías para mostrar ''Aprobado'' si una calificación es mayor o igual a 6, y ''Reprobado'' si es menor?', 'What Excel formula would you use to show ''Approved'' if a grade is greater than or equal to 6, and ''Failed'' if it''s less?', '["=PROMEDIO(A1>=6, ''Aprobado'', ''Reprobado'')","=SI(A1>=6, ''Aprobado'', ''Reprobado'')","=CONTAR(A1>=6, ''Aprobado'', ''Reprobado'')","=SUMA(A1>=6, ''Aprobado'', ''Reprobado'')"]'::jsonb, '["=AVERAGE(A1>=6, ''Approved'', ''Failed'')","=IF(A1>=6, ''Approved'', ''Failed'')","=COUNT(A1>=6, ''Approved'', ''Failed'')","=SUM(A1>=6, ''Approved'', ''Failed'')"]'::jsonb, 1, 'La función SI (IF en inglés) permite crear condiciones lógicas. La sintaxis correcta es =SI(condición, valor_si_verdadero, valor_si_falso).', 'The IF function allows creating logical conditions. The correct syntax is =IF(condition, value_if_true, value_if_false).', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ded54196-ea5b-422f-a790-472b8e9d9890', '¿Qué tipo de gráfica es más adecuada para mostrar cómo han cambiado las ventas de una empresa mes a mes durante un año?', 'What type of chart is most suitable to show how a company''s sales have changed month by month during a year?', '["Gráfica circular (pastel)","Gráfica de barras","Gráfica de líneas","Gráfica de dispersión"]'::jsonb, '["Pie chart","Bar chart","Line chart","Scatter plot"]'::jsonb, 2, 'Las gráficas de líneas son ideales para mostrar tendencias y cambios a lo largo del tiempo, como la evolución de ventas mes a mes.', 'Line charts are ideal for showing trends and changes over time, such as the evolution of sales month by month.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d6d452dc-715b-47c9-a3f6-29a57877c330', '¿Cuántas horas de sueño necesitan los adolescentes de 14-17 años?', 'How many hours of sleep do teenagers aged 14-17 need?', '["6-7 horas","8-10 horas","7-9 horas","10-12 horas"]'::jsonb, '["6-7 hours","8-10 hours","7-9 hours","10-12 hours"]'::jsonb, 1, 'Los adolescentes de 14-17 años necesitan entre 8-10 horas de sueño para su correcto desarrollo y funcionamiento.', 'Teenagers aged 14-17 need between 8-10 hours of sleep for proper development and functioning.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d6d452dc-715b-47c9-a3f6-29a57877c330', '¿Por qué se recomienda evitar pantallas 30-60 minutos antes de dormir?', 'Why is it recommended to avoid screens 30-60 minutes before sleeping?', '["Porque causan dolor de cabeza","Porque la luz azul suprime la melatonina","Porque gastan mucha energía","Porque dañan la vista"]'::jsonb, '["Because they cause headaches","Because blue light suppresses melatonin","Because they waste a lot of energy","Because they damage eyesight"]'::jsonb, 1, 'La luz azul de las pantallas suprime la producción de melatonina, que es la hormona que regula el sueño.', 'Blue light from screens suppresses melatonin production, which is the hormone that regulates sleep.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('d6d452dc-715b-47c9-a3f6-29a57877c330', '¿Cuánto dura aproximadamente un ciclo completo de sueño?', 'How long does a complete sleep cycle last approximately?', '["60 minutos","90 minutos","120 minutos","45 minutos"]'::jsonb, '["60 minutes","90 minutes","120 minutes","45 minutes"]'::jsonb, 1, 'Un ciclo completo de sueño dura aproximadamente 90 minutos y se repite entre 4-6 veces durante la noche.', 'A complete sleep cycle lasts approximately 90 minutes and repeats 4-6 times during the night.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a4acbb34-1b6d-4509-b9c6-778d20e5b3dd', '¿Cuál es la principal ventaja de usar almacenamiento en la nube comparado con guardar archivos solo en tu computadora?', 'What is the main advantage of using cloud storage compared to saving files only on your computer?', '["Es más rápido acceder a los archivos","Puedes acceder desde cualquier dispositivo y no pierdes archivos si tu computadora se descompone","Los archivos ocupan menos espacio","Es completamente gratis sin límites"]'::jsonb, '["It''s faster to access files","You can access from any device and don''t lose files if your computer breaks","Files take up less space","It''s completely free without limits"]'::jsonb, 1, 'La nube permite acceder a tus archivos desde cualquier dispositivo con internet y protege contra la pérdida de datos si tu computadora se daña.', 'The cloud allows you to access your files from any device with internet and protects against data loss if your computer gets damaged.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a4acbb34-1b6d-4509-b9c6-778d20e5b3dd', '¿Cuál de estas opciones representa una buena práctica para nombrar archivos según el contenido?', 'Which of these options represents a good practice for naming files according to the content?', '["tarea1.docx","documento.docx","Tarea_Mat101_Semana3_MiNombre.docx","archivo_nuevo.docx"]'::jsonb, '["tarea1.docx","documento.docx","Tarea_Mat101_Semana3_MiNombre.docx","archivo_nuevo.docx"]'::jsonb, 2, 'Un buen nombre de archivo debe ser descriptivo e incluir información como la materia, semana y tu nombre para facilitar su identificación.', 'A good file name should be descriptive and include information like the subject, week, and your name to make it easy to identify.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a4acbb34-1b6d-4509-b9c6-778d20e5b3dd', '¿Cuánto espacio gratuito ofrece Google Drive y con qué servicios se integra principalmente?', 'How much free space does Google Drive offer and what services does it mainly integrate with?', '["5 GB gratis, se integra con Microsoft Office","15 GB gratis, se integra con Gmail, Docs, Slides","2 GB gratis, es muy fácil de usar","5 GB gratis, para dispositivos Apple"]'::jsonb, '["5 GB free, integrates with Microsoft Office","15 GB free, integrates with Gmail, Docs, Slides","2 GB free, very easy to use","5 GB free, for Apple devices"]'::jsonb, 1, 'Google Drive ofrece 15 GB de almacenamiento gratuito y se integra perfectamente con los servicios de Google como Gmail, Docs y Slides.', 'Google Drive offers 15 GB of free storage and integrates seamlessly with Google services like Gmail, Docs, and Slides.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9f821b12-2f84-4871-b16d-5696e7b61aad', '¿Cuál es la forma correcta de hacer una oración negativa con ''she''?', 'What is the correct way to make a negative sentence with ''she''?', '["She don''t like pizza","She doesn''t likes pizza","She doesn''t like pizza","She does not likes pizza"]'::jsonb, '["She don''t like pizza","She doesn''t likes pizza","She doesn''t like pizza","She does not likes pizza"]'::jsonb, 2, 'Con he/she/it se usa ''doesn''t'' y el verbo regresa a su forma base (sin S). Por eso es ''doesn''t like'', no ''doesn''t likes''.', 'With he/she/it we use ''doesn''t'' and the verb returns to its base form (without S). That''s why it''s ''doesn''t like'', not ''doesn''t likes''.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9f821b12-2f84-4871-b16d-5696e7b61aad', '¿Cuál es la estructura correcta para hacer una pregunta en presente simple?', 'What is the correct structure to make a question in simple present?', '["Sujeto + do/does + verbo + ?","Do/Does + sujeto + verbo base + ?","Do/Does + verbo + sujeto + ?","Verbo + sujeto + do/does + ?"]'::jsonb, '["Subject + do/does + verb + ?","Do/Does + subject + base verb + ?","Do/Does + verb + subject + ?","Verb + subject + do/does + ?"]'::jsonb, 1, 'La estructura correcta es: Do/Does + sujeto + verbo en forma base + complemento + ?', 'The correct structure is: Do/Does + subject + base form verb + complement + ?', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9f821b12-2f84-4871-b16d-5696e7b61aad', '¿Cuál es la respuesta corta correcta para ''Does he work here?''', 'What is the correct short answer for ''Does he work here?''', '["Yes, he do / No, he don''t","Yes, he does / No, he doesn''t","Yes, he works / No, he doesn''t work","Yes, does / No, doesn''t"]'::jsonb, '["Yes, he do / No, he don''t","Yes, he does / No, he doesn''t","Yes, he works / No, he doesn''t work","Yes, does / No, doesn''t"]'::jsonb, 1, 'Las respuestas cortas con ''does'' son: Yes, he does (afirmativa) o No, he doesn''t (negativa).', 'Short answers with ''does'' are: Yes, he does (affirmative) or No, he doesn''t (negative).', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4c009973-76d8-4227-895d-1415ba8d77e2', '¿Cuál es la pendiente de una recta que pasa por los puntos (2, 5) y (4, 11)?', 'What is the slope of a line that passes through the points (2, 5) and (4, 11)?', '["m = 3","m = -3","m = 6","m = 2"]'::jsonb, '["m = 3","m = -3","m = 6","m = 2"]'::jsonb, 0, 'Usando la fórmula m = (y₂ - y₁) / (x₂ - x₁), tenemos m = (11 - 5) / (4 - 2) = 6 / 2 = 3', 'Using the formula m = (y₂ - y₁) / (x₂ - x₁), we have m = (11 - 5) / (4 - 2) = 6 / 2 = 3', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4c009973-76d8-4227-895d-1415ba8d77e2', 'En la función y = -4x + 7, ¿cuál es la ordenada al origen?', 'In the function y = -4x + 7, what is the y-intercept?', '["7","-4","4","-7"]'::jsonb, '["7","-4","4","-7"]'::jsonb, 0, 'En la forma y = mx + b, el valor b representa la ordenada al origen, que en este caso es 7.', 'In the form y = mx + b, the value b represents the y-intercept, which in this case is 7.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('4c009973-76d8-4227-895d-1415ba8d77e2', 'Si una función lineal tiene pendiente m = 0, ¿cómo es su gráfica?', 'If a linear function has slope m = 0, what does its graph look like?', '["Una línea horizontal","Una línea vertical","Una línea que sube","Una línea que baja"]'::jsonb, '["A horizontal line","A vertical line","A line that goes up","A line that goes down"]'::jsonb, 0, 'Cuando m = 0, no hay cambio en Y por cada unidad de X, lo que resulta en una línea horizontal.', 'When m = 0, there is no change in Y for each unit of X, resulting in a horizontal line.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b62867a1-5715-4106-8631-0942b7c31691', '¿Cuál de las siguientes herramientas utiliza la técnica de repetición espaciada para memorizar contenido?', 'Which of the following tools uses spaced repetition technique to memorize content?', '["Quizlet","Anki","Khan Academy","Duolingo"]'::jsonb, '["Quizlet","Anki","Khan Academy","Duolingo"]'::jsonb, 1, 'Anki es específicamente mencionada como una herramienta de tarjetas de memoria (flashcards) con repetición espaciada, siendo excelente para memorizar.', 'Anki is specifically mentioned as a flashcard tool with spaced repetition, being excellent for memorizing.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b62867a1-5715-4106-8631-0942b7c31691', 'Para evitar distracciones mientras estudias, ¿cuál NO es una recomendación mencionada en el contenido?', 'To avoid distractions while studying, which is NOT a recommendation mentioned in the content?', '["Bloquear notificaciones","Usar el modo ''No molestar''","Estudiar siempre con música","Poner el celular en otra habitación"]'::jsonb, '["Block notifications","Use ''Do not disturb'' mode","Always study with music","Put phone in another room"]'::jsonb, 2, 'El contenido no recomienda estudiar siempre con música. Solo menciona Brain.fm como música específicamente diseñada para concentración, pero no como regla general.', 'The content does not recommend always studying with music. It only mentions Brain.fm as music specifically designed for concentration, but not as a general rule.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b62867a1-5715-4106-8631-0942b7c31691', '¿Qué herramienta combina organización completa incluyendo notas, bases de datos y calendarios?', 'Which tool combines complete organization including notes, databases, and calendars?', '["Google Docs","Notion","OneNote","Trello"]'::jsonb, '["Google Docs","Notion","OneNote","Trello"]'::jsonb, 1, 'Notion es descrita específicamente como una herramienta de organización completa que incluye notas, bases de datos y calendarios.', 'Notion is specifically described as a complete organization tool that includes notes, databases, and calendars.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('95bd1790-0b9d-48d6-a969-8202e123ac10', 'En un grupo hay 15 estudiantes de ciencias y 20 estudiantes de humanidades. ¿Cuál es la razón simplificada de estudiantes de ciencias a estudiantes de humanidades?', 'In a group there are 15 science students and 20 humanities students. What is the simplified ratio of science students to humanities students?', '["15:20","3:4","4:3","20:15"]'::jsonb, '["15:20","3:4","4:3","20:15"]'::jsonb, 1, 'La razón de ciencias a humanidades es 15:20. Para simplificar, dividimos ambos números entre su máximo común divisor que es 5: 15÷5 = 3 y 20÷5 = 4, por lo tanto la razón simplificada es 3:4.', 'The ratio of science to humanities is 15:20. To simplify, we divide both numbers by their greatest common divisor which is 5: 15÷5 = 3 and 20÷5 = 4, therefore the simplified ratio is 3:4.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('95bd1790-0b9d-48d6-a969-8202e123ac10', 'Si 4 litros de gasolina cuestan $80, ¿cuánto costarán 7 litros usando regla de tres?', 'If 4 liters of gasoline cost $80, how much will 7 liters cost using rule of three?', '["$120","$140","$160","$180"]'::jsonb, '["$120","$140","$160","$180"]'::jsonb, 1, 'Usando regla de tres: 4 litros → $80, entonces 7 litros → x. Por lo tanto x = (7 × 80) ÷ 4 = 560 ÷ 4 = $140.', 'Using rule of three: 4 liters → $80, then 7 liters → x. Therefore x = (7 × 80) ÷ 4 = 560 ÷ 4 = $140.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('95bd1790-0b9d-48d6-a969-8202e123ac10', 'Una camisa cuesta $300 y tiene un descuento del 25%. ¿Cuál es el precio final?', 'A shirt costs $300 and has a 25% discount. What is the final price?', '["$225","$250","$275","$325"]'::jsonb, '["$225","$250","$275","$325"]'::jsonb, 0, 'Con 25% de descuento, el cliente paga el 75% del precio original. Usando el atajo: $300 × (1 - 0.25) = $300 × 0.75 = $225.', 'With 25% discount, the customer pays 75% of the original price. Using the shortcut: $300 × (1 - 0.25) = $300 × 0.75 = $225.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('6a12bdb1-8ebf-413a-8ca4-fc9710ff52ec', '¿Cuál es la función principal de la oración temática en un párrafo?', 'What is the main function of the topic sentence in a paragraph?', '["Cerrar y resumir las ideas del párrafo","Presentar la idea principal del párrafo","Ejemplificar con datos específicos","Conectar con el párrafo anterior"]'::jsonb, '["Close and summarize the paragraph''s ideas","Present the main idea of the paragraph","Exemplify with specific data","Connect with the previous paragraph"]'::jsonb, 1, 'La oración temática presenta la idea principal del párrafo y generalmente es la primera oración, estableciendo el tema que se desarrollará.', 'The topic sentence presents the main idea of the paragraph and is generally the first sentence, establishing the theme that will be developed.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('6a12bdb1-8ebf-413a-8ca4-fc9710ff52ec', '¿Cuál de los siguientes conectores se usa para expresar contraste?', 'Which of the following connectors is used to express contrast?', '["Debido a","Sin embargo","Además","Por lo tanto"]'::jsonb, '["Due to","However","Furthermore","Therefore"]'::jsonb, 1, '''Sin embargo'' es un conector de contraste que se usa para presentar ideas opuestas o diferentes a las mencionadas anteriormente.', '''However'' is a contrast connector used to present ideas that are opposite or different from those mentioned previously.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('6a12bdb1-8ebf-413a-8ca4-fc9710ff52ec', 'Según el contenido, ¿cuál es uno de los errores más comunes al escribir párrafos?', 'According to the content, what is one of the most common errors when writing paragraphs?', '["Usar conectores temporales","Incluir oraciones de desarrollo","Cambiar de tema sin aviso","Empezar con sangría"]'::jsonb, '["Using temporal connectors","Including development sentences","Changing topics without warning","Starting with indentation"]'::jsonb, 2, 'Cambiar de tema sin aviso rompe la coherencia del párrafo, ya que cada párrafo debe desarrollar una sola idea central de manera lógica.', 'Changing topics without warning breaks paragraph coherence, since each paragraph should develop a single central idea logically.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e76b2f04-17e9-4d52-abcb-c88644685be6', '¿Quién fue el primer Secretario de Educación Pública de México y en qué año se creó la SEP?', 'Who was the first Secretary of Public Education of Mexico and in what year was the SEP created?', '["Lázaro Cárdenas en 1934","José Vasconcelos en 1921","Diego Rivera en 1920","José Vasconcelos en 1936"]'::jsonb, '["Lázaro Cárdenas in 1934","José Vasconcelos in 1921","Diego Rivera in 1920","José Vasconcelos in 1936"]'::jsonb, 1, 'José Vasconcelos fue el primer Secretario de Educación Pública cuando se creó la SEP en 1921, iniciando importantes reformas educativas como el envío de maestros rurales y la promoción del muralismo.', 'José Vasconcelos was the first Secretary of Public Education when the SEP was created in 1921, initiating important educational reforms such as sending rural teachers and promoting muralism.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e76b2f04-17e9-4d52-abcb-c88644685be6', '¿Cuál fue el impacto del sistema educativo mexicano en el analfabetismo entre 1920 y 1990?', 'What was the impact of the Mexican educational system on illiteracy between 1920 and 1990?', '["Aumentó del 12% al 90%","Se mantuvo igual en 90%","Disminuyó del 90% al 12%","Disminuyó del 50% al 20%"]'::jsonb, '["Increased from 12% to 90%","Remained the same at 90%","Decreased from 90% to 12%","Decreased from 50% to 20%"]'::jsonb, 2, 'Gracias a la expansión del sistema educativo, la construcción de miles de escuelas y programas como el libro de texto gratuito, el analfabetismo en México bajó dramáticamente del 90% al 12%.', 'Thanks to the expansion of the educational system, the construction of thousands of schools and programs like free textbooks, illiteracy in Mexico dropped dramatically from 90% to 12%.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e76b2f04-17e9-4d52-abcb-c88644685be6', '¿Qué reforma educativa reciente implementó un enfoque humanista e inclusivo en el sistema educativo mexicano?', 'Which recent educational reform implemented a humanistic and inclusive approach in the Mexican educational system?', '["La obligatoriedad de secundaria en 1993","La creación del IPN en 1936","La Nueva Escuela Mexicana en 2019","La obligatoriedad del bachillerato en 2012"]'::jsonb, '["Mandatory secondary education in 1993","The creation of IPN in 1936","The New Mexican School in 2019","Mandatory high school in 2012"]'::jsonb, 2, 'La Nueva Escuela Mexicana, implementada en 2019, introdujo un enfoque humanista e inclusivo en el sistema educativo mexicano, representando una de las reformas más recientes.', 'The New Mexican School, implemented in 2019, introduced a humanistic and inclusive approach to the Mexican educational system, representing one of the most recent reforms.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('db305e88-3d80-47ee-8412-56a714b2c425', '¿Cuál es la forma correcta de pedir el menú en un restaurante?', 'What is the correct way to ask for the menu at a restaurant?', '["Can I have the menu, please?","I would like the menu","Give me the menu now","Where is the menu?"]'::jsonb, '["Can I have the menu, please?","I would like the menu","Give me the menu now","Where is the menu?"]'::jsonb, 0, 'La forma más cortés y apropiada de pedir el menú es ''Can I have the menu, please?'' ya que usa ''please'' y una estructura de pregunta educada.', 'The most polite and appropriate way to ask for the menu is ''Can I have the menu, please?'' as it uses ''please'' and a polite question structure.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('db305e88-3d80-47ee-8412-56a714b2c425', '¿Cuál de estas prendas de vestir NO es para la parte superior del cuerpo?', 'Which of these clothing items is NOT for the upper body?', '["T-shirt","Jacket","Skirt","Coat"]'::jsonb, '["T-shirt","Jacket","Skirt","Coat"]'::jsonb, 2, 'La falda (skirt) es una prenda que se usa en la parte inferior del cuerpo, mientras que t-shirt, jacket y coat son para la parte superior.', 'A skirt is a garment worn on the lower body, while t-shirt, jacket, and coat are for the upper body.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('db305e88-3d80-47ee-8412-56a714b2c425', '¿Cómo se dice en inglés ''Hace frío''?', 'How do you say ''Hace frío'' in English?', '["It''s hot","It''s cold","It''s windy","It''s cloudy"]'::jsonb, '["It''s hot","It''s cold","It''s windy","It''s cloudy"]'::jsonb, 1, '''It''s cold'' es la traducción correcta de ''Hace frío''. Se usa la estructura ''It''s + adjetivo'' para describir el clima.', '''It''s cold'' is the correct translation of ''Hace frío''. We use the structure ''It''s + adjective'' to describe the weather.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fc0bd98c-9d00-48eb-8f2d-2edcba27e544', '¿Cuál es la extensión adecuada de un resumen respecto al texto original?', 'What is the appropriate length of a summary compared to the original text?', '["Entre 1/2 y 3/4 del texto original","Entre 1/4 y 1/3 del texto original","Exactamente la mitad del texto original","No más de una cuartilla sin importar el texto original"]'::jsonb, '["Between 1/2 and 3/4 of the original text","Between 1/4 and 1/3 of the original text","Exactly half of the original text","No more than one page regardless of the original text"]'::jsonb, 1, 'Según el contenido, la regla para un resumen es que debe ser entre 1/4 y 1/3 del texto original para conservar solo las ideas principales.', 'According to the content, the rule for a summary is that it should be between 1/4 and 1/3 of the original text to preserve only the main ideas.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fc0bd98c-9d00-48eb-8f2d-2edcba27e544', '¿Cuál es la forma correcta de escribir el lugar y fecha en una carta formal?', 'What is the correct way to write the place and date in a formal letter?', '["Guadalajara, 15/03/2025","Guadalajara, Jalisco, a 15 de marzo de 2025","15 de marzo del 2025, Guadalajara","Gdl, Jal., 15-marzo-2025"]'::jsonb, '["Guadalajara, 15/03/2025","Guadalajara, Jalisco, a 15 de marzo de 2025","March 15, 2025, Guadalajara","Gdl, Jal., 15-March-2025"]'::jsonb, 1, 'En una carta formal, el lugar y fecha se escribe completo y formal: ''Guadalajara, Jalisco, a 15 de marzo de 2025'', evitando abreviaturas.', 'In a formal letter, the place and date is written complete and formal: ''Guadalajara, Jalisco, a 15 de marzo de 2025'', avoiding abbreviations.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fc0bd98c-9d00-48eb-8f2d-2edcba27e544', '¿Cuál de las siguientes características NO debe incluir un resumen?', 'Which of the following characteristics should NOT be included in a summary?', '["Ideas principales del texto original","Redacción con palabras propias","Opiniones personales del autor del resumen","Versión condensada del contenido"]'::jsonb, '["Main ideas from the original text","Writing with one''s own words","Personal opinions of the summary''s author","Condensed version of the content"]'::jsonb, 2, 'El contenido especifica claramente que un resumen NO incluye opiniones personales, solo debe conservar las ideas principales del texto original.', 'The content clearly specifies that a summary does NOT include personal opinions, it should only preserve the main ideas from the original text.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a237ae56-efc7-4a17-9d28-947660374c7c', '¿Cuál de los siguientes ejemplos corresponde a IA Estrecha que usas en tu vida diaria?', 'Which of the following examples corresponds to Narrow AI that you use in your daily life?', '["Una IA que puede hacer cualquier tarea como un humano","ChatGPT que genera texto y responde preguntas","Una IA hipotética que supera la inteligencia humana","Una máquina que no necesita datos para aprender"]'::jsonb, '["An AI that can do any task like a human","ChatGPT that generates text and answers questions","A hypothetical AI that exceeds human intelligence","A machine that doesn''t need data to learn"]'::jsonb, 1, 'ChatGPT es un ejemplo de IA Estrecha porque está especializada en una tarea específica: generar texto y responder preguntas, no puede realizar cualquier tarea intelectual.', 'ChatGPT is an example of Narrow AI because it specializes in a specific task: generating text and answering questions, it cannot perform any intellectual task.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a237ae56-efc7-4a17-9d28-947660374c7c', '¿Cómo funciona el Machine Learning para enseñar a una IA a reconocer gatos en fotos?', 'How does Machine Learning work to teach an AI to recognize cats in photos?', '["Se programan reglas específicas sobre cómo debe verse un gato","Se le muestran millones de fotos etiquetadas y la máquina encuentra patrones","La IA aprende automáticamente sin necesidad de ejemplos","Se le explica verbalmente qué características tiene un gato"]'::jsonb, '["Specific rules are programmed about how a cat should look","It''s shown millions of labeled photos and the machine finds patterns","AI learns automatically without needing examples","It''s verbally explained what characteristics a cat has"]'::jsonb, 1, 'En Machine Learning, en vez de programar reglas específicas, se le proporcionan muchos ejemplos (fotos etiquetadas como ''gato'' y ''no gato'') y la máquina encuentra los patrones por sí sola.', 'In Machine Learning, instead of programming specific rules, many examples are provided (photos labeled as ''cat'' and ''not cat'') and the machine finds the patterns on its own.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('a237ae56-efc7-4a17-9d28-947660374c7c', 'Según el contenido, ¿cuál es la mejor estrategia para prepararse para el futuro del trabajo con IA?', 'According to the content, what is the best strategy to prepare for the future of work with AI?', '["Evitar cualquier contacto con la inteligencia artificial","Aprender a trabajar CON la IA, no competir contra ella","Solo enfocarse en trabajos repetitivos y predecibles","Ignorar el desarrollo de habilidades técnicas"]'::jsonb, '["Avoid any contact with artificial intelligence","Learn to work WITH AI, not compete against it","Only focus on repetitive and predictable jobs","Ignore the development of technical skills"]'::jsonb, 1, 'El contenido enfatiza que lo más importante es aprender a trabajar CON la IA como herramienta, desarrollando habilidades complementarias como creatividad, empatía y pensamiento crítico.', 'The content emphasizes that the most important thing is to learn to work WITH AI as a tool, developing complementary skills like creativity, empathy, and critical thinking.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('56c4de7f-ef9b-4bcc-befa-640facd8e2e9', '¿Quién fue el conquistador español que dominó el territorio jalisciense entre 1530 y 1531?', 'Who was the Spanish conquistador that dominated the Jalisco territory between 1530 and 1531?', '["Hernán Cortés","Nuño de Guzmán","Pedro de Alvarado","Francisco Vázquez de Coronado"]'::jsonb, '["Hernán Cortés","Nuño de Guzmán","Pedro de Alvarado","Francisco Vázquez de Coronado"]'::jsonb, 1, 'Según el contenido, Nuño de Guzmán fue quien conquistó el territorio jalisciense entre 1530-1531, antes de que Guadalajara fuera fundada en 1542.', 'According to the content, Nuño de Guzmán was the one who conquered the Jalisco territory between 1530-1531, before Guadalajara was founded in 1542.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('56c4de7f-ef9b-4bcc-befa-640facd8e2e9', '¿Cuál de estos elementos culturales jaliscienses fue declarado Patrimonio Cultural Inmaterial de la Humanidad por la UNESCO en 2011?', 'Which of these Jalisco cultural elements was declared Intangible Cultural Heritage of Humanity by UNESCO in 2011?', '["El tequila","El mariachi","La charrería","La birria"]'::jsonb, '["Tequila","Mariachi","Charrería","Birria"]'::jsonb, 1, 'El mariachi fue reconocido como Patrimonio Cultural Inmaterial de la Humanidad por la UNESCO en 2011, siendo uno de los símbolos más importantes de la cultura jalisciense.', 'Mariachi was recognized as Intangible Cultural Heritage of Humanity by UNESCO in 2011, being one of the most important symbols of Jalisco culture.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('56c4de7f-ef9b-4bcc-befa-640facd8e2e9', 'Entre 1926 y 1929, Jalisco fue el epicentro de un conflicto armado conocido como:', 'Between 1926 and 1929, Jalisco was the epicenter of an armed conflict known as:', '["La Revolución Mexicana","La Guerra de Independencia","La Guerra Cristera","La Guerra de Reforma"]'::jsonb, '["The Mexican Revolution","The War of Independence","The Cristero War","The Reform War"]'::jsonb, 2, 'La Guerra Cristera (1926-1929) tuvo su epicentro en Jalisco, siendo un conflicto armado importante en la historia del estado durante el siglo XX.', 'The Cristero War (1926-1929) had its epicenter in Jalisco, being an important armed conflict in the state''s history during the 20th century.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('59283110-6982-43bc-8cb0-cc71c852a27d', '¿Qué es la tolerancia en el contexto de las adicciones?', 'What is tolerance in the context of addictions?', '["Es la capacidad de dejar las drogas fácilmente","Es cuando el cerebro necesita más cantidad de la sustancia para sentir el mismo efecto","Es cuando una persona puede controlar su consumo","Es la habilidad de mezclar diferentes sustancias"]'::jsonb, '["It''s the ability to quit drugs easily","It''s when the brain needs more of the substance to feel the same effect","It''s when a person can control their consumption","It''s the ability to mix different substances"]'::jsonb, 1, 'La tolerancia ocurre porque el cerebro se acostumbra a la sustancia y libera menos dopamina, por lo que necesita mayor cantidad para experimentar el mismo placer que antes.', 'Tolerance occurs because the brain gets used to the substance and releases less dopamine, so it needs a greater amount to experience the same pleasure as before.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('59283110-6982-43bc-8cb0-cc71c852a27d', '¿Por qué el alcohol es especialmente peligroso para los adolescentes?', 'Why is alcohol especially dangerous for adolescents?', '["Porque es más caro para ellos","Porque el cerebro adolescente no termina de desarrollarse hasta los ~25 años","Porque no tienen experiencia bebiendo","Porque solo afecta a los menores de edad"]'::jsonb, '["Because it''s more expensive for them","Because the adolescent brain doesn''t finish developing until around age 25","Because they have no drinking experience","Because it only affects minors"]'::jsonb, 1, 'El cerebro adolescente está en desarrollo hasta aproximadamente los 25 años, lo que lo hace especialmente vulnerable al daño que puede causar el alcohol en su estructura y funcionamiento.', 'The adolescent brain is developing until approximately age 25, making it especially vulnerable to the damage alcohol can cause to its structure and function.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('59283110-6982-43bc-8cb0-cc71c852a27d', '¿Cuál de los siguientes es un factor de protección contra las adicciones?', 'Which of the following is a protective factor against addictions?', '["Evitar toda información sobre drogas","Tener un proyecto de vida claro","Aislarse de todas las personas","Consumir solo los fines de semana"]'::jsonb, '["Avoiding all information about drugs","Having a clear life project","Isolating oneself from all people","Consuming only on weekends"]'::jsonb, 1, 'Tener un proyecto de vida claro es un factor de protección porque da sentido y dirección a la vida, motivando a la persona a cuidar su salud y evitar comportamientos que pongan en riesgo sus metas futuras.', 'Having a clear life project is a protective factor because it gives meaning and direction to life, motivating the person to take care of their health and avoid behaviors that put their future goals at risk.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('15b75f4c-aad4-4f2f-8f8e-adeb5221121e', '¿Cuál es el perímetro de un cuadrado que tiene un lado de 7 cm?', 'What is the perimeter of a square that has a side of 7 cm?', '["14 cm","21 cm","28 cm","49 cm"]'::jsonb, '["14 cm","21 cm","28 cm","49 cm"]'::jsonb, 2, 'El perímetro de un cuadrado se calcula con la fórmula P = 4L. Si el lado es 7 cm, entonces P = 4 × 7 = 28 cm.', 'The perimeter of a square is calculated with the formula P = 4L. If the side is 7 cm, then P = 4 × 7 = 28 cm.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('15b75f4c-aad4-4f2f-8f8e-adeb5221121e', 'Si un rectángulo tiene una base de 10 m y una altura de 6 m, ¿cuál es su área?', 'If a rectangle has a base of 10 m and a height of 6 m, what is its area?', '["16 m²","32 m²","60 m²","100 m²"]'::jsonb, '["16 m²","32 m²","60 m²","100 m²"]'::jsonb, 2, 'El área de un rectángulo se calcula con la fórmula A = base × altura. Si la base es 10 m y la altura es 6 m, entonces A = 10 × 6 = 60 m².', 'The area of a rectangle is calculated with the formula A = base × height. If the base is 10 m and the height is 6 m, then A = 10 × 6 = 60 m².', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('15b75f4c-aad4-4f2f-8f8e-adeb5221121e', '¿Cuál es la principal diferencia entre perímetro y área?', 'What is the main difference between perimeter and area?', '["El perímetro mide la superficie y el área mide la distancia alrededor","El perímetro mide la distancia alrededor y el área mide la superficie","Ambos miden lo mismo pero en diferentes unidades","El perímetro solo se usa en cuadrados y el área en círculos"]'::jsonb, '["Perimeter measures surface and area measures distance around","Perimeter measures distance around and area measures surface","Both measure the same thing but in different units","Perimeter is only used for squares and area for circles"]'::jsonb, 1, 'El perímetro es la distancia alrededor de una figura (suma de todos los lados), mientras que el área es la superficie que cubre una figura y se mide en unidades cuadradas.', 'Perimeter is the distance around a figure (sum of all sides), while area is the surface that a figure covers and is measured in square units.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fefef9a4-09fd-4c70-96c9-e41082563770', '¿Cuál de las siguientes metas cumple MEJOR con los criterios SMART?', 'Which of the following goals BEST meets the SMART criteria?', '["Quiero estudiar más","Voy a pasar todas las materias","Completaré mi bachillerato virtual aprobando todas las materias con promedio mínimo de 8.0 para junio 2025","Quiero terminar la prepa pronto"]'::jsonb, '["I want to study more","I''m going to pass all subjects","I will complete my virtual high school by passing all subjects with a minimum average of 8.0 by June 2025","I want to finish high school soon"]'::jsonb, 2, 'Esta meta es específica (bachillerato virtual), medible (promedio 8.0), alcanzable, relevante y tiene un plazo definido (junio 2025), cumpliendo todos los criterios SMART.', 'This goal is specific (virtual high school), measurable (8.0 average), achievable, relevant, and has a defined deadline (June 2025), meeting all SMART criteria.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fefef9a4-09fd-4c70-96c9-e41082563770', 'Según el contenido, ¿cuáles son los elementos que DEBE incluir tu proyecto académico personal?', 'According to the content, what elements MUST your personal academic project include?', '["Solo la meta principal y horario de estudio","Motivación, meta principal, metas mensuales, horario, sistema de apoyo, obstáculos y recompensas","Únicamente las metas SMART y el promedio deseado","Solo la motivación y las materias a cursar"]'::jsonb, '["Only the main goal and study schedule","Motivation, main goal, monthly goals, schedule, support system, obstacles and rewards","Only SMART goals and desired average","Only motivation and subjects to take"]'::jsonb, 1, 'El proyecto académico debe ser integral e incluir todos estos 7 elementos para tener un plan completo que multiplique las posibilidades de éxito.', 'The academic project should be comprehensive and include all these 7 elements to have a complete plan that multiplies the chances of success.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fefef9a4-09fd-4c70-96c9-e41082563770', 'Según los datos presentados, ¿cuál es la ventaja económica de completar el bachillerato en México?', 'According to the data presented, what is the economic advantage of completing high school in Mexico?', '["Una persona gana 20% más que alguien sin bachillerato","Una persona gana en promedio 35% más que alguien sin bachillerato","Una persona gana el doble que alguien sin estudios","Una persona gana 80% más que alguien sin bachillerato"]'::jsonb, '["A person earns 20% more than someone without high school","A person earns on average 35% more than someone without high school","A person earns double than someone without studies","A person earns 80% more than someone without high school"]'::jsonb, 1, 'El texto específicamente menciona que en México, una persona con bachillerato completo gana en promedio 35% más que alguien sin él.', 'The text specifically mentions that in Mexico, a person with complete high school earns on average 35% more than someone without it.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fb05e6ac-a745-4a12-9854-b340f6d007cf', '¿Cuál de estas contraseñas cumple con los criterios de seguridad recomendados?', 'Which of these passwords meets the recommended security criteria?', '["password123","MiNombre2005","Hol@Mund0_2024!","123456789"]'::jsonb, '["password123","MyName2005","Hell@W0rld_2024!","123456789"]'::jsonb, 2, 'La contraseña ''Hol@Mund0_2024!'' cumple con todos los criterios: tiene más de 12 caracteres, combina mayúsculas, minúsculas, números y símbolos, y no usa información personal obvia.', 'The password ''Hell@W0rld_2024!'' meets all criteria: it has more than 12 characters, combines uppercase, lowercase, numbers and symbols, and doesn''t use obvious personal information.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fb05e6ac-a745-4a12-9854-b340f6d007cf', 'Si recibes un correo que dice ser de tu banco pidiendo tu contraseña para ''verificar tu cuenta'', ¿qué debes hacer?', 'If you receive an email claiming to be from your bank asking for your password to ''verify your account'', what should you do?', '["Responder inmediatamente con tus datos","Hacer clic en el enlace para verificar","Ignorar el correo porque los bancos nunca piden contraseñas por correo","Reenviar el correo a tus amigos"]'::jsonb, '["Reply immediately with your data","Click the link to verify","Ignore the email because banks never ask for passwords via email","Forward the email to your friends"]'::jsonb, 2, 'Los bancos NUNCA piden contraseñas por correo electrónico. Este es un ejemplo clásico de phishing y debes ignorar completamente este tipo de mensajes.', 'Banks NEVER ask for passwords via email. This is a classic example of phishing and you should completely ignore this type of messages.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fb05e6ac-a745-4a12-9854-b340f6d007cf', '¿Cuál de estas acciones NO es recomendable al sufrir ciberbullying?', 'Which of these actions is NOT recommended when suffering cyberbullying?', '["Guardar capturas de pantalla como evidencia","Responder agresivamente al agresor","Bloquear al agresor","Hablar con un adulto de confianza"]'::jsonb, '["Save screenshots as evidence","Respond aggressively to the aggressor","Block the aggressor","Talk to a trusted adult"]'::jsonb, 1, 'Responder agresivamente al agresor NO es recomendable porque puede escalar el conflicto y empeorar la situación. Es mejor no responder al agresor y seguir los otros pasos de protección.', 'Responding aggressively to the aggressor is NOT recommended because it can escalate the conflict and worsen the situation. It''s better not to respond to the aggressor and follow the other protection steps.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('23a2f674-a669-4c3c-adda-5927bb032ad0', '¿Cuál es la forma correcta de preguntar por la profesión de alguien?', 'What is the correct way to ask about someone''s profession?', '["How do you work?","What do you do?","Where do you job?","How is your work?"]'::jsonb, '["How do you work?","What do you do?","Where do you job?","How is your work?"]'::jsonb, 1, 'La forma correcta de preguntar por la profesión es ''What do you do?'' que significa ''¿A qué te dedicas?''', 'The correct way to ask about someone''s profession is ''What do you do?'' which means ''¿A qué te dedicas?''', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('23a2f674-a669-4c3c-adda-5927bb032ad0', '¿Cómo se dice ''2:30'' en inglés usando la forma alternativa?', 'How do you say ''2:30'' in English using the alternative form?', '["It''s half to two","It''s half past two","It''s quarter past two","It''s two quarter"]'::jsonb, '["It''s half to two","It''s half past two","It''s quarter past two","It''s two quarter"]'::jsonb, 1, 'Para decir 2:30 se puede usar ''It''s two thirty'' o ''It''s half past two'' (media hora después de las dos).', 'To say 2:30 you can use ''It''s two thirty'' or ''It''s half past two'' (half an hour after two).', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('23a2f674-a669-4c3c-adda-5927bb032ad0', '¿Qué preposición se usa correctamente con la hora específica?', 'Which preposition is used correctly with a specific time?', '["in 3 o''clock","on 3 o''clock","at 3 o''clock","of 3 o''clock"]'::jsonb, '["in 3 o''clock","on 3 o''clock","at 3 o''clock","of 3 o''clock"]'::jsonb, 2, 'Con horas específicas siempre se usa la preposición ''at'': at 3 o''clock, at noon, at midnight.', 'With specific times we always use the preposition ''at'': at 3 o''clock, at noon, at midnight.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9a7c6693-d8b0-4356-bd65-7a8f40dcd542', '¿Cuál es la principal diferencia entre paráfrasis y síntesis?', 'What is the main difference between paraphrase and synthesis?', '["La paráfrasis usa ideas de varios textos, la síntesis de uno solo","La paráfrasis expresa ideas de un autor con tus palabras, la síntesis combina ideas de varias fuentes","La paráfrasis requiere citar fuentes, la síntesis no","La paráfrasis cambia el significado, la síntesis lo mantiene"]'::jsonb, '["Paraphrase uses ideas from multiple texts, synthesis from one only","Paraphrase expresses one author''s ideas in your words, synthesis combines ideas from multiple sources","Paraphrase requires citing sources, synthesis doesn''t","Paraphrase changes meaning, synthesis maintains it"]'::jsonb, 1, 'La paráfrasis consiste en expresar las ideas de otro autor con tus propias palabras manteniendo el significado original, mientras que la síntesis combina e integra ideas de varios textos o fuentes en un nuevo texto coherente.', 'Paraphrase consists of expressing another author''s ideas in your own words while maintaining the original meaning, while synthesis combines and integrates ideas from multiple texts or sources into a new coherent text.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9a7c6693-d8b0-4356-bd65-7a8f40dcd542', 'Al hacer una paráfrasis, ¿cuál de estas acciones NO es correcta?', 'When paraphrasing, which of these actions is NOT correct?', '["Cambiar la estructura de la oración","Usar sinónimos apropiados","Copiar el texto original cambiando solo 2-3 palabras","Citar siempre la fuente original"]'::jsonb, '["Change the sentence structure","Use appropriate synonyms","Copy the original text changing only 2-3 words","Always cite the original source"]'::jsonb, 2, 'Una paráfrasis correcta requiere una reformulación completa del texto original, no simplemente cambiar unas pocas palabras. Debe cambiar la estructura, usar sinónimos y mantener el significado, pero nunca ser una copia con cambios mínimos.', 'A correct paraphrase requires a complete reformulation of the original text, not simply changing a few words. It should change the structure, use synonyms and maintain meaning, but never be a copy with minimal changes.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('9a7c6693-d8b0-4356-bd65-7a8f40dcd542', '¿Cuál es el primer paso correcto para realizar una síntesis?', 'What is the correct first step to perform a synthesis?', '["Organizar las ideas en un esquema","Redactar un nuevo texto integrando todo","Leer todas las fuentes disponibles","Encontrar puntos en común y diferencias"]'::jsonb, '["Organize ideas in an outline","Write a new text integrating everything","Read all available sources","Find common points and differences"]'::jsonb, 2, 'Según los pasos establecidos para la síntesis, el primer paso es leer todas las fuentes disponibles. Solo después de esta lectura completa se pueden identificar ideas principales, encontrar similitudes y diferencias, y organizar la información.', 'According to the established steps for synthesis, the first step is to read all available sources. Only after this complete reading can you identify main ideas, find similarities and differences, and organize the information.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b3f2e5db-a01d-41d4-9425-95cd8cf0d590', '¿Cuál es la principal diferencia entre igualdad y equidad de género?', 'What is the main difference between gender equality and equity?', '["La igualdad da lo mismo a todos, la equidad da a cada quien lo que necesita","La igualdad es para mujeres, la equidad es para hombres","No hay diferencia, son sinónimos","La equidad es más antigua que la igualdad"]'::jsonb, '["Equality gives the same to everyone, equity gives each person what they need","Equality is for women, equity is for men","There''s no difference, they are synonyms","Equity is older than equality"]'::jsonb, 0, 'La igualdad consiste en dar lo mismo a todos, mientras que la equidad busca dar a cada persona lo que necesita para tener las mismas oportunidades, como el ejemplo de los zapatos de diferentes tallas.', 'Equality consists of giving the same to everyone, while equity seeks to give each person what they need to have the same opportunities, like the example of shoes in different sizes.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b3f2e5db-a01d-41d4-9425-95cd8cf0d590', '¿Por qué el estereotipo ''los hombres no lloran'' es considerado dañino?', 'Why is the stereotype ''men don''t cry'' considered harmful?', '["Porque hace que los hombres sean más fuertes","Porque reprime emociones y daña la salud mental","Porque es una tradición muy antigua","Porque las mujeres lloran más que los hombres"]'::jsonb, '["Because it makes men stronger","Because it represses emotions and damages mental health","Because it''s a very old tradition","Because women cry more than men"]'::jsonb, 1, 'Este estereotipo es dañino porque reprime las emociones naturales de los hombres, lo cual puede afectar negativamente su salud mental al no permitirles expresar sus sentimientos de manera saludable.', 'This stereotype is harmful because it represses men''s natural emotions, which can negatively affect their mental health by not allowing them to express their feelings in a healthy way.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b3f2e5db-a01d-41d4-9425-95cd8cf0d590', 'Según los datos presentados sobre México, ¿qué porcentaje del trabajo doméstico no remunerado realizan las mujeres?', 'According to the data presented about Mexico, what percentage of unpaid domestic work do women perform?', '["44%","51%","66%","77%"]'::jsonb, '["44%","51%","66%","77%"]'::jsonb, 2, 'Según los datos del contenido, las mujeres realizan el 66% del trabajo doméstico no remunerado en México, lo que evidencia una distribución desigual de estas responsabilidades.', 'According to the content data, women perform 66% of unpaid domestic work in Mexico, which shows an unequal distribution of these responsibilities.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('8db169fa-3762-41a2-adc8-e1b36e3e1300', '¿A qué hora se despierta Carlos todos los días?', 'What time does Carlos wake up every day?', '["A las 6 AM","A las 7 AM","A las 8 AM","A las 10 PM"]'::jsonb, '["At 6 AM","At 7 AM","At 8 AM","At 10 PM"]'::jsonb, 1, 'En el texto dice claramente ''I wake up at 7 AM every day''', 'The text clearly states ''I wake up at 7 AM every day''', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('8db169fa-3762-41a2-adc8-e1b36e3e1300', '¿Qué hicieron María y sus amigos en la playa?', 'What did Maria and her friends do at the beach?', '["Solo nadaron","Nadaron y jugaron voleibol","Solo compraron cocos","Vieron una película"]'::jsonb, '["Only swam","Swam and played volleyball","Only bought coconuts","Watched a movie"]'::jsonb, 1, 'El texto menciona ''They swam in the ocean and played volleyball''', 'The text mentions ''They swam in the ocean and played volleyball''', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('8db169fa-3762-41a2-adc8-e1b36e3e1300', '¿Cuál es la estrategia más importante para leer textos en inglés según el contenido?', 'What is the most important strategy for reading texts in English according to the content?', '["Traducir palabra por palabra","Buscar el sentido general","Memorizar todo el vocabulario","Leer muy lentamente"]'::jsonb, '["Translate word by word","Look for the general meaning","Memorize all vocabulary","Read very slowly"]'::jsonb, 1, 'Las estrategias enfatizan ''busca el SENTIDO general'' y ''No traduzcas palabra por palabra''', 'The strategies emphasize ''look for the general MEANING'' and ''Don''t translate word by word''', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('675bce7e-46b6-4317-9199-da4d076c637a', '¿En qué cuadrante del plano cartesiano se encuentra el punto P(-3, 5)?', 'In which quadrant of the Cartesian plane is point P(-3, 5) located?', '["Cuadrante I","Cuadrante II","Cuadrante III","Cuadrante IV"]'::jsonb, '["Quadrant I","Quadrant II","Quadrant III","Quadrant IV"]'::jsonb, 1, 'El punto P(-3, 5) tiene coordenada x negativa y coordenada y positiva, lo que corresponde al cuadrante II (arriba-izquierda).', 'Point P(-3, 5) has a negative x-coordinate and positive y-coordinate, which corresponds to quadrant II (upper-left).', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('675bce7e-46b6-4317-9199-da4d076c637a', '¿Cuál es la distancia entre los puntos A(0, 0) y B(3, 4)?', 'What is the distance between points A(0, 0) and B(3, 4)?', '["3","4","5","7"]'::jsonb, '["3","4","5","7"]'::jsonb, 2, 'Usando la fórmula d = √[(x₂-x₁)² + (y₂-y₁)²]: d = √[(3-0)² + (4-0)²] = √[9 + 16] = √25 = 5.', 'Using the formula d = √[(x₂-x₁)² + (y₂-y₁)²]: d = √[(3-0)² + (4-0)²] = √[9 + 16] = √25 = 5.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('675bce7e-46b6-4317-9199-da4d076c637a', 'Si una recta tiene pendiente m = 3, ¿cuál debe ser la pendiente de una recta perpendicular a ella?', 'If a line has slope m = 3, what should be the slope of a line perpendicular to it?', '["3","-3","1/3","-1/3"]'::jsonb, '["3","-3","1/3","-1/3"]'::jsonb, 3, 'Las rectas perpendiculares tienen pendientes que son recíprocas negativas. Si m₁ = 3, entonces m₂ = -1/3, ya que 3 × (-1/3) = -1.', 'Perpendicular lines have slopes that are negative reciprocals. If m₁ = 3, then m₂ = -1/3, since 3 × (-1/3) = -1.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('5252f2e9-555b-4620-909b-49f9dcf254f0', '¿Cuál de los siguientes pilares del pensamiento computacional consiste en dividir un problema grande en partes más pequeñas y manejables?', 'Which of the following pillars of computational thinking consists of breaking a large problem into smaller, manageable parts?', '["Patrones","Descomposición","Abstracción","Algoritmos"]'::jsonb, '["Patterns","Decomposition","Abstraction","Algorithms"]'::jsonb, 1, 'La descomposición es el pilar que consiste en dividir un problema complejo en partes más pequeñas y manejables para poder resolverlo de manera más eficiente.', 'Decomposition is the pillar that consists of breaking down a complex problem into smaller, manageable parts to solve it more efficiently.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('5252f2e9-555b-4620-909b-49f9dcf254f0', '¿Cuál es la principal diferencia entre un ciclo while y un ciclo for?', 'What is the main difference between a while loop and a for loop?', '["El ciclo while es más rápido que el for","El ciclo for se usa cuando sabemos el número de iteraciones, el while cuando la condición es incierta","El ciclo for solo funciona con números enteros","No hay diferencia, son equivalentes"]'::jsonb, '["The while loop is faster than the for loop","The for loop is used when we know the number of iterations, while when the condition is uncertain","The for loop only works with integers","There is no difference, they are equivalent"]'::jsonb, 1, 'El ciclo for se utiliza cuando conocemos de antemano cuántas veces queremos que se repita el ciclo, mientras que el ciclo while se usa cuando la repetición depende de una condición que puede cambiar durante la ejecución.', 'The for loop is used when we know in advance how many times we want the loop to repeat, while the while loop is used when the repetition depends on a condition that may change during execution.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('5252f2e9-555b-4620-909b-49f9dcf254f0', '¿Cuál de las siguientes características NO es propia de un buen algoritmo?', 'Which of the following characteristics is NOT typical of a good algorithm?', '["Debe ser preciso y no ambiguo","Debe ser infinito para cubrir todos los casos","Debe tener un inicio y un fin claros","Debe producir un resultado"]'::jsonb, '["It must be precise and unambiguous","It must be infinite to cover all cases","It must have a clear beginning and end","It must produce a result"]'::jsonb, 1, 'Un buen algoritmo debe ser finito, es decir, debe terminar en un número finito de pasos. Un algoritmo infinito no sería útil ya que nunca produciría un resultado.', 'A good algorithm must be finite, meaning it must terminate in a finite number of steps. An infinite algorithm would not be useful as it would never produce a result.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e1dcb0a6-efc8-4120-b81e-c7957073e819', '¿Cuál es el resultado de aplicar el producto notable (x + 3)(x - 3)?', 'What is the result of applying the notable product (x + 3)(x - 3)?', '["x² + 9","x² - 9","x² + 6x + 9","x² - 6x + 9"]'::jsonb, '["x² + 9","x² - 9","x² + 6x + 9","x² - 6x + 9"]'::jsonb, 1, 'Es una diferencia de cuadrados: (a + b)(a - b) = a² - b². Por lo tanto, (x + 3)(x - 3) = x² - 3² = x² - 9.', 'It''s a difference of squares: (a + b)(a - b) = a² - b². Therefore, (x + 3)(x - 3) = x² - 3² = x² - 9.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e1dcb0a6-efc8-4120-b81e-c7957073e819', 'Si se resuelve el sistema de ecuaciones por sustitución: 2x + y = 7 y x - y = 2, ¿cuál es el valor de x?', 'If the system of equations is solved by substitution: 2x + y = 7 and x - y = 2, what is the value of x?', '["x = 1","x = 2","x = 3","x = 4"]'::jsonb, '["x = 1","x = 2","x = 3","x = 4"]'::jsonb, 2, 'De la segunda ecuación: y = x - 2. Sustituyendo en la primera: 2x + (x - 2) = 7, entonces 3x - 2 = 7, por lo que 3x = 9 y x = 3.', 'From the second equation: y = x - 2. Substituting into the first: 2x + (x - 2) = 7, so 3x - 2 = 7, therefore 3x = 9 and x = 3.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('e1dcb0a6-efc8-4120-b81e-c7957073e819', '¿Cuál es la distancia entre los puntos A(1, 2) y B(4, 6)?', 'What is the distance between points A(1, 2) and B(4, 6)?', '["3","4","5","7"]'::jsonb, '["3","4","5","7"]'::jsonb, 2, 'Usando la fórmula de distancia: d = √[(x₂-x₁)² + (y₂-y₁)²] = √[(4-1)² + (6-2)²] = √[9 + 16] = √25 = 5.', 'Using the distance formula: d = √[(x₂-x₁)² + (y₂-y₁)²] = √[(4-1)² + (6-2)²] = √[9 + 16] = √25 = 5.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fd818ce0-acbe-4be9-8dab-e6965e6c7c51', '¿Cuál es la diferencia principal entre sexo biológico y género?', 'What is the main difference between biological sex and gender?', '["El sexo biológico se refiere a características físicas, mientras que el género es una construcción social","Ambos términos significan exactamente lo mismo","El género determina las características físicas de una persona","El sexo biológico cambia con la edad, pero el género no"]'::jsonb, '["Biological sex refers to physical characteristics, while gender is a social construction","Both terms mean exactly the same thing","Gender determines a person''s physical characteristics","Biological sex changes with age, but gender doesn''t"]'::jsonb, 0, 'El sexo biológico se basa en características físicas como cromosomas, hormonas y anatomía, mientras que el género es una construcción social que incluye roles, comportamientos y expectativas culturales.', 'Biological sex is based on physical characteristics like chromosomes, hormones and anatomy, while gender is a social construction that includes cultural roles, behaviors and expectations.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fd818ce0-acbe-4be9-8dab-e6965e6c7c51', '¿Cuál de las siguientes es una característica esencial del consentimiento en las relaciones?', 'Which of the following is an essential characteristic of consent in relationships?', '["Debe ser dado una sola vez al inicio de la relación","Puede ser retirado en cualquier momento","No es necesario si las personas se conocen bien","Solo se requiere en relaciones formales"]'::jsonb, '["It should be given only once at the beginning of the relationship","It can be withdrawn at any time","It''s not necessary if people know each other well","It''s only required in formal relationships"]'::jsonb, 1, 'El consentimiento debe ser libre, informado, específico y puede ser retirado en cualquier momento, independientemente del tipo de relación o situación previa.', 'Consent must be free, informed, specific and can be withdrawn at any time, regardless of the type of relationship or previous situation.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('fd818ce0-acbe-4be9-8dab-e6965e6c7c51', '¿Cuál es la función principal de los métodos anticonceptivos de barrera como el condón?', 'What is the main function of barrier contraceptive methods like condoms?', '["Solo prevenir embarazos no deseados","Solo prevenir infecciones de transmisión sexual","Prevenir tanto embarazos como infecciones de transmisión sexual","Regular el ciclo menstrual"]'::jsonb, '["Only prevent unwanted pregnancies","Only prevent sexually transmitted infections","Prevent both pregnancies and sexually transmitted infections","Regulate the menstrual cycle"]'::jsonb, 2, 'Los métodos anticonceptivos de barrera como el condón tienen una doble función: prevenir embarazos no deseados y reducir significativamente el riesgo de contraer infecciones de transmisión sexual.', 'Barrier contraceptive methods like condoms have a dual function: preventing unwanted pregnancies and significantly reducing the risk of contracting sexually transmitted infections.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('2ba2eed4-3f40-4495-865e-f548bc24ab33', 'En la oración ''María, tráeme el libro que está en la mesa'', ¿cuál es la función del lenguaje que predomina?', 'In the sentence ''María, bring me the book that is on the table'', what is the predominant function of language?', '["Función expresiva","Función conativa o apelativa","Función referencial","Función fática"]'::jsonb, '["Expressive function","Conative or appellative function","Referential function","Phatic function"]'::jsonb, 1, 'La función conativa o apelativa se centra en el receptor y busca influir en su comportamiento. En este caso, se le está pidiendo a María que realice una acción específica.', 'The conative or appellative function focuses on the receiver and seeks to influence their behavior. In this case, María is being asked to perform a specific action.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('2ba2eed4-3f40-4495-865e-f548bc24ab33', '¿Cuál de las siguientes palabras está correctamente acentuada según las reglas de tilde?', 'Which of the following words is correctly accented according to accent rules?', '["Matemáticas","Automovíl","Caracter","Examén"]'::jsonb, '["Matemáticas","Automovíl","Caracter","Examén"]'::jsonb, 0, 'Matemáticas es esdrújula (ma-te-má-ti-cas) y todas las palabras esdrújulas llevan tilde. Las otras opciones tienen errores: automóvil (grave terminada en consonante), carácter (grave terminada en consonante) y examen (grave terminada en vocal).', 'Matemáticas is a proparoxytone word (ma-te-má-ti-cas) and all proparoxytone words carry an accent mark. The other options have errors in their accentuation.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('2ba2eed4-3f40-4495-865e-f548bc24ab33', 'Un texto que tiene como intención principal convencer al lector sobre un punto de vista específico mediante razones y evidencias se clasifica como:', 'A text whose main intention is to convince the reader about a specific point of view through reasons and evidence is classified as:', '["Texto narrativo","Texto descriptivo","Texto expositivo","Texto argumentativo"]'::jsonb, '["Narrative text","Descriptive text","Expository text","Argumentative text"]'::jsonb, 3, 'El texto argumentativo tiene como propósito persuadir o convencer al receptor mediante argumentos, razones y evidencias sobre una tesis o punto de vista específico.', 'Argumentative text aims to persuade or convince the receiver through arguments, reasons and evidence about a specific thesis or point of view.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b7f769c0-3e39-4cf0-9a9f-199fb7850077', '¿Cuáles son los tres niveles de lectura que hemos estudiado?', 'What are the three levels of reading that we have studied?', '["Literal, inferencial y crítico","Básico, intermedio y avanzado","Superficial, profundo y analítico","Rápido, normal y detallado"]'::jsonb, '["Literal, inferential and critical","Basic, intermediate and advanced","Superficial, deep and analytical","Fast, normal and detailed"]'::jsonb, 0, 'Los tres niveles de lectura son: literal (comprensión directa del texto), inferencial (lectura entre líneas) y crítico (evaluación y juicio del contenido).', 'The three levels of reading are: literal (direct comprehension of text), inferential (reading between the lines) and critical (evaluation and judgment of content).', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b7f769c0-3e39-4cf0-9a9f-199fb7850077', '¿Qué representan las 5W en el análisis de noticias?', 'What do the 5Ws represent in news analysis?', '["Who, What, When, Where, Why","Write, Watch, Wait, Work, Wonder","Word, World, Wisdom, Will, Way","Web, Week, Weather, War, Win"]'::jsonb, '["Who, What, When, Where, Why","Write, Watch, Wait, Work, Wonder","Word, World, Wisdom, Will, Way","Web, Week, Weather, War, Win"]'::jsonb, 0, 'Las 5W son las preguntas básicas para analizar una noticia: Quién (Who), Qué (What), Cuándo (When), Dónde (Where) y Por qué (Why).', 'The 5Ws are the basic questions to analyze a news story: Who, What, When, Where and Why.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('b7f769c0-3e39-4cf0-9a9f-199fb7850077', '¿Cuál es la principal diferencia entre paráfrasis y síntesis?', 'What is the main difference between paraphrasing and synthesis?', '["La paráfrasis reformula un texto manteniendo su extensión, la síntesis lo resume","La paráfrasis es más larga que el original, la síntesis es igual","La paráfrasis cambia el significado, la síntesis lo mantiene","No hay diferencia, son sinónimos"]'::jsonb, '["Paraphrasing reformulates a text maintaining its length, synthesis summarizes it","Paraphrasing is longer than the original, synthesis is equal","Paraphrasing changes the meaning, synthesis maintains it","There is no difference, they are synonyms"]'::jsonb, 0, 'La paráfrasis reformula un texto con otras palabras manteniendo la extensión original, mientras que la síntesis condensa y resume la información esencial.', 'Paraphrasing reformulates a text with other words maintaining the original length, while synthesis condenses and summarizes the essential information.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('489f7cab-98cf-4298-b6ef-7586c93ab94a', '¿Cuál es la forma correcta del verbo TO BE en la oración: ''She ___ a teacher''?', 'What is the correct form of the verb TO BE in the sentence: ''She ___ a teacher''?', '["am","is","are","be"]'::jsonb, '["am","is","are","be"]'::jsonb, 1, 'Con pronombres de tercera persona singular (he/she/it) siempre usamos ''is''.', 'With third person singular pronouns (he/she/it) we always use ''is''.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('489f7cab-98cf-4298-b6ef-7586c93ab94a', '¿Cuál es la forma interrogativa correcta en presente simple para ''He plays soccer''?', 'What is the correct interrogative form in simple present for ''He plays soccer''?', '["Do he plays soccer?","Does he plays soccer?","Does he play soccer?","Do he play soccer?"]'::jsonb, '["Do he plays soccer?","Does he plays soccer?","Does he play soccer?","Do he play soccer?"]'::jsonb, 2, 'Con he/she/it usamos ''Does'' y el verbo va en forma base (sin S).', 'With he/she/it we use ''Does'' and the verb goes in base form (without S).', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('489f7cab-98cf-4298-b6ef-7586c93ab94a', '¿Cuál artículo es correcto: ''___ university'' y ''___ apple''?', 'Which articles are correct: ''___ university'' and ''___ apple''?', '["A university / A apple","An university / An apple","A university / An apple","An university / A apple"]'::jsonb, '["A university / A apple","An university / An apple","A university / An apple","An university / A apple"]'::jsonb, 2, 'Usamos ''A'' antes de sonido consonante (university) y ''AN'' antes de sonido vocal (apple).', 'We use ''A'' before consonant sounds (university) and ''AN'' before vowel sounds (apple).', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('1073ea0b-efd5-4054-8fd4-0523602facd3', '¿Cuáles son las 4 dimensiones de la salud que hemos estudiado?', 'What are the 4 dimensions of health that we have studied?', '["Física, mental, social y espiritual","Física, emocional, intelectual y económica","Corporal, psicológica, familiar y laboral","Biológica, psíquica, cultural y ambiental"]'::jsonb, '["Physical, mental, social and spiritual","Physical, emotional, intellectual and economic","Body, psychological, family and work","Biological, psychic, cultural and environmental"]'::jsonb, 0, 'Las 4 dimensiones de la salud son: física (funcionamiento del cuerpo), mental (bienestar psicológico), social (relaciones interpersonales) y espiritual (propósito y valores de vida).', 'The 4 dimensions of health are: physical (body functioning), mental (psychological well-being), social (interpersonal relationships) and spiritual (life purpose and values).', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('1073ea0b-efd5-4054-8fd4-0523602facd3', 'Según las recomendaciones de la OMS, ¿cuántos minutos de actividad física moderada deben realizar los adultos por semana?', 'According to WHO recommendations, how many minutes of moderate physical activity should adults do per week?', '["100 minutos","150 minutos","200 minutos","300 minutos"]'::jsonb, '["100 minutes","150 minutes","200 minutes","300 minutes"]'::jsonb, 1, 'La OMS recomienda que los adultos realicen al menos 150 minutos de actividad física aeróbica de intensidad moderada por semana, o 75 minutos de actividad vigorosa.', 'WHO recommends that adults do at least 150 minutes of moderate-intensity aerobic physical activity per week, or 75 minutes of vigorous activity.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('1073ea0b-efd5-4054-8fd4-0523602facd3', 'En el contexto de higiene del sueño, ¿cuál de las siguientes prácticas es MÁS recomendable antes de dormir?', 'In the context of sleep hygiene, which of the following practices is MOST recommended before sleeping?', '["Usar dispositivos electrónicos para relajarse","Tomar café para inducir somnolencia","Mantener una rutina regular y un ambiente tranquilo","Hacer ejercicio intenso 30 minutos antes"]'::jsonb, '["Using electronic devices to relax","Drinking coffee to induce drowsiness","Maintaining a regular routine and quiet environment","Doing intense exercise 30 minutes before"]'::jsonb, 2, 'Una buena higiene del sueño incluye mantener horarios regulares, crear un ambiente tranquilo y oscuro, y evitar estimulantes como pantallas, cafeína o ejercicio intenso antes de dormir.', 'Good sleep hygiene includes maintaining regular schedules, creating a quiet and dark environment, and avoiding stimulants like screens, caffeine or intense exercise before sleeping.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('7c74fb2b-af23-438e-b972-a9c364873d05', '¿Cuál es la forma correcta de expresar una acción que está ocurriendo ahora mismo?', 'What is the correct way to express an action that is happening right now?', '["I work in the garden every day","I am working in the garden now","I will work in the garden","I worked in the garden yesterday"]'::jsonb, '["I work in the garden every day","I am working in the garden now","I will work in the garden","I worked in the garden yesterday"]'::jsonb, 1, 'El presente continuo (am/is/are + verbo-ing) se usa para acciones que están ocurriendo en el momento de hablar.', 'The present continuous (am/is/are + verb-ing) is used for actions happening at the moment of speaking.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('7c74fb2b-af23-438e-b972-a9c364873d05', '¿Cuál oración usa correctamente un verbo modal para expresar obligación?', 'Which sentence correctly uses a modal verb to express obligation?', '["You can wear a coat when it''s cold","You should wear a coat when it''s cold","You must wear a uniform at school","You will wear a coat tomorrow"]'::jsonb, '["You can wear a coat when it''s cold","You should wear a coat when it''s cold","You must wear a uniform at school","You will wear a coat tomorrow"]'::jsonb, 2, 'El modal ''must'' expresa obligación fuerte o necesidad, mientras que ''can'' expresa habilidad y ''should'' expresa consejo.', 'The modal ''must'' expresses strong obligation or necessity, while ''can'' expresses ability and ''should'' expresses advice.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('7c74fb2b-af23-438e-b972-a9c364873d05', '¿Cuál es la diferencia principal entre ''will'' y ''going to'' para expresar futuro?', 'What is the main difference between ''will'' and ''going to'' to express future?', '["Will se usa para planes, going to para decisiones espontáneas","Will se usa para decisiones espontáneas, going to para planes","Ambos se usan exactamente igual","Will es pasado, going to es presente"]'::jsonb, '["Will is used for plans, going to for spontaneous decisions","Will is used for spontaneous decisions, going to for plans","Both are used exactly the same","Will is past, going to is present"]'::jsonb, 1, '''Will'' se usa para decisiones tomadas en el momento de hablar, mientras que ''going to'' se usa para planes ya decididos o intenciones.', '''Will'' is used for decisions made at the moment of speaking, while ''going to'' is used for already decided plans or intentions.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('736eda0f-b8af-4576-84b6-a306b0e8047f', '¿A qué conjunto numérico pertenece el número -7/3?', 'Which number set does -7/3 belong to?', '["Números naturales","Números enteros","Números racionales","Números irracionales"]'::jsonb, '["Natural numbers","Integer numbers","Rational numbers","Irrational numbers"]'::jsonb, 2, 'El número -7/3 es una fracción (cociente de dos enteros donde el denominador no es cero), por lo tanto pertenece al conjunto de los números racionales.', 'The number -7/3 is a fraction (quotient of two integers where the denominator is not zero), therefore it belongs to the set of rational numbers.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('736eda0f-b8af-4576-84b6-a306b0e8047f', '¿Cuál es el resultado de resolver la ecuación 3x - 5 = 2x + 7?', 'What is the result of solving the equation 3x - 5 = 2x + 7?', '["x = 2","x = 12","x = -2","x = 6"]'::jsonb, '["x = 2","x = 12","x = -2","x = 6"]'::jsonb, 1, 'Restando 2x de ambos lados: 3x - 2x - 5 = 7, entonces x - 5 = 7. Sumando 5 a ambos lados: x = 12.', 'Subtracting 2x from both sides: 3x - 2x - 5 = 7, so x - 5 = 7. Adding 5 to both sides: x = 12.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('736eda0f-b8af-4576-84b6-a306b0e8047f', 'Si un artículo cuesta $200 y tiene un descuento del 25%, ¿cuál es su precio final?', 'If an item costs $200 and has a 25% discount, what is its final price?', '["$150","$175","$160","$180"]'::jsonb, '["$150","$175","$160","$180"]'::jsonb, 0, 'El descuento es 25% de $200 = 0.25 × 200 = $50. El precio final es $200 - $50 = $150.', 'The discount is 25% of $200 = 0.25 × 200 = $50. The final price is $200 - $50 = $150.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ddeaaaf2-3fd1-4a28-984d-debf61490a39', '¿Cuál de las siguientes opciones corresponde a una característica del estilo de aprendizaje ''Kinestésico'' en el modelo VARK?', 'Which of the following options corresponds to a characteristic of the ''Kinesthetic'' learning style in the VARK model?', '["Prefiere información presentada en gráficos y diagramas","Aprende mejor a través de la experiencia práctica y el movimiento","Se enfoca en escuchar explicaciones y discusiones","Necesita leer y escribir para procesar información"]'::jsonb, '["Prefers information presented in graphs and diagrams","Learns better through practical experience and movement","Focuses on listening to explanations and discussions","Needs to read and write to process information"]'::jsonb, 1, 'El estilo kinestésico se caracteriza por aprender mejor a través de la experiencia práctica, el movimiento y la manipulación física de objetos.', 'The kinesthetic style is characterized by learning better through practical experience, movement, and physical manipulation of objects.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ddeaaaf2-3fd1-4a28-984d-debf61490a39', 'Según la Matriz de Eisenhower, ¿en qué cuadrante se ubican las tareas que son importantes pero no urgentes?', 'According to the Eisenhower Matrix, in which quadrant are tasks that are important but not urgent located?', '["Cuadrante 1: Hacer inmediatamente","Cuadrante 2: Planificar y programar","Cuadrante 3: Delegar","Cuadrante 4: Eliminar"]'::jsonb, '["Quadrant 1: Do immediately","Quadrant 2: Plan and schedule","Quadrant 3: Delegate","Quadrant 4: Eliminate"]'::jsonb, 1, 'Las tareas importantes pero no urgentes se ubican en el Cuadrante 2, donde deben planificarse y programarse para evitar que se vuelvan urgentes.', 'Important but not urgent tasks are located in Quadrant 2, where they should be planned and scheduled to prevent them from becoming urgent.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('ddeaaaf2-3fd1-4a28-984d-debf61490a39', '¿Cuál es una característica esencial de las metas SMART?', 'What is an essential characteristic of SMART goals?', '["Deben ser siempre a largo plazo","Deben incluir fechas límite específicas","Deben ser fáciles de alcanzar","Deben involucrar a otras personas"]'::jsonb, '["They must always be long-term","They must include specific deadlines","They must be easy to achieve","They must involve other people"]'::jsonb, 1, 'Las metas SMART deben ser específicas, medibles, alcanzables, relevantes y con tiempo definido (Time-bound), por lo que incluir fechas límite específicas es esencial.', 'SMART goals must be Specific, Measurable, Achievable, Relevant, and Time-bound, so including specific deadlines is essential.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('cd586867-1246-4582-ba92-b6d53b0ed6f1', '¿Cuál es la regla 6×6 en presentaciones efectivas?', 'What is the 6×6 rule in effective presentations?', '["Máximo 6 diapositivas con 6 imágenes cada una","Máximo 6 líneas de texto con 6 palabras por línea","6 colores diferentes en 6 diapositivas","6 minutos de presentación con 6 temas principales"]'::jsonb, '["Maximum 6 slides with 6 images each","Maximum 6 lines of text with 6 words per line","6 different colors in 6 slides","6 minutes of presentation with 6 main topics"]'::jsonb, 1, 'La regla 6×6 establece que cada diapositiva debe tener máximo 6 líneas de texto con no más de 6 palabras por línea para mantener la atención del público.', 'The 6×6 rule states that each slide should have a maximum of 6 lines of text with no more than 6 words per line to maintain audience attention.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('cd586867-1246-4582-ba92-b6d53b0ed6f1', '¿Qué función cumple el campo CCO (BCC) en el correo electrónico?', 'What function does the BCC field serve in email?', '["Enviar copias donde todos ven los destinatarios","Enviar copias ocultas donde los destinatarios no se ven entre sí","Marcar el correo como prioritario","Programar el envío del correo"]'::jsonb, '["Send copies where everyone sees the recipients","Send hidden copies where recipients don''t see each other","Mark the email as priority","Schedule the email sending"]'::jsonb, 1, 'CCO (Copia Carbón Oculta) o BCC permite enviar copias del correo sin que los destinatarios vean las direcciones de los demás, protegiendo la privacidad.', 'BCC (Blind Carbon Copy) allows sending email copies without recipients seeing each other''s addresses, protecting privacy.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('cd586867-1246-4582-ba92-b6d53b0ed6f1', '¿Cuál de estos componentes de hardware es responsable de ejecutar las instrucciones y realizar los cálculos en una computadora?', 'Which of these hardware components is responsible for executing instructions and performing calculations in a computer?', '["RAM (Memoria de acceso aleatorio)","Disco duro","CPU (Unidad central de procesamiento)","Dispositivos de entrada y salida"]'::jsonb, '["RAM (Random Access Memory)","Hard drive","CPU (Central Processing Unit)","Input and output devices"]'::jsonb, 2, 'La CPU es el cerebro de la computadora, encargada de ejecutar todas las instrucciones de los programas y realizar los cálculos necesarios para el funcionamiento del sistema.', 'The CPU is the brain of the computer, responsible for executing all program instructions and performing the calculations necessary for system operation.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('07ee6729-7efc-4bec-b611-ca730db15a6e', '¿Cuál era la característica principal del sistema educativo azteca conocido como Calmécac?', 'What was the main characteristic of the Aztec educational system known as Calmécac?', '["Estaba dirigido a los hijos de comerciantes","Era exclusivo para la nobleza y futuros sacerdotes","Se enfocaba únicamente en actividades militares","Era accesible para toda la población"]'::jsonb, '["It was directed at merchants'' children","It was exclusive for nobility and future priests","It focused only on military activities","It was accessible to the entire population"]'::jsonb, 1, 'El Calmécac era la institución educativa azteca reservada para los hijos de la nobleza y aquellos destinados al sacerdocio, donde recibían educación superior en religión, escritura, astronomía y gobierno.', 'The Calmécac was the Aztec educational institution reserved for the children of nobility and those destined for priesthood, where they received higher education in religion, writing, astronomy, and government.', 1)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('07ee6729-7efc-4bec-b611-ca730db15a6e', '¿Qué estableció el artículo 3° de la Constitución de 1917 respecto a la educación en México?', 'What did Article 3 of the 1917 Constitution establish regarding education in Mexico?', '["La educación sería privada y religiosa","La educación sería laica, gratuita y obligatoria","Solo los hombres tendrían derecho a la educación","La educación estaría a cargo de la Iglesia"]'::jsonb, '["Education would be private and religious","Education would be secular, free and mandatory","Only men would have the right to education","Education would be in charge of the Church"]'::jsonb, 1, 'El artículo 3° constitucional de 1917 estableció que la educación en México sería laica, gratuita y obligatoria, separando definitivamente la educación del control religioso.', 'Constitutional Article 3 of 1917 established that education in Mexico would be secular, free and mandatory, definitively separating education from religious control.', 2)
ON CONFLICT (semana_id, orden) DO NOTHING;

INSERT INTO quiz_semana (semana_id, pregunta, pregunta_en, opciones, opciones_en, respuesta_correcta, explicacion, explicacion_en, orden)
VALUES ('07ee6729-7efc-4bec-b611-ca730db15a6e', '¿Cuál fue la principal contribución de José Vasconcelos como primer Secretario de Educación Pública?', 'What was José Vasconcelos'' main contribution as the first Secretary of Public Education?', '["Creó el sistema de castas educativo","Implementó campañas masivas de alfabetización","Estableció la educación religiosa obligatoria","Fundó las primeras escuelas privadas"]'::jsonb, '["He created the educational caste system","He implemented massive literacy campaigns","He established mandatory religious education","He founded the first private schools"]'::jsonb, 1, 'Vasconcelos lanzó campañas masivas de alfabetización y promovió la educación popular, llevando libros y maestros a comunidades rurales para combatir el analfabetismo en México.', 'Vasconcelos launched massive literacy campaigns and promoted popular education, bringing books and teachers to rural communities to combat illiteracy in Mexico.', 3)
ON CONFLICT (semana_id, orden) DO NOTHING;
